using System;
using System.Collections.Generic;
using System.Linq;
using OnePieceTcg.Engine;
using OnePieceTcg.Engine.Bot;

// Headless bot-vs-bot battle harness for the OPTCG engine.
// Loops every starter-deck pairing over several seeds, running IntermediateBot.PlayFullMatch,
// and flags: crashes (exceptions), non-finishing games (hit the command cap = likely deadlock/
// infinite loop), and basic end-state invariant violations. Prints a summary + the worst cases.

class Program
{
    const string CardJsonPath = @"C:\Users\Nperr\One Piece TCG Simulator\Assets\StreamingAssets\Cards\official-card-library.json";

    static int Main(string[] args)
    {
        int loaded = CardLibraryLoader.Load(CardJsonPath);
        Console.WriteLine($"Loaded {loaded} card definitions from JSON.\n");
        if (args.Length > 0 && args[0] == "scenario") return Scenarios.Run();
        if (args.Length > 0 && args[0] == "coverage") return EffectCoverage.Run();
        if (args.Length > 0 && args[0] == "golden") return EffectCoverage.Golden(args.Length > 1 && args[1] == "write");
        if (args.Length > 0 && args[0] == "invariants") return InvariantSweep(args.Length > 1 && int.TryParse(args[1], out var q) ? q : 2);
        if (args.Length > 0 && args[0] == "diag") { Diag(args[1], args[2], int.Parse(args[3])); return 0; }
        if (args.Length > 0 && args[0] == "probe")
        {
            // Optional overrides: leader=<cardId> sets the south Leader (for leader-gated card
            // effects like ST17-002 Law's {Seven Warlords} clause); oppchar=<cardId> sets the
            // opponent's Character. e.g.  probe ST17-002 leader=ST17-001
            string leaderOverride = args.FirstOrDefault(a => a.StartsWith("leader="))?.Substring("leader=".Length);
            string oppCharOverride = args.FirstOrDefault(a => a.StartsWith("oppchar="))?.Substring("oppchar=".Length);
            string deckTopOverride = args.FirstOrDefault(a => a.StartsWith("decktop="))?.Substring("decktop=".Length);
            Probe(args[1], leaderOverride, oppCharOverride, deckTopOverride);
            return 0;
        }
        if (args.Length > 0 && args[0] == "trace") { Trace(args.Length > 1 ? args[1] : "st01", args.Length > 2 ? args[2] : "st02"); return 0; }
        // powtest <leaderId> [bigChar] — prints the south Leader's power on south's own turn vs
        // north's turn (to check [Opponent's Turn] / conditional passive auras). Optional bigChar
        // is a south board Character (e.g. a 7000-power body for ST30-001's −2000 self-debuff).
        if (args.Length > 0 && args[0] == "powtest") { PowTest(args[1], args.Length > 2 ? args[2] : null); return 0; }
        // atktest <cardId> [numFriends] — places the card as an ACTIVE south attacker with numFriends
        // extra friendly Characters, declares an attack on north's Leader, and reports the attacker's
        // power + any pending effect (verifies [When Attacking] self-buffs auto-apply, e.g. OP07-034).
        if (args.Length > 0 && args[0] == "atktest") { AtkTest(args[1], args.Length > 2 ? int.Parse(args[2]) : 3); return 0; }
        // luretest <lureCardId> — places a RESTED lure (with its DON!! xN) on north's board and checks
        // that a south attacker is blocked from hitting north's Leader but allowed to hit the lure.
        if (args.Length > 0 && args[0] == "luretest") { LureTest(args[1]); return 0; }
        // restricttest <cardId> <hiPowerCardId> — places cardId as an active south attacker, then declares
        // an attack on north's Leader with (a) 0 and (b) 2 copies of hiPowerCardId on north's board. Verifies
        // conditional "cannot attack unless opponent has N Characters with P+ base power" restrictions (EB04-005).
        if (args.Length > 0 && args[0] == "restricttest") { RestrictTest(args[1], args[2]); return 0; }
        // reacttest <reactorCardId> <reactorLeaderId> — puts the reactor card + leader on NORTH, has
        // SOUTH play a Character, and reports whether NORTH gets a reactive pending effect (OP04-024).
        if (args.Length > 0 && args[0] == "reacttest") { ReactTest(args[1], args[2]); return 0; }
        // evttest <reactorCardId> — puts the reactor (with its DON) on SOUTH, has SOUTH activate a
        // [Main] Event, and reports the reactor's "When you activate an Event" result (OP04-053 etc.).
        if (args.Length > 0 && args[0] == "evttest") { EvtTest(args[1]); return 0; }
        // koreptest — verifies OP05-030 Rosinante's "[Opponent's Turn] if your RESTED Character would
        // be K.O.'d, trash this instead": protects a RESTED victim but not an ACTIVE one.
        if (args.Length > 0 && args[0] == "koreptest") { KoRepTest(); return 0; }
        // koreptest2 <guardId> <victimId> [trashFuel] — generic removal-replacement test: places guardId
        // + victimId on south, seeds south's trash with trashFuel cards, has north K.O. the victim with
        // EB01-049 (K.O. up to 1 opp Character cost ≤ 2), and reports whether the victim was saved.
        if (args.Length > 0 && args[0] == "koreptest2") { KoRepTest2(args[1], args[2], args.Length > 3 ? int.Parse(args[3]) : 3); return 0; }
        // koreptest3 <guardId> <southLeaderId> — self-protection test: places guardId on south (guard==victim)
        // under southLeaderId, then north uncapped-K.O.s it (OP07-085 Stussy). Reports if the guard survived.
        // Used to verify condition-gated self-protection (EB04-044 Koby: Navy-leader gate).
        if (args.Length > 0 && args[0] == "koreptest3") { KoRepTest3(args[1], args[2]); return 0; }
        // kriegtest — OP15-008 Krieg: "give up to 3 of your opponent's rested DON!! to 1 of your
        // opponent's Characters." Verifies the DON goes to the CHOSEN opponent Character, not the first.
        if (args.Length > 0 && args[0] == "kriegtest") { KriegTest(); return 0; }
        // debufftest — OP15-001 Krieg leader passive "[DON!! x1][Opponent's Turn] if all your Characters
        // are {East Blue}, give all opponent Characters −2000 power". Checks the opp Character's power.
        if (args.Length > 0 && args[0] == "debufftest") { DebuffTest(); return 0; }
        // charpow <charId> — places the character on south and prints its power on south's own turn vs
        // the opponent's turn (verifies passive [Your Turn]/[Opponent's Turn] self-buff/debuff auras).
        if (args.Length > 0 && args[0] == "charpow")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "cp" });
            st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6;
            var S = st.Players["south"];
            for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
            var ch = new CardInstance { InstanceId = "CH", CardId = args[1], Owner = "south", Zone = "character" };
            var dg = System.Text.RegularExpressions.Regex.Match(CardData.GetCard(args[1])?.Effect ?? "", @"\[DON!! x(\d+)\]");
            if (dg.Success) for (int k = 0; k < int.Parse(dg.Groups[1].Value); k++) ch.AttachedDonIds.Add($"cd{k}");
            S.CharacterArea[0] = ch;
            Console.WriteLine($"{args[1]} {CardData.GetCard(args[1])?.Name} base power {CardData.GetCard(args[1])?.Power}");
            Console.WriteLine($"{CardData.GetCard(args[1])?.Effect}");
            st.ActiveSeat = "south"; Console.WriteLine($"power on SOUTH's (own) turn:     {GameEngine.GetPower(st, ch)}");
            st.ActiveSeat = "north"; Console.WriteLine($"power on NORTH's (opp) turn:      {GameEngine.GetPower(st, ch)}");
            return 0;
        }
        // stagepow <stageId> <recipientCharId> — places the Stage + a recipient Character on south and
        // prints the recipient's power on south's own turn vs the opponent's turn (verifies Stage-sourced
        // continuous power auras like EB04-010 Lulucia Kingdom are actually applied).
        if (args.Length > 0 && args[0] == "stagepow")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "sp" });
            st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6;
            var S = st.Players["south"];
            for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
            S.Stage = new CardInstance { InstanceId = "STG", CardId = args[1], Owner = "south", Zone = "stage" };
            var ch = new CardInstance { InstanceId = "CH", CardId = args[2], Owner = "south", Zone = "character" };
            S.CharacterArea[0] = ch;
            string stgEff = (CardData.GetCard(args[1])?.Effect ?? "").Replace("\n", " / ");
            Console.WriteLine($"STAGE {args[1]} {CardData.GetCard(args[1])?.Name}: {stgEff}");
            Console.WriteLine($"recipient {args[2]} {CardData.GetCard(args[2])?.Name} base power {CardData.GetCard(args[2])?.Power} (cost {CardData.GetCard(args[2])?.Cost})");
            st.ActiveSeat = "south"; Console.WriteLine($"recipient power on SOUTH's (own) turn: {GameEngine.GetPower(st, ch)}");
            st.ActiveSeat = "north"; Console.WriteLine($"recipient power on NORTH's (opp) turn:  {GameEngine.GetPower(st, ch)}");
            return 0;
        }
        // sbuff <cardId> <leaderId> <trashCardId> <trashCount> — places cardId on south under leaderId with
        // trashCount copies of trashCardId in south's trash, and prints its power (own turn). Verifies STATIC
        // conditional self-buffs ("If <cond>, this Character gains +N power [for every X]") are applied.
        if (args.Length > 0 && args[0] == "sbuff")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "sb" });
            st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6; st.ActiveSeat = "south";
            var S = st.Players["south"];
            for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
            if (args.Length > 2 && args[2] != "-") S.Leader.CardId = args[2];
            var ch = new CardInstance { InstanceId = "CH", CardId = args[1], Owner = "south", Zone = "character" };
            S.CharacterArea[0] = ch;
            int tc = args.Length > 4 ? int.Parse(args[4]) : 0;
            for (int i = 0; i < tc; i++) S.Trash.Add(new CardInstance { InstanceId = $"tb{i}", CardId = args[3], Owner = "south", Zone = "trash" });
            string trashLbl = args.Length > 3 ? args[3] : "-";
            string effLbl = (CardData.GetCard(args[1])?.Effect ?? "").Replace("\n", " / ");
            Console.WriteLine($"{args[1]} {CardData.GetCard(args[1])?.Name} base {CardData.GetCard(args[1])?.Power} | leader {S.Leader.CardId} | trash {tc}x {trashLbl}");
            Console.WriteLine(effLbl);
            Console.WriteLine($"POWER = {GameEngine.GetPower(st, ch)}");
            return 0;
        }
        // leadaura <leaderId> <charId> — places leaderId + a charId on south and prints the char's power
        // on own turn with 0 vs N DON attached to the LEADER (verifies [DON!! xN] leader board auras).
        if (args.Length > 0 && args[0] == "leadaura")
        {
            var ldef = CardData.GetCard(args[1]);
            string laEff = (ldef?.Effect ?? "").Replace("\n", " / ");
            Console.WriteLine($"=== LEADAURA {args[1]} {ldef?.Name}: {laEff} ===");
            foreach (int donOnLeader in new[] { 0, 1, 2 })
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "la" + donOnLeader });
                st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6; st.ActiveSeat = "south";
                var S = st.Players["south"];
                S.Leader.CardId = args[1];
                S.Leader.AttachedDonIds.Clear();
                for (int i = 0; i < donOnLeader; i++) S.Leader.AttachedDonIds.Add($"lad{i}");
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var ch = new CardInstance { InstanceId = "CH", CardId = args[2], Owner = "south", Zone = "character" };
                S.CharacterArea[0] = ch;
                st.ActiveSeat = "south"; int ownP = GameEngine.GetPower(st, ch);
                st.ActiveSeat = "north"; int oppP = GameEngine.GetPower(st, ch);
                Console.WriteLine($"  leader DON={donOnLeader}: char power own-turn={ownP}  opp-turn={oppP}  (char base {CardData.GetCard(args[2])?.Power})");
            }
            return 0;
        }
        // oppevent <reactorId> <donOnReactor> — south (active) has reactorId + an ally on board; south attacks,
        // north counters with an Event (OP01-057). Verifies "[Your Turn] when your opponent activates an Event"
        // reactions (OP01-004 Usopp draw / OP11-012 Franky board buff / OP06-044 Gion opponent-tax).
        if (args.Length > 0 && args[0] == "oppevent")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "oe" });
            st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6; st.ActiveSeat = "south";
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            int donR = args.Length > 2 ? int.Parse(args[2]) : 1;
            var react = new CardInstance { InstanceId = "REACT", CardId = args[1], Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            for (int k = 0; k < donR; k++) react.AttachedDonIds.Add($"rd{k}");
            S.CharacterArea[0] = react;
            S.CharacterArea[1] = new CardInstance { InstanceId = "ALLY", CardId = "ST01-006", Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            S.CharacterArea[2] = new CardInstance { InstanceId = "ATK", CardId = "ST01-006", Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            N.Hand.Add(new CardInstance { InstanceId = "CE", CardId = "OP01-057", Owner = "north", Zone = "hand" });
            for (int i = 0; i < 2; i++) N.Hand.Add(new CardInstance { InstanceId = $"nf{i}", CardId = "ST01-006", Owner = "north", Zone = "hand" }); // filler so Gion's tax has a target
            int nHandBefore = N.Hand.Count;
            for (int i = 0; i < 4; i++) N.CostArea.Add(new DonInstance { InstanceId = $"nd{i}", Rested = false });
            int handBefore = S.Hand.Count;
            int allyBefore = GameEngine.GetPower(st, S.CharacterArea[1]);
            GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "south", Attacker = "ATK", Target = N.Leader.InstanceId });
            if (st.Battle != null) st.Battle.Step = "counter";   // skip block, reach the counter step
            GameEngine.ApplyCommand(st, new GameCommand { Type = "counterWithCard", Seat = "north", InstanceId = "CE" });
            Console.WriteLine($"=== OPPEVENT reactor={args[1]} {CardData.GetCard(args[1])?.Name} DON={donR} ===\n{CardData.GetCard(args[1])?.Effect}");
            Console.WriteLine($"south hand {handBefore} -> {S.Hand.Count}   ally power {allyBefore} -> {GameEngine.GetPower(st, S.CharacterArea[1])}   north hand(after counter) {nHandBefore}(-1 CE)->{N.Hand.Count}");
            foreach (var l in st.EventLog.Skip(Math.Max(0, st.EventLog.Count - 5))) Console.WriteLine("   " + l.Message);
            return 0;
        }
        // lawleader — OP01-002 Trafalgar Law leader: 5 RED board chars + a RED and a BLUE cost<=5 card in
        // hand. Activates the leader, returns a red board char, then verifies the play step only allows a
        // DIFFERENT-color (blue) card, rejecting the same-color (red) one — plus the return-step glow.
        if (args.Length > 0 && args[0] == "lawleader")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "law" });
            st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6; st.ActiveSeat = "south";
            var S = st.Players["south"]; S.TurnsStarted = 3;
            S.Leader.CardId = "OP01-002";
            int nChars = args.Length > 1 ? int.Parse(args[1]) : 5;
            for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
            for (int i = 0; i < nChars && i < 5; i++) S.CharacterArea[i] = new CardInstance { InstanceId = $"c{i}", CardId = "EB01-005", Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            Console.WriteLine($"(board chars = {nChars})");
            S.CostArea.Clear();
            for (int i = 0; i < 4; i++) S.CostArea.Add(new DonInstance { InstanceId = $"d{i}", Rested = false });
            S.Hand.Clear();
            S.Hand.Add(new CardInstance { InstanceId = "HRED", CardId = "EB01-005", Owner = "south", Zone = "hand" });
            S.Hand.Add(new CardInstance { InstanceId = "HBLUE", CardId = "EB01-025", Owner = "south", Zone = "hand" });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "activateMain", Seat = "south", Target = S.Leader.InstanceId });
            var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
            Console.WriteLine($"RETURN-step pending: {(pe?.Text ?? "<none>").Substring(0, Math.Min(60, (pe?.Text ?? "x").Length))}");
            if (pe != null)
            {
                bool glowBoard = GameEngine.IsValidEffectTarget(st, pe, S.CharacterArea[0]);
                bool glowHand = GameEngine.IsValidEffectTarget(st, pe, S.Hand.First(h => h.InstanceId == "HRED"));
                Console.WriteLine($"  return-step glow: board char={glowBoard} (want True)   hand card={glowHand} (want False)");
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "c0" });
            }
            var pe2 = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
            Console.WriteLine($"PLAY-step pending: {(pe2?.Text ?? "<none>").Substring(0, Math.Min(55, (pe2?.Text ?? "x").Length))}  firstPick={pe2?.FirstPickId}");
            if (pe2 != null)
            {
                Console.WriteLine($"  play-step glow: HRED(same color)={GameEngine.IsValidEffectTarget(st, pe2, S.Hand.First(h => h.InstanceId == "HRED"))} (want False)   HBLUE(diff)={GameEngine.IsValidEffectTarget(st, pe2, S.Hand.First(h => h.InstanceId == "HBLUE"))} (want True)");
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe2.EffectId, Target = "HRED" });
                bool redPlayed = S.CharacterArea.Any(c => c != null && c.InstanceId == "HRED");
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe2.EffectId, Target = "HBLUE" });
                bool bluePlayed = S.CharacterArea.Any(c => c != null && c.InstanceId == "HBLUE");
                Console.WriteLine($"RESULT: redPlayed={redPlayed} (want False)   bluePlayed={bluePlayed} (want True)");
            }
            return 0;
        }
        // odentest — OP01-031 Kouzuki Oden leader: "You can trash 1 {Land of Wano} card from hand: Set up to
        // 2 DON as active." Verifies the "You can <cost>:" prefix pays the trash cost and sets 2 rested DON active.
        if (args.Length > 0 && args[0] == "odentest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "oden" });
            st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6; st.ActiveSeat = "south";
            var S = st.Players["south"]; S.TurnsStarted = 3;
            S.Leader.CardId = "OP01-031";
            S.Hand.Clear();
            S.Hand.Add(new CardInstance { InstanceId = "WANO", CardId = "EB01-002", Owner = "south", Zone = "hand" });
            S.CostArea.Clear();
            for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = $"d{i}", Rested = true });   // 3 RESTED DON
            int restedBefore = S.CostArea.Count(d => d.Rested);
            GameEngine.ApplyCommand(st, new GameCommand { Type = "activateMain", Seat = "south", Target = S.Leader.InstanceId });
            for (int g = 0; g < 4; g++)
            {
                var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
                if (pe == null) break;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "WANO" });
            }
            bool wanoTrashed = S.Trash.Any(c => c.InstanceId == "WANO");
            int restedAfter = S.CostArea.Count(d => d.Rested);
            Console.WriteLine($"=== ODENTEST OP01-031 ===\nwanoTrashed={wanoTrashed} (want True)   rested DON {restedBefore}->{restedAfter} (want 3->1: 2 set active)");
            foreach (var l in st.EventLog.Skip(Math.Max(0, st.EventLog.Count - 5))) Console.WriteLine("   " + l.Message);
            return 0;
        }
        // oppkotest <reactorLeaderId> <donOnLeader> — south(active) has reactorLeaderId + DON on leader; south
        // K.O.s a north Character (via EB01-049). Verifies "[Your Turn] when your opponent's Character is K.O.'d,
        // <effect>" reactions (OP01-061 Kaido DON-ramp).
        if (args.Length > 0 && args[0] == "oppkotest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "opko" });
            st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6; st.ActiveSeat = "south";
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            S.Leader.CardId = args[1];
            int donL = args.Length > 2 ? int.Parse(args[2]) : 1;
            S.Leader.AttachedDonIds.Clear();
            for (int i = 0; i < donL; i++) S.Leader.AttachedDonIds.Add($"ld{i}");
            S.Leader.Rested = true;   // so a "set this Leader as active" reaction (Rob Lucci) is observable
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            N.CharacterArea[0] = new CardInstance { InstanceId = "VICT", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false };
            var ko = new CardInstance { InstanceId = "KO", CardId = "EB01-049", Owner = "south", Zone = "hand" };
            S.Hand.Add(ko);
            for (int i = 0; i < 4; i++) S.Hand.Add(new CardInstance { InstanceId = $"hf{i}", CardId = "ST01-006", Owner = "south", Zone = "hand" }); // fuel for trash-cost reactions
            for (int i = 0; i < 6; i++) S.CostArea.Add(new DonInstance { InstanceId = $"sd{i}", Rested = false });
            int donBefore = S.CostArea.Count; int activeBefore = S.CostArea.Count(d => !d.Rested); int handBefore = S.Hand.Count;
            GameEngine.ApplyCommand(st, new GameCommand { Type = "playCard", Seat = "south", InstanceId = "KO", SlotIndex = 0 });
            var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
            if (pe != null) GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "VICT" });
            // Drive any follow-up reaction (Rob Lucci's optional trash-2 cost → set leader active).
            for (int g = 0; g < 6; g++)
            {
                var rpe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
                if (rpe == null) break;
                var fuel = S.Hand.FirstOrDefault(h => h.InstanceId.StartsWith("hf"));
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = rpe.EffectId, Target = fuel?.InstanceId });
            }
            Console.WriteLine($"leaderActiveAfter={!S.Leader.Rested}");
            Console.WriteLine($"=== OPPKOTEST {args[1]} {CardData.GetCard(args[1])?.Name} DON-on-leader={donL} ===\n{CardData.GetCard(args[1])?.Effect}");
            bool victimKOd = !N.CharacterArea.Any(c => c != null && c.InstanceId == "VICT");
            int activeAfter = S.CostArea.Count(d => !d.Rested);
            Console.WriteLine($"victimKOd={victimKOd}   south DON {donBefore}->{S.CostArea.Count} (active {activeBefore}->{activeAfter})   south hand {handBefore - 1}(after KO play)->{S.Hand.Count}");
            foreach (var l in st.EventLog.Skip(Math.Max(0, st.EventLog.Count - 5))) Console.WriteLine("   " + l.Message);
            return 0;
        }
        // scaletest <cardId> <handSize> — places cardId on south with DON attached per its [DON!! xN] and a
        // controlled hand size, own turn, and prints its power. Verifies turn-tagged "for every X" scaling.
        if (args.Length > 0 && args[0] == "scaletest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "sc" });
            st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6; st.ActiveSeat = "south";
            var S = st.Players["south"];
            for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
            var ch = new CardInstance { InstanceId = "CH", CardId = args[1], Owner = "south", Zone = "character" };
            var dg = System.Text.RegularExpressions.Regex.Match(CardData.GetCard(args[1])?.Effect ?? "", @"\[DON!! x(\d+)\]");
            if (dg.Success) for (int k = 0; k < int.Parse(dg.Groups[1].Value); k++) ch.AttachedDonIds.Add($"cd{k}");
            S.CharacterArea[0] = ch;
            int handSize = args.Length > 2 ? int.Parse(args[2]) : 3;
            S.Hand.Clear();
            for (int i = 0; i < handSize; i++) S.Hand.Add(new CardInstance { InstanceId = $"h{i}", CardId = "ST01-006", Owner = "south", Zone = "hand" });
            Console.WriteLine($"{args[1]} {CardData.GetCard(args[1])?.Name} base {CardData.GetCard(args[1])?.Power}, DON attached {ch.AttachedDonIds.Count}, hand {handSize}");
            Console.WriteLine($"{CardData.GetCard(args[1])?.Effect}");
            Console.WriteLine($"POWER (own turn) = {GameEngine.GetPower(st, ch)}");
            return 0;
        }
        // battleimmune <auraId> <recipientId> <withAura 0|1> — north attacks a RESTED south recipient with a
        // higher-power attacker; if withAura, auraId is on south's board. Verifies aura-granted battle-K.O.
        // immunity (OP01-099 Kurozumi Semimaru protecting other {Kurozumi Clan} Characters).
        if (args.Length > 0 && args[0] == "battleimmune")
        {
            bool withAura = args.Length > 3 && args[3] == "1";
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "bi" + (withAura ? 1 : 0) });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            if (withAura) S.CharacterArea[0] = new CardInstance { InstanceId = "AURA", CardId = args[1], Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            S.CharacterArea[1] = new CardInstance { InstanceId = "RCPT", CardId = args[2], Owner = "south", Zone = "character", Rested = true, PlayedOnTurn = 0 };
            var atk = new CardInstance { InstanceId = "ATK", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            for (int k = 0; k < 4; k++) atk.AttachedDonIds.Add($"ad{k}");   // base 1000 + 4 DON = 5000 (> recipient)
            N.CharacterArea[0] = atk;
            int recPow = GameEngine.GetPower(st, S.CharacterArea[1]); int atkPow = GameEngine.GetPower(st, atk);
            GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "ATK", Target = "RCPT" });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "passBlock", Seat = "south" });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "passCounter", Seat = "south" });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveAttack", Seat = "south" });
            bool alive = S.CharacterArea.Any(c => c != null && c.InstanceId == "RCPT");
            Console.WriteLine($"=== BATTLEIMMUNE aura={args[1]} recipient={args[2]} {CardData.GetCard(args[2])?.Name} withAura={withAura} ===");
            Console.WriteLine($"attacker {atkPow} vs recipient {recPow} → recipientAlive={alive}  (withAura want True; without want False)");
            foreach (var l in st.EventLog.Skip(Math.Max(0, st.EventLog.Count - 4))) Console.WriteLine("   " + l.Message);
            return 0;
        }
        // garptest — OP02-002 Garp leader: "[Your Turn] When this Leader or any of your Characters is given a
