        // a north Character, and checks its cost dropped by 1.
        if (args.Length > 0 && args[0] == "garptest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "garp" });
            st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6; st.ActiveSeat = "south";
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            S.Leader.CardId = "OP02-002";
            S.CostArea.Clear();
            for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = $"d{i}", Rested = false });
            for (int i = 0; i < 5; i++) N.CharacterArea[i] = null;
            N.CharacterArea[0] = new CardInstance { InstanceId = "OPP", CardId = "OP01-025", Owner = "north", Zone = "character", Rested = false };
            int costBefore = GameEngine.GetCost(st, N.CharacterArea[0]);
            GameEngine.ApplyCommand(st, new GameCommand { Type = "attachDon", Seat = "south", Target = S.Leader.InstanceId, Amount = 1 });
            var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
