            if (pe != null) GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "OPP" });
            int costAfter = GameEngine.GetCost(st, N.CharacterArea[0]);
            Console.WriteLine($"opp char (OP01-025) cost {costBefore}->{costAfter} (want -1)");
            foreach (var l in st.EventLog.Skip(Math.Max(0, st.EventLog.Count - 4))) Console.WriteLine("   " + l.Message);
            return 0;
        }
        // blockbantest <attackerId> — south attacker declares an attack (firing [When Attacking]); north has a
        // WEAK (2000) and a STRONG (4000) Blocker. Verifies "cannot activate a [Blocker] with N or less power"
        // bars only the weak one (OP01-120 Shanks / OP03-002 Adio).
        if (args.Length > 0 && args[0] == "blockbantest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "bb" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            string weakId = args.Length > 2 ? args[2] : "EB01-017";     // barred blocker
            string strongId = args.Length > 3 ? args[3] : "EB01-006";   // allowed blocker
            bool clearHand = args.Length > 4 && args[4] == "1";
            if (clearHand) S.Hand.Clear();   // for conditions like Morley "1 or less cards in hand"
            var atk = new CardInstance { InstanceId = "ATK", CardId = args[1], Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            var dg = System.Text.RegularExpressions.Regex.Match(CardData.GetCard(args[1])?.Effect ?? "", @"\[DON!! x(\d+)\]");
            if (dg.Success) for (int k = 0; k < int.Parse(dg.Groups[1].Value); k++) atk.AttachedDonIds.Add($"ad{k}");
            S.CharacterArea[0] = atk;
            N.CharacterArea[0] = new CardInstance { InstanceId = "WEAK", CardId = weakId, Owner = "north", Zone = "character", Rested = false };
            N.CharacterArea[1] = new CardInstance { InstanceId = "STRONG", CardId = strongId, Owner = "north", Zone = "character", Rested = false };
            GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "south", Attacker = "ATK", Target = N.Leader.InstanceId });
            int peCount = st.PendingEffects.Count(e => e.Seat == "south");
            for (int g = 0; g < 3; g++) { var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south"); if (pe == null) break; GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = null }); }
            Console.WriteLine($"(south hand={S.Hand.Count} pending={peCount} battle={(st.Battle != null)} costBanMax={st.Battle?.BlockerCostBanMax} powBanMax={st.Battle?.BlockerPowerBanMax} noBlock={st.Battle?.NoBlocker})");
            bool weakBarred = st.Battle != null && GameEngine.BlockBarredByCurrentAttack(st, N.CharacterArea[0]);
            bool strongBarred = GameEngine.BlockBarredByCurrentAttack(st, N.CharacterArea[1]);
            Console.WriteLine($"=== BLOCKBANTEST {args[1]} {CardData.GetCard(args[1])?.Name} ===\n{CardData.GetCard(args[1])?.Effect}");
            Console.WriteLine($"weak(2000) barred={weakBarred} (want True)   strong(4000) barred={strongBarred} (want False)");
            return 0;
        }
        // jozutest — OP02-008 Jozu: "[DON!! x1] If you have 2 or less Life cards AND Leader's type includes
        // Whitebeard Pirates, gains [Rush]." Checks HasRush across (leader WB?, Life count) combos.
        if (args.Length > 0 && args[0] == "jozutest")
        {
            foreach (var (leaderId, life) in new[] { ("OP02-001", 2), ("OP02-001", 4), ("OP01-001", 2) })
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "jz" + leaderId + life });
                st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6; st.ActiveSeat = "south";
                var S = st.Players["south"];
                S.Leader.CardId = leaderId;
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var jozu = new CardInstance { InstanceId = "JOZU", CardId = "OP02-008", Owner = "south", Zone = "character", PlayedOnTurn = 6 };
                jozu.AttachedDonIds.Add("jd0");   // [DON!! x1]
                S.CharacterArea[0] = jozu;
                S.Life.Clear();
                for (int i = 0; i < life; i++) S.Life.Add(new CardInstance { InstanceId = $"lf{i}", CardId = "ST01-006", Owner = "south", Zone = "life" });
                bool rush = GameEngine.HasRush(st, jozu);
                bool wb = leaderId == "OP02-001";   // OP02-001 Newgate is Whitebeard Pirates; OP01-001 Zoro is not
