        // are set active. <vanilla 0|1> chooses a vanilla (want ramp) vs effect char (want NO ramp).
        if (args.Length > 0 && args[0] == "sanjitest")
        {
            bool vanilla = !(args.Length > 1 && args[1] == "0");
            string playId = vanilla ? "OP01-012" : "OP02-011";   // OP01-012 Sai (no effect) vs OP02-011 Vista (On Play)
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "sanji" + vanilla });
            st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6; st.ActiveSeat = "south";
            var S = st.Players["south"];
            S.Leader.CardId = "OP02-026";
            for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
            S.Hand.Clear();
            S.Hand.Add(new CardInstance { InstanceId = "PLAY", CardId = playId, Owner = "south", Zone = "hand" });
            S.CostArea.Clear();
            for (int i = 0; i < 6; i++) S.CostArea.Add(new DonInstance { InstanceId = $"d{i}", Rested = false });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "playCard", Seat = "south", InstanceId = "PLAY", SlotIndex = 0 });
            // Sanji's reactive ("set up to 2 DON active") is an auto/optional; resolve any south pending.
            for (int g = 0; g < 3; g++) { var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south"); if (pe == null) break; GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = null }); }
            int restedAfter = S.CostArea.Count(dd => dd.Rested);
            Console.WriteLine($"=== SANJITEST play={playId} vanilla={vanilla} ===");
            Console.WriteLine($"rested DON after (play cost 2 rests 2; Sanji sets 2 active → want 0 if vanilla, 2 if not) = {restedAfter}");
            foreach (var l in st.EventLog.Skip(Math.Max(0, st.EventLog.Count - 4))) Console.WriteLine("   " + l.Message);
            return 0;
        }
        // drawtotest — OP02-051 Ivankov: "[On Play] Draw card(s) so that you have 3 cards in your hand and then
