        // magellantest — OP02-071 Magellan leader "[Your Turn][OPT] When a DON!! card on THE field is returned to
        // your DON!! deck, this Leader gains +1000 power." Plays a DON!!−1 card (Shiryu) and checks Magellan +1000.
        if (args.Length > 0 && args[0] == "magellantest")
        {
