                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 7; // opponent's (north's) turn
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "BUF", CardId = "OP14-070", Owner = "south", Zone = "character", Rested = false };
                S.CostArea.Clear();
                for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = $"sd{i}", Rested = false });
                int fieldDonBefore = S.CostArea.Count;
                bool sourceIsChar = st.Players["north"] != null; // dummy
                // north's effect (from a north Character or Leader) rests Buffalo.
                if (sourceCardId == "LEADER") { st.PendingEffects.Add(new PendingEffect { EffectId = "R", Seat = "north", SourceInstanceId = N.Leader.InstanceId, Text = "Rest up to 1 of your opponent's Characters." }); }
                else { N.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = sourceCardId, Owner = "north", Zone = "character" }; st.PendingEffects.Add(new PendingEffect { EffectId = "R", Seat = "north", SourceInstanceId = "SRC", Text = "Rest up to 1 of your opponent's Characters." }); }
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = "R", Target = "BUF" });
                // The reactive queues for south; auto-resolve it (return DON + set active).
                for (int g = 0; g < 3; g++) { var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south"); if (pe == null) break; GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = null }); }
                bool active = S.CharacterArea[0] != null && !S.CharacterArea[0].Rested;
                int donDelta = fieldDonBefore - S.CostArea.Count;
                return (active, donDelta);
            };
