        // op04060test — OP04-060 "[On Your Opponent's Attack] [Once Per Turn] DON!! −1: Draw 1 card and trash 1
        // card from your hand." Verifies the reactive queues on the opponent's attack, the DON!! −1 cost is PAID
        // (not free), and the body runs; and that with 0 field DON the effect FIZZLES (no draw).
        if (args.Length > 0 && args[0] == "op04060test")
        {
            System.Func<int, (int don, int deck, int trash, bool resolved)> run = (int fieldDon) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op04060_" + fieldDon });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 9;
                var S = st.Players["south"]; var N = st.Players["north"];
                S.TurnsStarted = 4; N.TurnsStarted = 4;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "R", CardId = "OP04-060", Owner = "south", Zone = "character", Rested = true };
                S.CostArea.Clear();
                for (int i = 0; i < fieldDon; i++) S.CostArea.Add(new DonInstance { InstanceId = $"sd{i}", Rested = false });
                S.Hand.Clear();
                for (int i = 0; i < 2; i++) S.Hand.Add(new CardInstance { InstanceId = $"h{i}", CardId = "ST01-002", Owner = "south", Zone = "hand" });
                var natk = new CardInstance { InstanceId = "NATK", CardId = "EB02-035", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
                N.CharacterArea[0] = natk;
                int deckBefore = S.Deck.Count;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "NATK", Target = S.Leader.InstanceId });
                var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south" && e.Timing == "onOpponentsAttack");
                bool resolved = false;
                if (pe != null)
                {
                    // Pay the DON cost + draw (Target=null auto-pays with exactly 1 DON), then the
                    // mandatory trash-from-hand becomes pending. Try to SKIP it via passEffect — a
                    // mandatory "trash 1 card from your hand" with cards in hand must NOT be skippable.
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = null });
                    var trashPe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
                    if (trashPe != null)
                        GameEngine.ApplyCommand(st, new GameCommand { Type = "passEffect", Seat = "south", EffectId = trashPe.EffectId });
                    resolved = true;
                }
                return (S.CostArea.Count, deckBefore - S.Deck.Count, S.Trash.Count, resolved);
            };
            var paid = run(1);   // exactly 1 field DON → auto-pays, draws 1; mandatory trash CANNOT be skipped
            var broke = run(0);  // 0 field DON → fizzles, no draw
