        // thenchaintest — combo ". Then," chains where clause 2's target depends on clause 1's effect.
        //   EB01-046 Brook: "Give up to 1 opp Char −1 cost. Then, K.O. up to 1 opp Char with a cost of 0."
        //     → a cost-1 char reduced to 0 must then be K.O.-able (clause 2 sees clause 1's cost reduction).
        //   OP04-038: "Rest up to 1 opp Char. Then, K.O. up to 1 opp RESTED Char with cost ≤6."
        //     → resting an active char then makes it K.O.-able by clause 2.
        if (args.Length > 0 && args[0] == "thenchaintest")
        {
            System.Func<string, string, bool> koedVia = (string effText, string victimCard) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "thenchain" + victimCard });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                // Real on-board source (the splitter queues the ". Then," remainder only for a source it can find).
                S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-002", Owner = "south", Zone = "character" };
                var v = new CardInstance { InstanceId = "V", CardId = victimCard, Owner = "north", Zone = "character", Rested = false };
                N.CharacterArea[0] = v;
                var eff = new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "SRC", Text = effText };
                st.PendingEffects.Add(eff);
                // Resolve every pending effect (clause 1, then the queued clause 2) targeting the victim.
                for (int guard = 0; guard < 6 && st.PendingEffects.Any(e => e.Seat == "south"); guard++)
                {
                    var pe = st.PendingEffects.First(e => e.Seat == "south");
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "V" });
                }
                return !N.CharacterArea.Any(c => c != null && c.InstanceId == "V"); // KO'd?
            };
            // EB01-046: cost-1 victim (ST01-006) → reduced to 0 → KO'd.
            bool brookKo = koedVia("Give up to 1 of your opponent's Characters −1 cost during this turn. Then, K.O. up to 1 of your opponent's Characters with a cost of 0.", "ST01-006");
            // OP04-038: active victim rested by clause 1, then KO'd by clause 2 (cost ≤6). ST01-006 is cost 1.
            bool weakKo = koedVia("Rest up to 1 of your opponent's Leader or Character cards. Then, K.O. up to 1 of your opponent's rested Characters with a cost of 6 or less.", "ST01-006");
            // OP11-018: a 7000-power victim (OP11-017) is only K.O.-able (≤6000) AFTER clause 1's −4000 power.
            bool powerKo = koedVia("Give up to 1 of your opponent's Characters −4000 power during this turn. Then, K.O. up to 1 of your opponent's Characters with 6000 power or less.", "OP11-017");
            // give-DON → rest-opponent chain (EB03-015 Camie body): clause 1 attaches DON to an own char,
            // clause 2 rests an opponent Character (cost ≤2). Verify clause 2 fires (V ends rested).
            bool donChainRested;
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "donchain" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "EB01-006", Owner = "south", Zone = "character" }; // recipient + source
                S.CostArea.Clear(); S.CostArea.Add(new DonInstance { InstanceId = "rd", Rested = true });
                var v2 = new CardInstance { InstanceId = "V", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false }; // cost 1
                N.CharacterArea[0] = v2;
                var eff = new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "SRC",
                    Text = "Give up to 1 rested DON!! card to your Leader or 1 of your Characters. Then, rest up to 1 of your opponent's Characters with a cost of 2 or less." };
                st.PendingEffects.Add(eff);
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "SRC" }); // clause 1
                foreach (var pe in st.PendingEffects.Where(e => e.Seat == "south").ToList())
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "V" }); // clause 2
                donChainRested = v2.Rested;
            }
            bool pass = brookKo && weakKo && powerKo && donChainRested;
            Console.WriteLine($"=== THENCHAINTEST === EB01-046 cost→KO={brookKo}   OP04-038 rest→KO={weakKo}   OP11-018 power→KO={powerKo}   giveDON→rest={donChainRested} (all want True) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // trashanytest — P-051 Shanks "[When Attacking] You may trash any number of cards from your hand. This
        // Character gains +1000 power during this battle for every card trashed." Interactive multi-trash must
        // trash each clicked card and scale the buff by +1000 per card (was: flat +1000, trashed nothing).
        if (args.Length > 0 && args[0] == "trashanytest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "trashany" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
