            int before = GameEngine.GetPower(st, sh);
            var eff = new PendingEffect { EffectId = "P", Seat = "south", SourceInstanceId = "SH", TargetZone = EffectTargetZone.Hand,
                Text = "You may trash any number of cards from your hand. This Character gains +1000 power during this battle for every card trashed." };
            st.PendingEffects.Add(eff);
            // Trash 2 of the 3 cards, then skip.
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "P", Target = "h0" });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "P", Target = "h1" });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "P", Target = null }); // skip remaining
            int after = GameEngine.GetPower(st, sh);
            bool pass = after == before + 2000 && S.Trash.Count == 2 && S.Hand.Count == 1;
            Console.WriteLine($"=== TRASHANYTEST === power {before}->{after} (want +2000 for 2 trashed) trash={S.Trash.Count} hand={S.Hand.Count} : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // leaderfreezetest — OP04-031 Doflamingo "Up to 3 of your opponent's rested Leader and Character cards
        // will not become active in your opponent's next Refresh Phase." A frozen LEADER must STAY rested through
        // its owner's Refresh Phase (the freeze was ignored for the Leader/Stage — only Characters were checked).
        if (args.Length > 0 && args[0] == "leaderfreezetest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "ldrfreeze" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-002", Owner = "south", Zone = "character" };
            N.Leader.Rested = true; // opponent's Leader is rested (e.g. it attacked)
            var eff = new PendingEffect { EffectId = "F", Seat = "south", SourceInstanceId = "SRC",
                Text = "Up to a total of 3 of your opponent's rested Leader and Character cards will not become active in your opponent's next Refresh Phase." };
            st.PendingEffects.Add(eff);
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "F", Target = N.Leader.InstanceId });
            bool frozen = GameEngine.HasModifier(st, N.Leader, "freeze");
            GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "south" }); // → north's Refresh Phase
            bool stayedRested = N.Leader.Rested; // frozen Leader must NOT become active
            // Control: a NON-frozen rested leader DOES un-rest at its Refresh (proves the refresh actually ran).
            var st2 = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "ldrfreeze_ctrl" });
            st2.Status = "active"; st2.Phase = "main"; st2.ActiveSeat = "south"; st2.TurnNumber = 6;
            st2.Players["south"].TurnsStarted = 3; st2.Players["north"].TurnsStarted = 3;
            st2.Players["north"].Leader.Rested = true;
            GameEngine.ApplyCommand(st2, new GameCommand { Type = "endTurn", Seat = "south" });
            bool controlUnrested = !st2.Players["north"].Leader.Rested;
            bool pass = frozen && stayedRested && controlUnrested;
            Console.WriteLine($"=== LEADERFREEZETEST === leader-frozen={frozen}(T) stayed-rested={stayedRested}(T) control-leader-unrested={controlUnrested}(T) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // rushchartest — EB04-011 "[Rush: Character]" — played this turn, may attack an opponent CHARACTER but
        // NOT the Leader (unlike full [Rush]).
        if (args.Length > 0 && args[0] == "rushchartest")
        {
            System.Func<string, bool> attackSucceeds = (string targetKind) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "rushchar" + targetKind });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                var atk = new CardInstance { InstanceId = "ATK", CardId = "EB04-011", Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 6 }; // played THIS turn
                S.CharacterArea[0] = atk;
                var rc = new CardInstance { InstanceId = "RC", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = true }; // rested char (valid target)
                N.CharacterArea[0] = rc;
                string target = targetKind == "char" ? "RC" : N.Leader.InstanceId;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "south", Attacker = "ATK", Target = target });
                return st.Battle != null;
            };
            bool vsChar = attackSucceeds("char");   // allowed (Rush:Character)
            bool vsLeader = attackSucceeds("leader"); // rejected (can't hit Leader the turn played)
            bool pass = vsChar && !vsLeader;
            Console.WriteLine($"=== RUSHCHARTEST === attack Character={vsChar}(T) attack Leader={vsLeader}(F) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // stageactivatetest — OP03-098 Enies Lobby "[Activate: Main] You may rest this Stage: If your Leader's
        // type includes 'CP', give up to 1 opp Char −2 cost." Activating rests the Stage (cost) and fires the body.
        if (args.Length > 0 && args[0] == "stageactivatetest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "stageact" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.Leader = new CardInstance { InstanceId = "LDR", CardId = "OP03-076", Owner = "south", Zone = "leader" }; // CP leader
            for (int i = 0; i < 5; i++) N.CharacterArea[i] = null;
            S.Stage = new CardInstance { InstanceId = "STG", CardId = "OP03-098", Owner = "south", Zone = "stage", Rested = false };
            var v = new CardInstance { InstanceId = "V", CardId = "EB01-002", Owner = "north", Zone = "character" }; // base cost 5
            N.CharacterArea[0] = v;
            int costBefore = GameEngine.GetCost(st, v);
            GameEngine.ApplyCommand(st, new GameCommand { Type = "activateMain", Seat = "south", Target = "STG" });
            bool stageRested = S.Stage != null && S.Stage.Rested;
            foreach (var pe in st.PendingEffects.Where(e => e.Seat == "south").ToList())
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "V" });
            int costAfter = GameEngine.GetCost(st, v);
            bool pass = stageRested && costAfter == costBefore - 2;
            Console.WriteLine($"=== STAGEACTIVATETEST === stage-rested={stageRested}(T)   opp cost {costBefore}->{costAfter} (want −2) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // donminustest — a "DON!! −N" cost may be paid with an ATTACHED DON (clicking it detaches it, weakening
        // the host Character), or with a cost-area DON (host keeps its power). Verifies the per-DON pick choice.
        if (args.Length > 0 && args[0] == "donminustest")
        {
            System.Func<string, (int, int, int)> payWith = (string clickDon) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "donminus" + clickDon });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var ch = new CardInstance { InstanceId = "CH", CardId = "ST01-006", Owner = "south", Zone = "character" }; // base 1000
                ch.AttachedDonIds.Add("ad1"); ch.AttachedDonIds.Add("ad2"); // power 3000 on owner turn
                S.CharacterArea[0] = ch;
                S.CostArea.Clear();
                S.CostArea.Add(new DonInstance { InstanceId = "ca1", Rested = false }); // 1 cost-area DON
                int donDeckBefore = S.DonDeck;
                var eff = new PendingEffect { EffectId = "D", Seat = "south", SourceInstanceId = "CH",
                    Text = "DON!! −1 (You may return the specified number of DON!! cards from your field to your DON!! deck.): Draw 1 card." };
                st.PendingEffects.Add(eff);
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "D", Target = null }); // await per-DON click
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "D", Target = clickDon }); // return the chosen DON
                return (ch.AttachedDonIds.Count, GameEngine.GetPower(st, ch), S.DonDeck - donDeckBefore);
            };
            var attached = payWith("ad1"); // return an attached DON → CH loses a DON + power
            var costArea = payWith("ca1"); // return a cost-area DON → CH keeps its DON + power
            bool pass = attached.Item1 == 1 && attached.Item2 == 2000 && attached.Item3 == 1
                        && costArea.Item1 == 2 && costArea.Item2 == 3000 && costArea.Item3 == 1;
            Console.WriteLine($"=== DONMINUSTEST === pay-attached: CHdon={attached.Item1}(1) CHpow={attached.Item2}(2000) donDeck+{attached.Item3}(1)   pay-costarea: CHdon={costArea.Item1}(2) CHpow={costArea.Item2}(3000) donDeck+{costArea.Item3}(1) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // milltest — self-mill ("trash N cards from the top of your deck"): (1) body-mill caps at deck size
        // (deck-out safety, no crash), (2) normal body-mill trashes exactly N, (3) mill-as-COST + body fires the
        // body only after the mill is paid, (4) cost-mill is UNPAYABLE when the deck is smaller than N.
        if (args.Length > 0 && args[0] == "milltest")
        {
            // helper: build a fresh south-turn state with a deck of exactly `deckN` cards
            System.Func<int, string, (GameState, PlayerState)> mk = (int deckN, string seed) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = seed });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                S.Trash.Clear();
                while (S.Deck.Count > deckN) S.Deck.RemoveAt(S.Deck.Count - 1);
                return (st, S);
            };
            // (1) body-mill 3 with a deck of only 1 → trashes only what's there (1), deck 0, NO crash. Per rule
            // 9-2-1-2, 0 cards in deck is itself a defeat condition, so the milling player correctly self-defeats
            // (status "finished") at the next rule-processing — the point is the mill caps at deck size cleanly.
            var (st1, S1) = mk(1, "mill1");
            for (int i = 0; i < 5; i++) S1.CharacterArea[i] = null;
            S1.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-006", Owner = "south", Zone = "character" };
            st1.PendingEffects.Add(new PendingEffect { EffectId = "M", Seat = "south", SourceInstanceId = "SRC", Text = "Trash 3 cards from the top of your deck." });
            GameEngine.ApplyCommand(st1, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "M", Target = null });
            bool deckoutSafe = S1.Deck.Count == 0 && S1.Trash.Count == 1 && st1.Status == "finished";

            // (2) body-mill 3 with a deck of 12 → deck 9, trash 3
            var (st2, S2) = mk(12, "mill2");
            for (int i = 0; i < 5; i++) S2.CharacterArea[i] = null;
            S2.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-006", Owner = "south", Zone = "character" };
            st2.PendingEffects.Add(new PendingEffect { EffectId = "M", Seat = "south", SourceInstanceId = "SRC", Text = "Trash 3 cards from the top of your deck." });
            GameEngine.ApplyCommand(st2, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "M", Target = null });
            bool normalMill = S2.Deck.Count == 9 && S2.Trash.Count == 3;

            // (3) mill-as-cost + body: EB04-049 "You may trash 2 ... : K.O. up to 1 opp Character base cost 5 or less"
            var (st3, S3) = mk(12, "mill3");
            var N3 = st3.Players["north"];
            for (int i = 0; i < 5; i++) { S3.CharacterArea[i] = null; N3.CharacterArea[i] = null; }
            S3.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-006", Owner = "south", Zone = "character" };
            var victim = new CardInstance { InstanceId = "VIC", CardId = "ST01-004", Owner = "north", Zone = "character" }; // Usopp, cost 2
            N3.CharacterArea[0] = victim;
            int deckB3 = S3.Deck.Count, trashB3 = S3.Trash.Count;
            st3.PendingEffects.Add(new PendingEffect { EffectId = "K", Seat = "south", SourceInstanceId = "SRC",
                Text = "You may trash 2 cards from the top of your deck: K.O. up to 1 of your opponent's Characters with a base cost of 5 or less." });
            // call 1: opt into the "You may trash 2" mill cost → pays it and QUEUES the KO body as a new effect
            GameEngine.ApplyCommand(st3, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "K", Target = null });
            bool costMilled = (deckB3 - S3.Deck.Count) == 2 && (S3.Trash.Count - trashB3) == 2;
            // call 2: the queued KO body now awaits a target — resolve it against VIC
            var koBody = st3.PendingEffects.FirstOrDefault(e => e.Seat == "south" && (e.Text ?? "").Contains("K.O."));
            if (koBody != null)
                GameEngine.ApplyCommand(st3, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = koBody.EffectId, Target = "VIC" });
            bool victimKod = N3.CharacterArea[0] == null && N3.Trash.Any(c => c.InstanceId == "VIC");

            // (4) cost-mill UNPAYABLE: same body but a deck of 1 → cost cannot be paid → no mill, no KO
            var (st4, S4) = mk(1, "mill4");
            var N4 = st4.Players["north"];
            for (int i = 0; i < 5; i++) { S4.CharacterArea[i] = null; N4.CharacterArea[i] = null; }
            S4.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-006", Owner = "south", Zone = "character" };
            var victim4 = new CardInstance { InstanceId = "VIC", CardId = "ST01-004", Owner = "north", Zone = "character" };
            N4.CharacterArea[0] = victim4;
            st4.PendingEffects.Add(new PendingEffect { EffectId = "K", Seat = "south", SourceInstanceId = "SRC",
                Text = "You may trash 2 cards from the top of your deck: K.O. up to 1 of your opponent's Characters with a base cost of 5 or less." });
            GameEngine.ApplyCommand(st4, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "K", Target = null });
            GameEngine.ApplyCommand(st4, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "K", Target = "VIC" });
            bool unpayableSafe = S4.Deck.Count == 1 && N4.CharacterArea[0] != null; // deck untouched, victim survives

            bool pass = deckoutSafe && normalMill && costMilled && victimKod && unpayableSafe;
            Console.WriteLine($"=== MILLTEST === deckoutSafe(deck0/trash1/active)={deckoutSafe}  normalMill(deck9/trash3)={normalMill}  costMill(-2deck/+2trash)={costMilled}  victimKO={victimKod}  unpayable(deck1/victim-alive)={unpayableSafe} : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // op04011test — conditional reveal with a POWER filter + unconditional "place at bottom" tail (OP04-011
        // Nami: "Reveal 1 from top. If the revealed card is a Character with 6000 power or more, this Character
        // gains +3000 this turn. Then, place the revealed card at the bottom of your deck."). Two guards:
        // (a) the "6000 power or more" filter must gate the buff; (b) the revealed card ALWAYS goes to the bottom.
        if (args.Length > 0 && args[0] == "op04011test")
        {
            System.Func<string, (int, string, string)> reveal = (string topCardId) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "rev" + topCardId });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var nami = new CardInstance { InstanceId = "NAMI", CardId = "OP04-011", Owner = "south", Zone = "character" }; // base 3000
                S.CharacterArea[0] = nami;
                // deck: [top = revealed] [sentinel] … — after "place at bottom" the sentinel becomes the new top
                S.Deck.Clear();
                S.Deck.Add(new CardInstance { InstanceId = "TOP", CardId = topCardId, Owner = "south", Zone = "deck" });
                S.Deck.Add(new CardInstance { InstanceId = "SENT", CardId = "ST01-006", Owner = "south", Zone = "deck" });
                S.Deck.Add(new CardInstance { InstanceId = "X3", CardId = "ST01-006", Owner = "south", Zone = "deck" });
                st.PendingEffects.Add(new PendingEffect { EffectId = "R", Seat = "south", SourceInstanceId = "NAMI",
                    Text = "Reveal 1 card from the top of your deck. If the revealed card is a Character card with 6000 power or more, this Character gains +3000 power during this turn. Then, place the revealed card at the bottom of your deck." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "R", Target = null });
                return (GameEngine.GetPower(st, nami), S.Deck.Count > 0 ? S.Deck[0].InstanceId : "-", S.Deck.Count > 0 ? S.Deck[S.Deck.Count - 1].InstanceId : "-");
            };
            var hi = reveal("OP11-017"); // 7000 char → buff fires (3000+3000=6000), TOP goes to bottom
            var lo = reveal("ST01-006"); //  1000 char → NO buff (3000), TOP still goes to bottom
            bool hiOk = hi.Item1 == 6000 && hi.Item2 == "SENT" && hi.Item3 == "TOP";
            bool loOk = lo.Item1 == 3000 && lo.Item2 == "SENT" && lo.Item3 == "TOP";
            bool pass = hiOk && loOk;
            Console.WriteLine($"=== OP04011TEST === hi(7000): pow={hi.Item1}(6000) top={hi.Item2}(SENT) bottom={hi.Item3}(TOP)   lo(1000): pow={lo.Item1}(3000) top={lo.Item2}(SENT) bottom={lo.Item3}(TOP) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // selfrevivetest — "Play this Character card from your trash[ rested]" self-revive (OP03-013/OP09-052/
        // ST30-008 enter RESTED; OP14-120/OP16-014 enter ACTIVE). The revive handler (L9387) must honor the
        // "rested" qualifier; it also must NO-OP cleanly when the slot is full or the card already left the trash.
        if (args.Length > 0 && args[0] == "selfrevivetest")
        {
            System.Func<string, bool, (bool, bool)> revive = (string bodyText, bool fillSlots) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "revive" + bodyText.Length + fillSlots });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                if (fillSlots) for (int i = 0; i < 5; i++) S.CharacterArea[i] = new CardInstance { InstanceId = "F" + i, CardId = "ST01-006", Owner = "south", Zone = "character" };
                // the source sits in trash as if just K.O.'d
                var dead = new CardInstance { InstanceId = "SELF", CardId = "OP03-013", Owner = "south", Zone = "trash" };
                S.Trash.Clear(); S.Trash.Add(dead);
                st.PendingEffects.Add(new PendingEffect { EffectId = "V", Seat = "south", SourceInstanceId = "SELF", Text = bodyText });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "V", Target = null });
                var back = S.CharacterArea.FirstOrDefault(c => c != null && c.InstanceId == "SELF");
                bool inPlay = back != null;
                bool rested = back != null && back.Rested;
                return (inPlay, rested);
            };
            var restedCard = revive("You may play this Character card from your trash rested.", false); // → in play, RESTED
            var activeCard = revive("Play this Character card from your trash.", false);                 // → in play, ACTIVE
            var noSlot = revive("Play this Character card from your trash.", true);                       // slots full → stays in trash
            bool pass = restedCard.Item1 && restedCard.Item2
                        && activeCard.Item1 && !activeCard.Item2
                        && !noSlot.Item1;
            Console.WriteLine($"=== SELFREVIVETEST === rested: inPlay={restedCard.Item1}(T) rested={restedCard.Item2}(T)   active: inPlay={activeCard.Item1}(T) rested={activeCard.Item2}(F)   full-slot: inPlay={noSlot.Item1}(F) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // op03090test — "Play up to 1 Character card with a type including \"CP\" and a cost of 4 or less from your
        // trash rested" (OP03-090). Verify the GLOW (IsValidEffectTarget) AND the resolver honor the DUAL filter
        // (type CP + cost ≤4) identically, the played card enters RESTED, and "up to 1" allows a skip.
        if (args.Length > 0 && args[0] == "op03090test")
        {
            string body = "Play up to 1 Character card with a type including \"CP\" and a cost of 4 or less from your trash rested.";
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op03090" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"];
            for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
            S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "OP03-090", Owner = "south", Zone = "character" };
            var good = new CardInstance { InstanceId = "GOOD", CardId = "EB01-017", Owner = "south", Zone = "trash" }; // CP0 cost2 ✓
            var badCost = new CardInstance { InstanceId = "BADC", CardId = "EB03-040", Owner = "south", Zone = "trash" }; // CP9 cost5 ✗cost
            var badType = new CardInstance { InstanceId = "BADT", CardId = "EB01-003", Owner = "south", Zone = "trash" }; // non-CP cost4 ✗type
            S.Trash.Clear(); S.Trash.Add(good); S.Trash.Add(badCost); S.Trash.Add(badType);
            var eff = new PendingEffect { EffectId = "P", Seat = "south", SourceInstanceId = "SRC", Text = body, TargetZone = EffectTargetZone.Trash };
            st.PendingEffects.Add(eff);
            // glow checks
            bool glowGood = GameEngine.IsValidEffectTarget(st, eff, good);
            bool glowBadCost = GameEngine.IsValidEffectTarget(st, eff, badCost);
            bool glowBadType = GameEngine.IsValidEffectTarget(st, eff, badType);
            // resolver must REJECT a non-CP target (stays in trash) — try badType first
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "P", Target = "BADT" });
            bool resolverRejectsBadType = S.Trash.Any(c => c.InstanceId == "BADT") && !S.CharacterArea.Any(c => c != null && c.InstanceId == "BADT");
            // then resolve against the valid target
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "P", Target = "GOOD" });
            var played = S.CharacterArea.FirstOrDefault(c => c != null && c.InstanceId == "GOOD");
            bool playedRested = played != null && played.Rested;
            bool goneFromTrash = !S.Trash.Any(c => c.InstanceId == "GOOD");
            bool pass = glowGood && !glowBadCost && !glowBadType && resolverRejectsBadType && playedRested && goneFromTrash;
            Console.WriteLine($"=== OP03090TEST === glow good={glowGood}(T) badCost={glowBadCost}(F) badType={glowBadType}(F)  resolver-rejects-badType={resolverRejectsBadType}(T)  played-rested={playedRested}(T) gone-from-trash={goneFromTrash}(T) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // op13047test — quoted-type gating in the removal-replacement path (OP13-047 Fossa: "If your Character
        // with a type including \"Whitebeard Pirates\" would be K.O.'d by your opponent's effect, you may trash
        // this Character instead."). The protection must fire ONLY for a WB victim (substring: "Whitebeard Pirates
        // Allies" counts), NOT a non-WB victim. Confirms the quoted-type filter (L4410) is enforced, not passed-all.
        if (args.Length > 0 && args[0] == "op13047test")
        {
            System.Func<string, (bool, bool)> koVictim = (string victimCardId) =>
            {
