            var gated = run(6, false);   // Life+hand=6 (>4) → nothing
            var draw = run(2, false);    // ≤4, no big char → draw 1 (hand+1, deck-1)
            var bigC = run(2, true);     // ≤4, big char → auto-draws (default); ramp-instead not offered in auto
            bool pass = gated.Item1 == 0 && gated.Item3 == 0
                        && draw.Item1 == 1 && draw.Item3 == 1
                        && bigC.Item1 == 1 && bigC.Item3 == 1;
            Console.WriteLine($"=== OP04040TEST === gated(6): hand+{gated.Item1}(0) deck-{gated.Item3}(0)   draw(2): hand+{draw.Item1}(1) deck-{draw.Item3}(1)   bigChar(2): hand+{bigC.Item1}(1) deck-{bigC.Item3}(1) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // condcoveragetest — batch-audit EvaluateCondition against unusual leading-If condition shapes harvested
        // from the DB. Each row builds a SATISFYING state and asserts the condition returns TRUE (an unhandled
        // condition silently returns false → the gated effect never fires, like #189). Reports any that fail.
        if (args.Length > 0 && args[0] == "condcoveragetest")
        {
            var mi = typeof(GameEngine).GetMethod("EvaluateCondition", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static);
            System.Func<string, System.Action<PlayerState, PlayerState, GameState>, bool> check = (string cond, System.Action<PlayerState, PlayerState, GameState> setup) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "cond" + cond.GetHashCode() });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                setup(S, N, st);
                return (bool)mi.Invoke(null, new object[] { st, "south", cond, S.CharacterArea.FirstOrDefault(c => c != null)?.InstanceId, false });
            };
            var results = new List<(string, bool)>();
            // 1. cost-8+ Character present
            results.Add(("you have a Character with a cost of 8 or more", check("you have a Character with a cost of 8 or more", (S, N, st) => S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "EB02-004", Owner = "south", Zone = "character" })));
            // 2. 2+ rested Characters
            results.Add(("you have 2 or more rested Characters", check("you have 2 or more rested Characters", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "ST01-006", Owner = "south", Zone = "character", Rested = true }; S.CharacterArea[1] = new CardInstance { InstanceId = "C1", CardId = "ST01-006", Owner = "south", Zone = "character", Rested = true }; })));
            // 3. any DON given (attached)
            results.Add(("you have any DON!! cards given", check("you have any DON!! cards given", (S, N, st) => { var c = new CardInstance { InstanceId = "C0", CardId = "ST01-006", Owner = "south", Zone = "character" }; c.AttachedDonIds.Add("d1"); S.CharacterArea[0] = c; })));
            // 4. fewer Life than opponent
            results.Add(("you have less Life cards than your opponent", check("you have less Life cards than your opponent", (S, N, st) => { S.Life.Clear(); S.Life.Add(new CardInstance { InstanceId = "l", CardId = "ST01-006", Owner = "south", Zone = "life" }); while (N.Life.Count < 3) N.Life.Add(new CardInstance { InstanceId = "nl" + N.Life.Count, CardId = "ST01-006", Owner = "north", Zone = "life" }); })));
            // 5. opponent has more DON than you
            results.Add(("your opponent has more DON!! cards on their field than you", check("your opponent has more DON!! cards on their field than you", (S, N, st) => { S.CostArea.Clear(); N.CostArea.Clear(); for (int i = 0; i < 5; i++) N.CostArea.Add(new DonInstance { InstanceId = "nd" + i }); S.CostArea.Add(new DonInstance { InstanceId = "sd" }); })));
            // 6. 2+ Characters with base cost 5+
            results.Add(("you have 2 or more Characters with a base cost of 5 or more", check("you have 2 or more Characters with a base cost of 5 or more", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "EB01-002", Owner = "south", Zone = "character" }; S.CharacterArea[1] = new CardInstance { InstanceId = "C1", CardId = "EB01-002", Owner = "south", Zone = "character" }; })));
            // 7. total of 2+ given DON
            results.Add(("you have a total of 2 or more given DON!! cards", check("you have a total of 2 or more given DON!! cards", (S, N, st) => { var c = new CardInstance { InstanceId = "C0", CardId = "ST01-006", Owner = "south", Zone = "character" }; c.AttachedDonIds.Add("d1"); c.AttachedDonIds.Add("d2"); S.CharacterArea[0] = c; })));
            // 8. this Character was played on this turn
            results.Add(("this Character was played on this turn", check("this Character was played on this turn", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "ST01-006", Owner = "south", Zone = "character", PlayedOnTurn = st.TurnNumber }; })));
            // 9. only Characters on your field are {Celestial Dragons} type
            results.Add(("the only Characters on your field are {Celestial Dragons} type Characters", check("the only Characters on your field are {Celestial Dragons} type Characters", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "OP05-084", Owner = "south", Zone = "character" }; })));
            // 10. 2+ rested {ODYSSEY} type Characters
            results.Add(("you have 2 or more rested {ODYSSEY} type Characters", check("you have 2 or more rested {ODYSSEY} type Characters", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "EB03-037", Owner = "south", Zone = "character", Rested = true }; S.CharacterArea[1] = new CardInstance { InstanceId = "C1", CardId = "EB03-037", Owner = "south", Zone = "character", Rested = true }; })));
            // 11. 20 or less cards in your deck
            results.Add(("you have 20 or less cards in your deck", check("you have 20 or less cards in your deck", (S, N, st) => { while (S.Deck.Count > 20) S.Deck.RemoveAt(S.Deck.Count - 1); })));
            // 12. 3 or more Characters
            results.Add(("you have 3 or more Characters", check("you have 3 or more Characters", (S, N, st) => { for (int i = 0; i < 3; i++) S.CharacterArea[i] = new CardInstance { InstanceId = "C" + i, CardId = "ST01-006", Owner = "south", Zone = "character" }; })));
            // ---- batch 2: rarer board-state conditions ----
            results.Add(("it is your second turn or later", check("it is your second turn or later", (S, N, st) => { S.TurnsStarted = 3; })));
            results.Add(("the total cost of your Characters is 5 or more", check("the total cost of your Characters is 5 or more", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "EB01-002", Owner = "south", Zone = "character" }; })));
            results.Add(("you have 5 Characters", check("you have 5 Characters", (S, N, st) => { for (int i = 0; i < 5; i++) S.CharacterArea[i] = new CardInstance { InstanceId = "C" + i, CardId = "ST01-006", Owner = "south", Zone = "character" }; })));
            results.Add(("you have 5 or less active DON!! cards", check("you have 5 or less active DON!! cards", (S, N, st) => { S.CostArea.Clear(); for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = "d" + i, Rested = false }); })));
            results.Add(("you have 2 or more active DON!! cards", check("you have 2 or more active DON!! cards", (S, N, st) => { S.CostArea.Clear(); for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = "d" + i, Rested = false }); })));
            results.Add(("there is a Character with 8000 power or more", check("there is a Character with 8000 power or more", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "EB01-023", Owner = "south", Zone = "character" }; })));
            results.Add(("you have 5 {Impel Down} type Characters with different card names", check("you have 5 {Impel Down} type Characters with different card names", (S, N, st) => { var ids = new[] { "EB01-022", "EB01-026", "EB01-032", "EB01-036", "EB02-038" }; for (int i = 0; i < 5; i++) S.CharacterArea[i] = new CardInstance { InstanceId = "C" + i, CardId = ids[i], Owner = "south", Zone = "character" }; })));
            results.Add(("all of your DON!! cards are rested", check("all of your DON!! cards are rested", (S, N, st) => { S.CostArea.Clear(); for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = "d" + i, Rested = true }); })));
            // ---- batch 3: color-filtered / named-card / type counts ----
            results.Add(("you have 3 or more blue {Cross Guild} type Characters", check("you have 3 or more blue {Cross Guild} type Characters", (S, N, st) => { for (int i = 0; i < 3; i++) S.CharacterArea[i] = new CardInstance { InstanceId = "C" + i, CardId = "EB03-021", Owner = "south", Zone = "character" }; })));
            results.Add(("you have 2 or more [Prisoner of Impel Down] cards", check("you have 2 or more [Prisoner of Impel Down] cards", (S, N, st) => { for (int i = 0; i < 2; i++) S.CharacterArea[i] = new CardInstance { InstanceId = "C" + i, CardId = "OP16-042", Owner = "south", Zone = "character" }; })));
            results.Add(("you have 3 or more {Foxy Pirates} type Characters", check("you have 3 or more {Foxy Pirates} type Characters", (S, N, st) => { var ids = new[] { "EB02-034", "EB04-033", "EB04-036" }; for (int i = 0; i < 3; i++) S.CharacterArea[i] = new CardInstance { InstanceId = "C" + i, CardId = ids[i], Owner = "south", Zone = "character" }; })));
            // ---- batch 4: opponent-scope / base-power / power-filtered / word-order shapes ----
            results.Add(("there is a Character with 8000 power or more", check("there is a Character with 8000 power or more", (S, N, st) => { N.CharacterArea[0] = new CardInstance { InstanceId = "OPC", CardId = "EB01-023", Owner = "north", Zone = "character" }; }))); // opp-side only (any field)
            results.Add(("you have 1 or less Characters with 6000 power or more", check("you have 1 or less Characters with 6000 power or more", (S, N, st) => { }))); // 0 such → 0≤1 TRUE
            results.Add(("you have a Character with 10000 power or more", check("you have a Character with 10000 power or more", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "EB02-004", Owner = "south", Zone = "character" }; })));
            results.Add(("you have a Character with 7000 base power or more", check("you have a Character with 7000 base power or more", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "EB01-002", Owner = "south", Zone = "character" }; })));
            results.Add(("you have a {Donquixote Pirates} type Character with 6000 power or more", check("you have a {Donquixote Pirates} type Character with 6000 power or more", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "EB03-010", Owner = "south", Zone = "character" }; })));
            results.Add(("your opponent has a Character with 5000 or more power", check("your opponent has a Character with 5000 or more power", (S, N, st) => { N.CharacterArea[0] = new CardInstance { InstanceId = "OPC", CardId = "EB01-002", Owner = "north", Zone = "character" }; }))); // word order "5000 or more power"
            results.Add(("your opponent has a Character with 8000 base power or more", check("your opponent has a Character with 8000 base power or more", (S, N, st) => { N.CharacterArea[0] = new CardInstance { InstanceId = "OPC", CardId = "EB02-004", Owner = "north", Zone = "character" }; })));
            results.Add(("your opponent has a Character with 8000 power or more", check("your opponent has a Character with 8000 power or more", (S, N, st) => { N.CharacterArea[0] = new CardInstance { InstanceId = "OPC", CardId = "EB01-023", Owner = "north", Zone = "character" }; })));
            // ---- batch 5: NEGATIVE scope assertions (char on the WRONG side must NOT satisfy) ----
            System.Func<string, System.Action<PlayerState, PlayerState, GameState>, bool> checkNeg = (string cond, System.Action<PlayerState, PlayerState, GameState> setup) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "condN" + cond.GetHashCode() });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                setup(S, N, st);
                bool r = (bool)mi.Invoke(null, new object[] { st, "south", cond, S.CharacterArea.FirstOrDefault(c => c != null)?.InstanceId, false });
                return !r; // pass when the condition is correctly FALSE
            };
            // "your opponent has a Character with 8000 power" — 8000 char on MY side, opp empty → must be FALSE
            results.Add(("[neg] opp-8000-power with char on MY side", checkNeg("your opponent has a Character with 8000 power or more", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "EB01-023", Owner = "south", Zone = "character" }; })));
            // "you have 2 or more [Prisoner of Impel Down] cards" — only 1 on field → must be FALSE
            results.Add(("[neg] 2+ named with only 1 present", checkNeg("you have 2 or more [Prisoner of Impel Down] cards", (S, N, st) => { S.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "OP16-042", Owner = "south", Zone = "character" }; })));
            // "you have 3 or more blue {Cross Guild} type Characters" — only 2 → must be FALSE
            results.Add(("[neg] 3+ Cross Guild with only 2", checkNeg("you have 3 or more blue {Cross Guild} type Characters", (S, N, st) => { for (int i = 0; i < 2; i++) S.CharacterArea[i] = new CardInstance { InstanceId = "C" + i, CardId = "EB03-021", Owner = "south", Zone = "character" }; })));
            int failCount = results.Count(r => !r.Item2);
            Console.WriteLine("=== CONDCOVERAGETEST ===");
            foreach (var r in results) Console.WriteLine($"  [{(r.Item2 ? "OK " : "FAIL")}] {r.Item1}");
            Console.WriteLine($"  {results.Count - failCount}/{results.Count} conditions satisfied : {(failCount == 0 ? "PASS" : "FAIL")}");
            return failCount == 0 ? 0 : 1;
        }
        // eb04046test — EB04-046 Doll "[Opponent's Turn] All of your {Navy} type Characters gain +2 cost." A
        // continuous defensive cost aura (raises own Navy Characters' cost so opponent cost-removal can't hit
        // them) that is ACTIVE only during the opponent's turn. Verifies GetCost reflects +2 on opp turn (source
        // buffs itself too), 0 on own turn, and that a non-Navy Character is unaffected.
        if (args.Length > 0 && args[0] == "eb04046test")
        {
            System.Func<string, (int, int, int)> costs = (string activeSeat) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "doll" + activeSeat });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = activeSeat; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var doll = new CardInstance { InstanceId = "DOLL", CardId = "EB04-046", Owner = "south", Zone = "character" }; // Navy, base 2
                var komei = new CardInstance { InstanceId = "KOMEI", CardId = "EB02-034", Owner = "south", Zone = "character" }; // Navy, base 4
                var nonNavy = new CardInstance { InstanceId = "NN", CardId = "ST01-006", Owner = "south", Zone = "character" }; // base 1, not Navy
                S.CharacterArea[0] = doll; S.CharacterArea[1] = komei; S.CharacterArea[2] = nonNavy;
                return (GameEngine.GetCost(st, doll), GameEngine.GetCost(st, komei), GameEngine.GetCost(st, nonNavy));
            };
            var opp = costs("north"); // opponent's turn → +2 to Navy
            var own = costs("south"); // own turn → no bonus
            bool pass = opp.Item1 == 4 && opp.Item2 == 6 && opp.Item3 == 1
                        && own.Item1 == 2 && own.Item2 == 4 && own.Item3 == 1;
            Console.WriteLine($"=== EB04046TEST === oppTurn: doll={opp.Item1}(4) komei={opp.Item2}(6) nonNavy={opp.Item3}(1)   ownTurn: doll={own.Item1}(2) komei={own.Item2}(4) nonNavy={own.Item3}(1) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // op13004test — OP13-004 Sabo leader: (1) "If you have 4 or more Life cards, give this Leader −1000
        // power." (2) "[DON!! x1] If you have a Character with a cost of 8 or more, your Leader and all of your
        // Characters gain +1000 power." Aura is gated on BOTH a DON!! x1 threshold (Leader has ≥1 attached DON)
        // AND the cost-8+ condition. Measured on a plain recipient char (no DON confound) + the Leader debuff.
        if (args.Length > 0 && args[0] == "op13004test")
        {
            System.Func<int, int, bool, int, int> setup = (int life, int leaderDon, bool bigChar, int which) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st13", NorthDeck = "st13", Seed = "sabo" + life + leaderDon + bigChar + which });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                // force the leader to be OP13-004
                S.Leader = new CardInstance { InstanceId = "LDR", CardId = "OP13-004", Owner = "south", Zone = "leader" };
                for (int i = 0; i < leaderDon; i++) S.Leader.AttachedDonIds.Add("ld" + i);
                S.Life.Clear();
                for (int i = 0; i < life; i++) S.Life.Add(new CardInstance { InstanceId = "L" + i, CardId = "ST01-006", Owner = "south", Zone = "life" });
                var recip = new CardInstance { InstanceId = "RECIP", CardId = "ST01-006", Owner = "south", Zone = "character" }; // base 1000
                S.CharacterArea[0] = recip;
                if (bigChar) S.CharacterArea[1] = new CardInstance { InstanceId = "BIG", CardId = "EB02-004", Owner = "south", Zone = "character" }; // cost 8
                return which == 0 ? GameEngine.GetPower(st, recip) : GameEngine.GetPower(st, S.Leader);
            };
            int auraOn = setup(2, 1, true, 0);   // DON + big char → recip 1000+1000=2000
            int noDon = setup(2, 0, true, 0);    // no DON → aura off → 1000
            int noBig = setup(2, 1, false, 0);   // no big char → aura off → 1000
            int lifeDebuff = setup(5, 0, false, 1); // Life 5 (≥4), leader base 5000 −1000 = 4000 (no DON self-buff)
            bool pass = auraOn == 2000 && noDon == 1000 && noBig == 1000 && lifeDebuff == 4000;
            Console.WriteLine($"=== OP13004TEST === recip auraON={auraOn}(2000) noDON={noDon}(1000) noBigChar={noBig}(1000)   leader lifeDebuff={lifeDebuff}(4000) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // auraflttest — aura RECIPIENT-FILTER variants: (1) self-exclusion "other than this Character" (OP04-012
        // Cobra: {Alabasta} others +1000, source NOT buffed); (2) multi-type "or" (OP10-001 Smoker leader: {Navy}
        // OR {Punk Hazard} +1000, opp turn); (3) base-cost filter from a STAGE (EB04-010: base cost 1 +5000, opp
        // turn). Confirms each recipient filter resolves and non-matching Characters are untouched.
        if (args.Length > 0 && args[0] == "auraflttest")
        {
            // (1) self-exclusion, own turn
            int koza, cobra;
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "cobra" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var cob = new CardInstance { InstanceId = "COBRA", CardId = "OP04-012", Owner = "south", Zone = "character" }; // Alabasta, power 0, aura source
                var kz = new CardInstance { InstanceId = "KOZA", CardId = "EB01-004", Owner = "south", Zone = "character" };  // Alabasta, power 3000
                S.CharacterArea[0] = cob; S.CharacterArea[1] = kz;
                koza = GameEngine.GetPower(st, kz); cobra = GameEngine.GetPower(st, cob);
            }
            // (2) multi-type OR, opp turn, Smoker leader
            int komei, monet, plain, komeiOwn;
            {
                System.Func<string, (int, int, int)> run = (string active) =>
                {
                    var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "smoker" + active });
                    st.Status = "active"; st.Phase = "main"; st.ActiveSeat = active; st.TurnNumber = 6;
                    var S = st.Players["south"];
                    for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                    S.Leader = new CardInstance { InstanceId = "LDR", CardId = "OP10-001", Owner = "south", Zone = "leader" };
                    var km = new CardInstance { InstanceId = "KM", CardId = "EB02-034", Owner = "south", Zone = "character" }; // Navy 6000
                    var mn = new CardInstance { InstanceId = "MN", CardId = "EB03-010", Owner = "south", Zone = "character" }; // Punk Hazard 6000
                    var pl = new CardInstance { InstanceId = "PL", CardId = "ST01-006", Owner = "south", Zone = "character" }; // plain 1000
                    S.CharacterArea[0] = km; S.CharacterArea[1] = mn; S.CharacterArea[2] = pl;
                    return (GameEngine.GetPower(st, km), GameEngine.GetPower(st, mn), GameEngine.GetPower(st, pl));
                };
                var oppT = run("north"); komei = oppT.Item1; monet = oppT.Item2; plain = oppT.Item3;
                komeiOwn = run("south").Item1;
            }
            // (3) base-cost filter from a Stage, opp turn
            int doma, kozaC2;
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "lulucia" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.Stage = new CardInstance { InstanceId = "STG", CardId = "EB04-010", Owner = "south", Zone = "stage" };
                var dm = new CardInstance { InstanceId = "DOMA", CardId = "EB01-005", Owner = "south", Zone = "character" }; // base cost 1, power 3000
                var kz2 = new CardInstance { InstanceId = "KZ2", CardId = "EB01-004", Owner = "south", Zone = "character" }; // base cost 2, power 3000
                S.CharacterArea[0] = dm; S.CharacterArea[1] = kz2;
                doma = GameEngine.GetPower(st, dm); kozaC2 = GameEngine.GetPower(st, kz2);
            }
            bool pass = koza == 4000 && cobra == 0
                        && komei == 7000 && monet == 7000 && plain == 1000 && komeiOwn == 6000
                        && doma == 8000 && kozaC2 == 3000;
            Console.WriteLine($"=== AURAFLTTEST === self-excl: koza={koza}(4000) cobra={cobra}(0)   multiOR opp: komei={komei}(7000) monet={monet}(7000) plain={plain}(1000) own: komei={komeiOwn}(6000)   baseCost1: doma={doma}(8000) koza2={kozaC2}(3000) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // op02024test — OP02-024 Moby Dick (Stage): "[Your Turn] If you have 1 or less Life cards, your
        // [Edward.Newgate] and all your Characters with a type including \"Whitebeard Pirates\" gain +2000 power."
        // Conditional aura that must FLIP LIVE on BOTH gates: Life ≤1 AND your turn. Recipient uses "type
        // including" (substring — buffs "Whitebeard Pirates Allies" too, per #186/#183). Stage as aura source.
        if (args.Length > 0 && args[0] == "op02024test")
        {
            System.Func<int, string, (int, int)> run = (int life, string active) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "moby" + life + active });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = active; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.Stage = new CardInstance { InstanceId = "MOBY", CardId = "OP02-024", Owner = "south", Zone = "stage" };
                var vista = new CardInstance { InstanceId = "VISTA", CardId = "EB02-027", Owner = "south", Zone = "character" }; // WB exact, 5000
                var doma = new CardInstance { InstanceId = "DOMA", CardId = "EB01-005", Owner = "south", Zone = "character" };  // "WB Allies" substring, 3000
                S.CharacterArea[0] = vista; S.CharacterArea[1] = doma;
