            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = "KOE", Target = "VICT" });
            var react = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
            bool reactQueued = react != null;
            if (react != null)
            {
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = react.EffectId, Target = null });   // pay DON-rest, await hand pick
                var react2 = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
                if (react2 != null)
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = react2.EffectId, Target = "ARLONG" });
            }
            int restedDon = S.CostArea.Count(d => d.Rested);
            bool arlongInPlay = S.CharacterArea.Any(c => c != null && c.InstanceId == "ARLONG");
            bool arlongGoneFromHand = !S.Hand.Any(c => c.InstanceId == "ARLONG");
            bool pass = reactQueued && restedDon == 1 && arlongInPlay && arlongGoneFromHand;
            Console.WriteLine($"=== OP11035TEST === reactQueued={reactQueued}(T) donRested={restedDon}(1) arlongInPlay={arlongInPlay}(T) goneFromHand={arlongGoneFromHand}(T) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // koreactprobe — for each "When this Character is K.O.'d by your opponent's effect, <payoff>" card, KO it via
        // a north effect and report whether the reactive payoff got QUEUED (vs silently logged "needs manual resolution").
        if (args.Length > 0 && args[0] == "koreactprobe")
        {
            foreach (var cid in new[] { "OP11-051", "OP11-035", "OP11-024", "EB01-057", "OP09-052" })
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "kore" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "VICT", CardId = cid, Owner = "south", Zone = "character", Rested = false };
                N.CharacterArea[0] = new CardInstance { InstanceId = "NC", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false };
                int pendBefore = st.PendingEffects.Count;
                st.PendingEffects.Add(new PendingEffect { EffectId = "KOE", Seat = "north", SourceInstanceId = "NC",
                    Text = "K.O. up to 1 of your opponent's Characters." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = "KOE", Target = "VICT" });
                bool koed = S.CharacterArea[0] == null || S.CharacterArea[0].InstanceId != "VICT";
                var react = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
                // Direct gate verdict on the reactive body (via reflection) to distinguish "KO didn't fire" from "gate rejected".
                var mi = typeof(GameEngine).GetMethod("IsAutomatedEffectPattern", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static);
                var cdef = CardData.GetCard(cid);
                string body = "";
                foreach (var ln in (cdef.Effect ?? "").Split('\n')) { var m = System.Text.RegularExpressions.Regex.Match(ln, @"is K\.O\.'d[^,]*, (.+)$"); if (m.Success) { body = m.Groups[1].Value.Trim(); break; } }
                bool gate = body != "" && (bool)mi.Invoke(null, new object[] { body });
                int lifeCnt = S.Life.Count; bool lookActive = st.DeckLook != null && st.DeckLook.Seat == "south";
                Console.WriteLine($"{cid}: koed={koed} reactQueued={(react != null)} gate={gate} southLife={lifeCnt} lookActive={lookActive} body=\"{(body.Length > 50 ? body.Substring(0, 50) : body)}\"");
            }
            return 0;
        }
        // koreplacetest — replacement effects ("If … would be K.O.'d/removed …, you may <pay> instead") with the
        // tricky non-numeric / named / Leader-targeted payments: OP04-082 (rest your Leader or 1 [Corrida Coliseum]),
        // OP15-009 (give your Leader −2000), OP11-110 (rest 1 of your [Fish-Man Island] or your [Shirahoshi] Leader).
        // Verifies the victim survives when a LEGAL payment exists, dies when only ILLEGAL targets exist, and never
        // rests a decoy character or a wrong-named leader.
        if (args.Length > 0 && args[0] == "koreplacetest")
        {
            bool all = true;
            // OP11-110 legal (Shirahoshi leader present) → survives via leader; decoy not rested.
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "krt1" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; st.Players["north"].CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "GUARD", CardId = "OP11-110", Owner = "south", Zone = "character" };
                S.CharacterArea[1] = new CardInstance { InstanceId = "DECOY", CardId = "ST01-006", Owner = "south", Zone = "character" };
                S.Leader = new CardInstance { InstanceId = "LDR", CardId = "OP11-022", Owner = "south", Zone = "leader" };
                st.PendingEffects.Add(new PendingEffect { EffectId = "K", Seat = "north", SourceInstanceId = "N", Text = "K.O. up to 1 of your opponent's Characters." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = "K", Target = "GUARD" });
                bool ok = S.CharacterArea.Any(c => c != null && c.InstanceId == "GUARD")
                          && !S.CharacterArea.Any(c => c != null && c.InstanceId == "DECOY" && c.Rested);
                all &= ok; Console.WriteLine($"  OP11-110 legal: survived+decoyOk={ok}");
            }
            // OP11-110 illegal (no Shirahoshi/Fish-Man Island) → dies; nothing wrongly rested.
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "krt2" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; st.Players["north"].CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "GUARD", CardId = "OP11-110", Owner = "south", Zone = "character" };
                S.CharacterArea[1] = new CardInstance { InstanceId = "DECOY", CardId = "ST01-006", Owner = "south", Zone = "character" };
                st.PendingEffects.Add(new PendingEffect { EffectId = "K", Seat = "north", SourceInstanceId = "N", Text = "K.O. up to 1 of your opponent's Characters." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = "K", Target = "GUARD" });
                bool ok = !S.CharacterArea.Any(c => c != null && c.InstanceId == "GUARD")
                          && !S.CharacterArea.Any(c => c != null && c.InstanceId == "DECOY" && c.Rested)
                          && !(S.Leader != null && S.Leader.Rested);
                all &= ok; Console.WriteLine($"  OP11-110 illegal: diedNoIllegalPay={ok}");
            }
            // OP04-082 self-protect via resting the Leader.
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "krt3" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; st.Players["north"].CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "GUARD", CardId = "OP04-082", Owner = "south", Zone = "character" };
                st.PendingEffects.Add(new PendingEffect { EffectId = "K", Seat = "north", SourceInstanceId = "N", Text = "K.O. up to 1 of your opponent's Characters." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = "K", Target = "GUARD" });
                bool ok = S.CharacterArea.Any(c => c != null && c.InstanceId == "GUARD") && S.Leader != null && S.Leader.Rested;
                all &= ok; Console.WriteLine($"  OP04-082: survivedViaLeaderRest={ok}");
            }
            // OP15-009 protects a separate 7000-or-less victim by giving the Leader -2000.
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "krt4" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; st.Players["north"].CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "GUARD", CardId = "OP15-009", Owner = "south", Zone = "character" };
                S.CharacterArea[1] = new CardInstance { InstanceId = "VICT", CardId = "ST01-006", Owner = "south", Zone = "character" };
                int lp0 = GameEngine.GetPower(st, S.Leader);
                st.PendingEffects.Add(new PendingEffect { EffectId = "K", Seat = "north", SourceInstanceId = "N", Text = "K.O. up to 1 of your opponent's Characters." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = "K", Target = "VICT" });
                bool ok = S.CharacterArea.Any(c => c != null && c.InstanceId == "VICT") && GameEngine.GetPower(st, S.Leader) == lp0 - 2000;
                all &= ok; Console.WriteLine($"  OP15-009: victimSaved+leaderMinus2000={ok}");
            }
            Console.WriteLine($"=== KOREPLACETEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // turnlifetest — #220: "turn N cards from the top of your Life cards face-up/down: <payoff>" cost only checked
        // Life COUNT, not whether N FLIPPABLE (opposite-state) cards exist — so it paid for FREE when all Life was
        // already in the target state, firing the payoff without paying. Verify payable/unpayable for both directions.
        if (args.Length > 0 && args[0] == "turnlifetest")
        {
            bool all = true;
            // faceUp helper: build a KO effect gated on turning `n` Life face-up/down; return whether the payoff (KO) fired.
            bool RunKO(string clause, int lifeCount, bool lifeFaceUp)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "tl_" + clause.Length + lifeCount + lifeFaceUp });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"]; S.TurnsStarted = 3;
                S.Life.Clear();
                for (int i = 0; i < lifeCount; i++) S.Life.Add(new CardInstance { InstanceId = "sl" + i, CardId = "ST01-006", Owner = "south", Zone = "life", FaceUp = lifeFaceUp });
                for (int i = 0; i < 5; i++) N.CharacterArea[i] = null;
                N.CharacterArea[0] = new CardInstance { InstanceId = "NC", CardId = "ST01-006", Owner = "north", Zone = "character", PlayedOnTurn = 3 };
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId, Text = clause });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                var react = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
                if (react != null) GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = react.EffectId, Target = "NC" });
                return !N.CharacterArea.Any(c => c != null && c.InstanceId == "NC");   // KO fired?
            }
            void Check(string label, bool got, bool want) { bool ok = got == want; all &= ok; Console.WriteLine($"  {label}: koFired={got} want={want} : {(ok ? "ok" : "FAIL")}"); }
            string up = "You may turn 1 card from the top of your Life cards face-up: K.O. up to 1 of your opponent's Characters with a base cost of 4 or less.";
            Check("face-up payable (3 face-down)", RunKO(up, 3, false), true);
            Check("face-up UNPAYABLE (all face-up)", RunKO(up, 2, true), false);
            string down = "You may turn 1 card from the top of your Life cards face-down: K.O. up to 1 of your opponent's Characters with a base cost of 4 or less.";
            Check("face-down payable (2 face-up)", RunKO(down, 2, true), true);
            Check("face-down UNPAYABLE (all face-down)", RunKO(down, 3, false), false);
            Console.WriteLine($"=== TURNLIFETEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // op16104test — OP16-104 (base 3000): "[When Attacking] Select up to 1 of your opponent's Characters. This
