        if (args.Length > 0 && args[0] == "op16104test")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op16104" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"]; S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "OP16-104", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
            N.CharacterArea[0] = new CardInstance { InstanceId = "TGT", CardId = "EB01-002", Owner = "north", Zone = "character", PlayedOnTurn = 3 }; // 7000
            int srcBefore = GameEngine.GetPower(st, S.CharacterArea[0]);
            int tgtPow = GameEngine.GetPower(st, N.CharacterArea[0]);
            st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "SRC",
                Text = "Select up to 1 of your opponent's Characters. This Character's base power becomes the same as the selected Character during this turn." });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "TGT" });
            int srcAfter = GameEngine.GetPower(st, S.CharacterArea[0]);
            bool pass = srcAfter == tgtPow;
            Console.WriteLine($"=== OP16104TEST === srcBefore={srcBefore} selectedPow={tgtPow} srcAfter={srcAfter}(want {tgtPow}) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
