        // op15092test — OP15-092 Luffy modal-by-trash-count: base 7000/cost 7. ≥10 trash → base becomes 9000 AND
        // +10 cost; ≥30 trash → +1000 power (cumulative → 10000). Verify base-power-set + the +10 cost + cumulative buff.
        if (args.Length > 0 && args[0] == "op15092test")
        {
            bool all = true;
            void Run(string label, int trash, int expectPower, int expectCost)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op15092_" + trash });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "L", CardId = "OP15-092", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
                S.Trash.Clear();
                for (int i = 0; i < trash; i++) S.Trash.Add(new CardInstance { InstanceId = "t" + i, CardId = "ST01-006", Owner = "south", Zone = "trash" });
                int power = GameEngine.GetPower(st, S.CharacterArea[0]);
                int cost = GameEngine.GetCost(st, S.CharacterArea[0]);
                bool ok = power == expectPower && cost == expectCost;
                all &= ok;
                Console.WriteLine($"  {label} (trash={trash}): power={power}(want {expectPower}) cost={cost}(want {expectCost}) : {(ok ? "ok" : "FAIL")}");
            }
            Run("<10 trash: base 7000/cost 7", 5, 7000, 7);
            Run("≥10 trash: base 9000 + +10 cost", 12, 9000, 17);
            Run("≥30 trash: 9000+1000 power", 32, 10000, 17);
