        // swaptest — "Swap the base power of the selected Characters with each other during this turn." OP14-001
        // (own {Supernovas}/{Heart Pirates}) + OP14-017 (opponent, 9000 base or less). After swapping A(6000)↔B(1000),
        // A's power becomes 1000 and B's becomes 6000 this turn.
        if (args.Length > 0 && args[0] == "swaptest")
        {
            bool all = true;
            void Check(string label, bool ok) { all &= ok; Console.WriteLine($"  {label}: {(ok ? "ok" : "FAIL")}"); }
            // OP14-001: two OWN {Supernovas}/{Heart Pirates} chars, powers 6000 & 1000.
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "swap1" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "A", CardId = "EB01-012", Owner = "south", Zone = "character", PlayedOnTurn = 3 }; // 6000
                S.CharacterArea[1] = new CardInstance { InstanceId = "B", CardId = "EB01-015", Owner = "south", Zone = "character", PlayedOnTurn = 3 }; // 1000
                int aBefore = GameEngine.GetPower(st, S.CharacterArea[0]), bBefore = GameEngine.GetPower(st, S.CharacterArea[1]);
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId,
                    Text = "Select 2 of your {Supernovas} or {Heart Pirates} type Characters. Swap the base power of the selected Characters with each other during this turn." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "A" });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "B" });
                int aAfter = GameEngine.GetPower(st, S.CharacterArea[0]), bAfter = GameEngine.GetPower(st, S.CharacterArea[1]);
                Check($"OP14-001 swap A{aBefore}→{aAfter} B{bBefore}→{bAfter}", aAfter == bBefore && bAfter == aBefore);
            }
            // OP14-017: two OPPONENT chars with 9000 base or less (7000 & 1000).
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "swap2" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"]; S.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) N.CharacterArea[i] = null;
                N.CharacterArea[0] = new CardInstance { InstanceId = "X", CardId = "EB01-002", Owner = "north", Zone = "character", PlayedOnTurn = 3 }; // 7000
                N.CharacterArea[1] = new CardInstance { InstanceId = "Y", CardId = "EB01-015", Owner = "north", Zone = "character", PlayedOnTurn = 3 }; // 1000
                int xB = GameEngine.GetPower(st, N.CharacterArea[0]), yB = GameEngine.GetPower(st, N.CharacterArea[1]);
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId,
                    Text = "Select 2 of your opponent's Characters with 9000 base power or less. Swap the base power of the selected Characters with each other during this turn." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "X" });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "Y" });
                int xA = GameEngine.GetPower(st, N.CharacterArea[0]), yA = GameEngine.GetPower(st, N.CharacterArea[1]);
                Check($"OP14-017 opp swap X{xB}→{xA} Y{yB}→{yA}", xA == yB && yA == xB);
            }
            // OP14-009: swap your Leader (5000) with a Character (2000).
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "swap3" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "CH", CardId = "OP01-019", Owner = "south", Zone = "character", PlayedOnTurn = 3 }; // 2000
                int ldrB = GameEngine.GetPower(st, S.Leader), chB = GameEngine.GetPower(st, S.CharacterArea[0]);
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId,
                    Text = "Select your Leader and 1 Character. Swap the base power of the selected Characters with each other during this turn." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = S.Leader.InstanceId });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "CH" });
                int ldrA = GameEngine.GetPower(st, S.Leader), chA = GameEngine.GetPower(st, S.CharacterArea[0]);
                Check($"OP14-009 Leader↔Char L{ldrB}→{ldrA} C{chB}→{chA}", ldrA == chB && chA == ldrB);
            }
