        // costleadertest — "You may give your active Leader −5000 power during this turn: <payoff>" self-debuff cost.
        // (a) active Leader → cost paid (Leader −5000) + payoff (draw) fires; (b) RESTED Leader → cost unpayable
        // ("active" requirement) → no debuff, no payoff. Plus OP04-002's compound "rest this Character AND give…".
        if (args.Length > 0 && args[0] == "costleadertest")
        {
            bool all = true;
            // EB03-006-style "give your active Leader −5000: Draw 1"
            void RunDraw(string label, bool leaderRested, bool expectPaid)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "cl_" + label });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3;
                S.Leader.Rested = leaderRested;
                int ldrBase = GameEngine.GetPower(st, S.Leader);   // note: rested doesn't change base power
                int handBefore = S.Hand.Count;
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId, Text = "You may give your active Leader −5000 power during this turn: Draw 1 card." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                int drew = S.Hand.Count - handBefore;
                int ldrPow = GameEngine.GetPower(st, S.Leader);
                bool paid = drew == 1;
                bool ok = paid == expectPaid && (!expectPaid || ldrPow == ldrBase - 5000);
                all &= ok;
                Console.WriteLine($"  {label} (leaderRested={leaderRested}): drew={drew} leaderPow {ldrBase}→{ldrPow} : {(ok ? "ok" : "FAIL")}");
            }
            RunDraw("active leader → pay+draw", false, true);
            RunDraw("rested leader → unpayable", true, false);
            // OP04-002 compound: rest this Character AND give active Leader −5000 → deck-look starts.
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "cl_op04002" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "OP04-002", Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 3 };
                int ldrBase = GameEngine.GetPower(st, S.Leader);
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "SRC",
