        if (args.Length > 0 && args[0] == "untilhavetest")
        {
            bool all = true;
            void Check(string label, int got, int want) { bool ok = got == want; all &= ok; Console.WriteLine($"  {label}: {got} want={want} : {(ok ? "ok" : "FAIL")}"); }
            GameState Fresh(string seed) { var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = seed }); st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6; st.Players["south"].TurnsStarted = 3; return st; }
            // Draw-up to 3
            foreach (var (h, exp) in new[] { (1, 3), (5, 5) })
