                Check($"draw-up hand {h}→", S.Hand.Count, exp);
            }
            // Trash-Life down to 2
            foreach (var (l, exp) in new[] { (5, 2), (1, 1) })
            {
                var st = Fresh("uh_l" + l); var S = st.Players["south"];
                S.Life.Clear(); for (int i = 0; i < l; i++) S.Life.Add(new CardInstance { InstanceId = "l" + i, CardId = "ST01-006", Owner = "south", Zone = "life", FaceUp = false });
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId, Text = "Trash cards from the top of your Life cards until you have 2 Life cards." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                Check($"trash-Life {l}→", S.Life.Count, exp);
            }
            // Trash-hand down to 5 (interactive: click cards until 5 remain)
            foreach (var (h, exp) in new[] { (8, 5), (3, 3) })
            {
                var st = Fresh("uh_th" + h); var S = st.Players["south"];
                S.Hand.Clear(); for (int i = 0; i < h; i++) S.Hand.Add(new CardInstance { InstanceId = "h" + i, CardId = "ST01-006", Owner = "south", Zone = "hand" });
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId, Text = "Trash cards from your hand until you have 5 cards in your hand." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                for (int i = 0; i < h && S.Hand.Count > 5; i++) GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "h" + i });
