            var chop = new CardInstance { InstanceId = "C", CardId = "EB02-016", Owner = "south", Zone = "character" };
            Check("Chopperman is [Chopperman] (own)", GameEngine.NameMatches(st, chop, "Chopperman"), true);
            Check("Chopperman treated as [Tony Tony.Chopper]", GameEngine.NameMatches(st, chop, "Tony Tony.Chopper"), true);
            Check("Chopperman NOT [Usopp]", GameEngine.NameMatches(st, chop, "Usopp"), false);
