        // blockerdenialtest — blocker denial: (a) OP11-013 "opponent's Characters with 2000 power or less cannot
        // activate [Blocker]" — a 2000-power Blocker is DENIED, a 4000-power Blocker CAN block; (b) blanket
        // "opponent cannot activate [Blocker] during this battle" — NONE can block; (c) [Unblockable] attacker.
        if (args.Length > 0 && args[0] == "blockerdenialtest")
        {
            bool all = true;
            // Returns whether `blockerId` successfully blocks (becomes the new attack target).
            bool CanBlock(string effectClause, bool unblockableAttacker, string blockerId, string blockerCard)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "bd_" + blockerId + blockerCard + effectClause.Length + unblockableAttacker });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"]; S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "ATK", CardId = "ST01-006", Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
                N.CharacterArea[0] = new CardInstance { InstanceId = blockerId, CardId = blockerCard, Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
                bool battleScoped = effectClause.Contains("during this battle");
                // "during this turn" effects persist and are applied BEFORE the attack; "during this battle" effects
                // need an active battle, so they're applied AFTER declareAttack (mirroring a [When Attacking] effect).
                void ApplyEffect()
                {
                    if (string.IsNullOrEmpty(effectClause)) return;
                    st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId, Text = effectClause });
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                }
                if (!battleScoped) ApplyEffect();
                if (unblockableAttacker) st.ActiveModifiers.Add(new CardModifier { TargetInstanceId = "ATK", ModifierType = "keyword", Keyword = "Unblockable", Duration = "thisTurn" });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "south", Attacker = "ATK", Target = N.Leader.InstanceId });
                if (battleScoped) ApplyEffect();
                GameEngine.ApplyCommand(st, new GameCommand { Type = "blockAttack", Seat = "north", Blocker = blockerId });
                return st.Battle != null && st.Battle.TargetId == blockerId;   // block succeeded?
            }
            void Check(string label, bool got, bool want) { bool ok = got == want; all &= ok; Console.WriteLine($"  {label}: blocked={got} want={want} : {(ok ? "ok" : "FAIL")}"); }
            string op11 = "All of your opponent's Characters with 2000 power or less cannot activate [Blocker] during this turn.";
            Check("OP11-013: 2000-pow Blocker denied", CanBlock(op11, false, "WEAK", "EB01-017"), false);   // EB01-017 = 2000
            Check("OP11-013: 4000-pow Blocker allowed", CanBlock(op11, false, "STRONG", "EB01-006"), true);  // EB01-006 = 4000
            Check("blanket during battle: denied", CanBlock("Your opponent cannot activate [Blocker] during this battle.", false, "STRONG", "EB01-006"), false);
            Check("no effect: Blocker allowed", CanBlock("", false, "STRONG", "EB01-006"), true);
            Check("Unblockable attacker: denied", CanBlock("", true, "STRONG", "EB01-006"), false);
            Console.WriteLine($"=== BLOCKERDENIALTEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // cannotattacktest — "This Character cannot attack unless <cond>": EB04-051 "…unless there is a Character with
        // 12000 base power or more" (Emet, 7000 — needs ANOTHER 12000+ char). Verify the attack is blocked when the
        // condition fails and allowed when it holds. Battle starting (st.Battle != null) = attack allowed.
        if (args.Length > 0 && args[0] == "cannotattacktest")
        {
            bool all = true;
            bool CanAttack(bool withBigChar)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "cna" + withBigChar });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"]; S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "EMET", CardId = "EB04-051", Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 3 };
                if (withBigChar) S.CharacterArea[1] = new CardInstance { InstanceId = "BIG", CardId = "EB04-061", Owner = "south", Zone = "character", PlayedOnTurn = 3 }; // 12000
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "south", Attacker = "EMET", Target = N.Leader.InstanceId });
                return st.Battle != null;   // battle started ⇒ attack allowed
            }
            void Check(string label, bool got, bool want) { bool ok = got == want; all &= ok; Console.WriteLine($"  {label}: attackAllowed={got} want={want} : {(ok ? "ok" : "FAIL")}"); }
            Check("no 12000+ char → blocked", CanAttack(false), false);
            Check("12000+ char present → allowed", CanAttack(true), true);
            // Targeted opp-cannot-attack (untilNextTurn): south locks a north Character; on north's turn it can't
            // attack, and after north's turn the restriction expires.
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "cnaopp" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"]; S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                N.CharacterArea[0] = new CardInstance { InstanceId = "NC", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId,
                    Text = "Up to 1 of your opponent's Characters cannot attack until the end of your opponent's next turn." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "NC" });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "south" });   // → north's turn
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "NC", Target = S.Leader.InstanceId });
                bool blockedOnOppTurn = st.Battle == null;   // attack rejected
                GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "north" });   // → south turn
                GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "south" });   // → north's NEXT turn (restriction expired)
                if (N.CharacterArea[0] != null) N.CharacterArea[0].Rested = false;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "NC", Target = S.Leader.InstanceId });
                bool allowedAfterExpiry = st.Battle != null;
                Check("opp char locked on their turn", blockedOnOppTurn, true);
                Check("restriction expired next cycle", allowedAfterExpiry, true);
            }
            Console.WriteLine($"=== CANNOTATTACKTEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // durationtest — cross-turn durations ("until the end of your opponent's next turn/End Phase") must PERSIST
        // through the opponent's next turn and EXPIRE at the controller's next turn start. Covers +cost (OP08-088),
        // +power, and [Blocker] keyword (must be active DURING the opponent's turn so the char can block).
        if (args.Length > 0 && args[0] == "durationtest")
        {
            bool all = true;
            // Returns (afterApply, duringOpp, afterMyNext) via a reader func on the target character.
            (T, T, T) Cycle<T>(string clause, string chCard, Func<GameState, CardInstance, T> read)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "dur_" + clause.Length });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"]; S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "CH", CardId = chCard, Owner = "south", Zone = "character", PlayedOnTurn = 3 };
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "CH", Text = clause });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "CH" });
                T a = read(st, S.CharacterArea[0]);
                GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "south" });
                T b = read(st, S.CharacterArea[0]);
                GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "north" });
                T c = read(st, S.CharacterArea[0]);
                return (a, b, c);
            }
            void CheckInt(string label, (int, int, int) got, int apply, int during, int after)
            { bool ok = got.Item1 == apply && got.Item2 == during && got.Item3 == after; all &= ok; Console.WriteLine($"  {label}: {got} want=({apply},{during},{after}) : {(ok ? "ok" : "FAIL")}"); }
            void CheckBool(string label, (bool, bool, bool) got, bool apply, bool during, bool after)
            { bool ok = got.Item1 == apply && got.Item2 == during && got.Item3 == after; all &= ok; Console.WriteLine($"  {label}: {got} want=({apply},{during},{after}) : {(ok ? "ok" : "FAIL")}"); }
            // Use a VANILLA character (EB01-005 — no printed keyword) so HasBlocker reflects only the GRANT.
            int baseCost = GameEngine.GetCard(new CardInstance { CardId = "EB01-005" }).Cost;
            CheckInt("+1cost", Cycle("This Character gains +1 cost until the end of your opponent's next turn.", "EB01-005", (st, c) => GameEngine.GetCost(st, c)), baseCost + 1, baseCost + 1, baseCost);
            int basePow = GameEngine.GetCard(new CardInstance { CardId = "EB01-005" }).Power;
            CheckInt("+3000power", Cycle("This Character gains +3000 power until the end of your opponent's next turn.", "EB01-005", (st, c) => GameEngine.GetPower(st, c)), basePow + 3000, basePow + 3000, basePow);
            CheckBool("[Blocker]", Cycle("This Character gains [Blocker] until the end of your opponent's next turn.", "EB01-005", (st, c) => GameEngine.HasBlocker(st, c)), true, true, false);
            CheckBool("[Rush]", Cycle("This Character gains [Rush] until the end of your opponent's next turn.", "EB01-005", (st, c) => GameEngine.HasRush(st, c)), true, true, false);
            Console.WriteLine($"=== DURATIONTEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // donramptest — DON!! ramp/recover: (a) ramp-active adds an ACTIVE DON from the DON deck (DonDeck-1);
        // (b) ramp-rested adds a RESTED DON; (c) ramp is capped by DonDeck (10-DON field cap → DonDeck=0 adds 0);
        // (d) recover "set up to N DON active" un-rests up to N (capped at N and at rested count).
        if (args.Length > 0 && args[0] == "donramptest")
        {
            bool all = true;
            void Check(string label, bool ok) { all &= ok; Console.WriteLine($"  {label}: {(ok ? "ok" : "FAIL")}"); }
            // ramp-active
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "dr1" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.CostArea.Clear(); S.DonDeck = 4;
