                S.Deck.Insert(0, new CardInstance { InstanceId = "PICK", CardId = pickCardId, Owner = "south", Zone = "deck" });
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId, Text = clause });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "deckLookSelect", Seat = "south", Target = "PICK" });
                return S.Hand.Any(c => c.InstanceId == "PICK");
            }
            void Check(string label, bool got, bool want) { bool ok = got == want; all &= ok; Console.WriteLine($"  {label}: added={got} want={want} : {(ok ? "ok" : "FAIL")}"); }
            string shcExclNami = "Look at 5 cards from the top of your deck; reveal up to 1 {Straw Hat Crew} type card other than [Nami] and add it to your hand.";
            Check("excl: SHC Nami rejected", TryAdd(shcExclNami, "EB02-017"), false); // Nami excluded
            Check("tag restored: SHC Sanji ok", TryAdd(shcExclNami, "EB01-014"), true); // SHC non-Nami
            Check("tag enforced: non-SHC rejected", TryAdd(shcExclNami, "EB01-002"), false); // not Straw Hat Crew
            string incl = "Look at 5 cards from the top of your deck; reveal up to 1 [Sabo], [Portgas.D.Ace], or [Monkey.D.Luffy] and add it to your hand.";
            Check("inclusion: named card ok", TryAdd(incl, "EB02-061"), true);   // EB02-061 = Monkey.D.Luffy
            Check("inclusion: non-named rejected", TryAdd(incl, "EB01-014"), false); // Sanji not in the list
            Console.WriteLine($"=== REVEALEXCLTEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // revealcosttest — reveal-add cost filters (#213). "cost of N or more" (EB02-008) and the "cost of N to M"
        // range (EB03-060) were UNPARSED → any-cost card was addable. Verify min + range bounds now reject.
        if (args.Length > 0 && args[0] == "revealcosttest")
        {
            bool all = true;
            // Try to add `pickId` from a look; return whether it landed in hand.
            bool TryAdd(string clause, string pickId, string pickCardId)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "rc_" + pickId + clause.Length });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3;
                S.Deck.Insert(0, new CardInstance { InstanceId = "PICK", CardId = pickCardId, Owner = "south", Zone = "deck" });
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId, Text = clause });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "deckLookSelect", Seat = "south", Target = "PICK" });
                return S.Hand.Any(c => c.InstanceId == "PICK");
            }
            string min4 = "Look at 4 cards from the top of your deck; reveal up to 1 card with a cost of 4 or more and add it to your hand.";
            string range28 = "Look at 4 cards from the top of your deck; reveal up to 1 card with a cost of 2 to 8 and add it to your hand.";
            void Check(string label, bool got, bool want) { bool ok = got == want; all &= ok; Console.WriteLine($"  {label}: added={got} want={want} : {(ok ? "ok" : "FAIL")}"); }
            Check("min4: cost1 rejected", TryAdd(min4, "P", "ST01-006"), false);
            Check("min4: cost8 accepted", TryAdd(min4, "P", "EB02-004"), true);
            Check("range2to8: cost1 rejected(below)", TryAdd(range28, "P", "ST01-006"), false); // cost 1 < 2
            Check("range2to8: cost5 accepted", TryAdd(range28, "P", "EB01-002"), true);         // cost 5 in range
            Check("range2to8: cost10 rejected(above)", TryAdd(range28, "P", "EB02-052"), false); // cost 10 > 8
            Console.WriteLine($"=== REVEALCOSTTEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // totalbufftest — EB02-007: "Up to a total of 3 of your Leader and Character cards gain +1000 power during
        // this turn." Must be up to 3 DISTINCT cards (+1000 each), NOT the same card 3× (+3000). Verifies distinct-
        // target enforcement (re-pick rejected) AND that 3 distinct targets all receive the buff.
        if (args.Length > 0 && args[0] == "totalbufftest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "tbuff" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; S.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
            S.CharacterArea[0] = new CardInstance { InstanceId = "CH", CardId = "ST01-006", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
            int basePow = GameEngine.GetPower(st, S.CharacterArea[0]);
            st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S.Leader.InstanceId,
                Text = "Up to a total of 3 of your Leader and Character cards gain +1000 power during this turn." });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "CH" });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "CH" });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "CH" });
            int finalPow = GameEngine.GetPower(st, S.CharacterArea[0]);
            Console.WriteLine($"  re-pick same 3x: base={basePow} final={finalPow} (correct=+1000={basePow + 1000}; BUG=+3000={basePow + 3000})");
            // Now 3 DISTINCT cards (2 chars + leader) — all three must get +1000.
            var st2 = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "tbuff2" });
            st2.Status = "active"; st2.Phase = "main"; st2.ActiveSeat = "south"; st2.TurnNumber = 6;
            var S2 = st2.Players["south"]; S2.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) S2.CharacterArea[i] = null;
            S2.CharacterArea[0] = new CardInstance { InstanceId = "C0", CardId = "ST01-006", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
            S2.CharacterArea[1] = new CardInstance { InstanceId = "C1", CardId = "ST01-006", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
            int c0b = GameEngine.GetPower(st2, S2.CharacterArea[0]), ldrB = GameEngine.GetPower(st2, S2.Leader);
            st2.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = S2.Leader.InstanceId,
                Text = "Up to a total of 3 of your Leader and Character cards gain +1000 power during this turn." });
            GameEngine.ApplyCommand(st2, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "C0" });
            GameEngine.ApplyCommand(st2, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "C1" });
            GameEngine.ApplyCommand(st2, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = S2.Leader.InstanceId });
            int c0a = GameEngine.GetPower(st2, S2.CharacterArea[0]), c1a = GameEngine.GetPower(st2, S2.CharacterArea[1]), ldrA = GameEngine.GetPower(st2, S2.Leader);
            bool distinctOk = c0a == c0b + 1000 && c1a == c0b + 1000 && ldrA == ldrB + 1000;
            bool repickOk = finalPow == basePow + 1000;
            Console.WriteLine($"  re-pick same 3x: final={finalPow} (want {basePow + 1000}) : {(repickOk ? "ok" : "FAIL")}");
            Console.WriteLine($"  3 distinct: C0={c0a} C1={c1a} Leader={ldrA} (each +1000) : {(distinctOk ? "ok" : "FAIL")}");
            bool pass = repickOk && distinctOk;
            Console.WriteLine($"=== TOTALBUFFTEST === {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // donDistributetest — multi-target rested-DON distribution.
        // OP04-004: "Give up to 1 rested DON!! card to each of your {Alabasta} type Characters" (auto to EACH match).
        // OP08-001: "Give up to 3 of your {Animal} or {Drum Kingdom} type Characters up to 1 rested DON!! card each"
        //           (pick up to 3; 1 each). A non-matching Character must get NONE.
        if (args.Length > 0 && args[0] == "donDistributetest")
        {
            bool all = true;
            // OP04-004 auto-distribute to each Alabasta char (2 Alabasta + 1 non-Alabasta; 3 rested DON available).
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "dd1" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "AL0", CardId = "EB01-004", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
                S.CharacterArea[1] = new CardInstance { InstanceId = "AL1", CardId = "EB02-001", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
                S.CharacterArea[2] = new CardInstance { InstanceId = "NON", CardId = "ST01-006", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
                S.CostArea.Clear();
                for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = "d" + i, Rested = true });
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "AL0",
                    Text = "Give up to 1 rested DON!! card to each of your {Alabasta} type Characters." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                int al0 = S.CharacterArea[0].AttachedDonIds.Count, al1 = S.CharacterArea[1].AttachedDonIds.Count, non = S.CharacterArea[2].AttachedDonIds.Count;
                bool ok = al0 == 1 && al1 == 1 && non == 0;
                all &= ok; Console.WriteLine($"  OP04-004 toEach: AL0={al0}(1) AL1={al1}(1) NON={non}(0) : {(ok ? "ok" : "FAIL")}");
            }
            // OP08-001 pick up to 3; give 1 DON each. Pick AN0 and AN1 (2 of 3), leave a 3rd.
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "dd2" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "AN0", CardId = "EB01-006", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
                S.CharacterArea[1] = new CardInstance { InstanceId = "AN1", CardId = "EB01-018", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
                S.CharacterArea[2] = new CardInstance { InstanceId = "NON", CardId = "ST01-006", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
                S.CostArea.Clear();
                for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = "d" + i, Rested = true });
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "AN0",
                    Text = "Give up to 3 of your {Animal} or {Drum Kingdom} type Characters up to 1 rested DON!! card each." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });   // await picks
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "AN0" });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "AN1" });
                int an0 = S.CharacterArea[0].AttachedDonIds.Count, an1 = S.CharacterArea[1].AttachedDonIds.Count;
                bool nonReject = S.CharacterArea[2].AttachedDonIds.Count == 0;
                bool ok = an0 == 1 && an1 == 1 && nonReject;
                all &= ok; Console.WriteLine($"  OP08-001 pick2: AN0={an0}(1) AN1={an1}(1) NONrejected={nonReject} : {(ok ? "ok" : "FAIL")}");
            }
            Console.WriteLine($"=== DONDISTRIBUTETEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // banishkwtest — [Banish] keyword: (1) OP06-002's self-power-gated grant ("If this Character has 7000 power
        // or more…") reads CURRENT power incl. DON-attach timing; (2) the combat mechanic trashes the Leader's Life
        // card with NO Trigger and NOT to hand.
        if (args.Length > 0 && args[0] == "banishkwtest")
        {
            bool all = true;
            void Run(string label, int don, string activeSeat, bool expect)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "ban_" + label });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = activeSeat; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3; st.Players["north"].TurnsStarted = 3;
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var self = new CardInstance { InstanceId = "SELF", CardId = "OP06-002", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
                for (int i = 0; i < don; i++) self.AttachedDonIds.Add("d" + i);
                S.CharacterArea[0] = self;
                int pow = GameEngine.GetPower(st, self);
                bool has = GameEngine.HasBanish(st, self);
                bool ok = has == expect; all &= ok;
                Console.WriteLine($"  {label}: power={pow} banish={has} expect={expect} : {(ok ? "ok" : "FAIL")}");
            }
            Run("0DON southTurn", 0, "south", false);   // 5000
            Run("2DON southTurn", 2, "south", true);    // 5000+2000=7000
            Run("2DON northTurn", 2, "north", false);   // DON attach adds only on own turn → 5000
            // Combat: a [Banish] attacker hitting the Leader trashes the Life card (no Trigger, not added to hand).
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "bancombat" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                var atk = new CardInstance { InstanceId = "ATK", CardId = "OP06-002", Owner = "south", Zone = "character", PlayedOnTurn = 0 };
                for (int i = 0; i < 3; i++) atk.AttachedDonIds.Add("d" + i);   // 5000+3000=8000, has Banish, beats 5000 leader
                S.CharacterArea[0] = atk;
                N.Life.Clear();
                N.Life.Add(new CardInstance { InstanceId = "LIFE", CardId = "EB01-035", Owner = "north", Zone = "life", FaceUp = false }); // trigger card
                int handBefore = N.Hand.Count, trashBefore = N.Trash.Count;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "south", Attacker = "ATK", Target = N.Leader.InstanceId });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "passBlock", Seat = "north" });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "passCounter", Seat = "north" });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveAttack", Seat = "north" });
                bool inTrash = N.Trash.Any(c => c.InstanceId == "LIFE");
                bool inHand = N.Hand.Any(c => c.InstanceId == "LIFE");
                bool lifeGone = !N.Life.Any(c => c.InstanceId == "LIFE");
                bool ok = inTrash && !inHand && lifeGone; all &= ok;
                Console.WriteLine($"  Banish combat: lifeTrashed={inTrash} lifeToHand={inHand} lifeLeft={!lifeGone} : {(ok ? "ok" : "FAIL")}");
            }
            Console.WriteLine($"=== BANISHKWTEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // opcostdebufftest — continuous "[…] [Your Turn] [If <cond>,] Give all of your opponent's Characters −N cost"
        // auras (GetOpponentCostDebuffAura) must lower the OPPONENT's Character cost, gated on turn / [DON!! xN] /
        // condition. Target = north EB02-004 (base cost 8). Aura sits on SOUTH; applies on south's turn only.
        if (args.Length > 0 && args[0] == "opcostdebufftest")
        {
            bool all = true;
            // (label, auraCardId, activeSeat, donOnAura, extraSetup, expectedCost)
            bool Run(string label, string auraId, string activeSeat, int donOnAura, Action<PlayerState> setup, int expectCost)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "ocd_" + label });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = activeSeat; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                var aura = new CardInstance { InstanceId = "AURA", CardId = auraId, Owner = "south", Zone = "character", PlayedOnTurn = 3 };
                for (int i = 0; i < donOnAura; i++) aura.AttachedDonIds.Add("d" + i);
                S.CharacterArea[0] = aura;
                setup(S);
                N.CharacterArea[0] = new CardInstance { InstanceId = "TGT", CardId = "EB02-004", Owner = "north", Zone = "character", PlayedOnTurn = 3 }; // cost 8
                int cost = GameEngine.GetCost(st, N.CharacterArea[0]);
                bool ok = cost == expectCost;
                Console.WriteLine($"  {label}: oppCharCost={cost} expect={expectCost} : {(ok ? "ok" : "FAIL")}");
                return ok;
            }
            Action<PlayerState> none = S => { };
            Action<PlayerState> minks3 = S => { for (int i = 0; i < 3; i++) S.CharacterArea[i + 1] = new CardInstance { InstanceId = "M" + i, CardId = "EB02-013", Owner = "south", Zone = "character", PlayedOnTurn = 3 }; };
            all &= Run("OP02-121 -5 southTurn", "OP02-121", "south", 0, none, 3);   // 8-5
            all &= Run("OP02-121 -5 northTurn (off)", "OP02-121", "north", 0, none, 8);
            all &= Run("OP03-078 -3 with1DON", "OP03-078", "south", 1, none, 5);   // 8-3
            all &= Run("OP03-078 -3 with0DON (off)", "OP03-078", "south", 0, none, 8);
            all &= Run("EB04-017 -1 with3Minks", "EB04-017", "south", 0, minks3, 7); // 8-1
            all &= Run("EB04-017 -1 with0Minks (off)", "EB04-017", "south", 0, none, 8);
            // OP05-084 -4 "if the only Characters on your field are {Celestial Dragons}" (aura IS a CD → alone = met).
            Action<PlayerState> nonCd = S => { S.CharacterArea[1] = new CardInstance { InstanceId = "NCD", CardId = "ST01-006", Owner = "south", Zone = "character", PlayedOnTurn = 3 }; };
            all &= Run("OP05-084 -4 onlyCD MET", "OP05-084", "south", 0, none, 4);   // 8-4, only CD on board
            all &= Run("OP05-084 -4 non-CD present (off)", "OP05-084", "south", 0, nonCd, 8);
            Console.WriteLine($"=== OPCOSTDEBUFFTEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // op01067test — OP01-067 Sabo: "[DON!! x1] Give blue Events in your hand −1 cost." Continuous aura on OTHER
        // hand cards (blue Events). GetCost must apply −1 while OP01-067 holds 1 DON, gate off with 0 DON, and NOT
        // touch a Character (type filter = Events).
        if (args.Length > 0 && args[0] == "op01067test")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op01067" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; S.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
            var sabo = new CardInstance { InstanceId = "SABO", CardId = "OP01-067", Owner = "south", Zone = "character", PlayedOnTurn = 3 };
            S.CharacterArea[0] = sabo;
            var ev = new CardInstance { InstanceId = "EV", CardId = "EB02-030", Owner = "south", Zone = "hand" }; // blue Event
            var ch = new CardInstance { InstanceId = "CH", CardId = "ST01-006", Owner = "south", Zone = "hand" }; // a Character (must not be reduced)
            S.Hand.Clear(); S.Hand.Add(ev); S.Hand.Add(ch);
            int evBase = GameEngine.GetCard(ev).Cost, chBase = GameEngine.GetCard(ch).Cost;
            int evNoDon = GameEngine.GetCost(st, ev);
            sabo.AttachedDonIds.Add("d0");
            int evWith = GameEngine.GetCost(st, ev);
            int chWith = GameEngine.GetCost(st, ch);
            bool pass = evNoDon == evBase && evWith == evBase - 1 && chWith == chBase;
            Console.WriteLine($"=== OP01067TEST === evNoDon={evNoDon}(={evBase}) evWith1Don={evWith}(={evBase - 1}) charUnchanged={chWith}(={chBase}) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // kwcondtest — conditional CONTINUOUS keyword grants ("If <cond>, this Character gains [KW]") must gate on
        // the condition (HasPrintedKeywordGrant evaluates the leading "If <cond>,"). Covers count conditions
        // (hand/DON/trash/Life), a power-threshold board existence (OP05-003), and a {type}-existence with an
        // "other than this card" SELF-EXCLUSION (OP13-009 is itself {Mountain Bandits} → alone must NOT qualify).
        if (args.Length > 0 && args[0] == "kwcondtest")
        {
            bool all = true;
            bool Run(string label, string cardId, string kw, Action<GameState, PlayerState> setup, bool expect)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "kw_" + label });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var self = new CardInstance { InstanceId = "SELF", CardId = cardId, Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 3 };
                S.CharacterArea[0] = self;
                setup(st, S);
                bool has = kw == "Blocker" ? GameEngine.HasBlocker(st, self)
                         : kw == "Rush"   ? GameEngine.HasRush(st, self)
                         : GameEngine.HasDoubleAttack(st, self);
                bool ok = has == expect;
                Console.WriteLine($"  {label} ({cardId} [{kw}]): has={has} expect={expect} : {(ok ? "ok" : "FAIL")}");
                return ok;
            }
            Action<GameState, PlayerState> hand(int n) => (st, S) => { S.Hand.Clear(); for (int i = 0; i < n; i++) S.Hand.Add(new CardInstance { InstanceId = "h" + i, CardId = "ST01-006", Owner = "south", Zone = "hand" }); };
            Action<GameState, PlayerState> don(int n) => (st, S) => { S.CostArea.Clear(); for (int i = 0; i < n; i++) S.CostArea.Add(new DonInstance { InstanceId = "d" + i }); };
            Action<GameState, PlayerState> trash(int n) => (st, S) => { S.Trash.Clear(); for (int i = 0; i < n; i++) S.Trash.Add(new CardInstance { InstanceId = "t" + i, CardId = "ST01-006", Owner = "south", Zone = "trash" }); };
            Action<GameState, PlayerState> life(int n) => (st, S) => { S.Life.Clear(); for (int i = 0; i < n; i++) S.Life.Add(new CardInstance { InstanceId = "l" + i, CardId = "ST01-006", Owner = "south", Zone = "life" }); };
            Action<GameState, PlayerState> secondChar(string cid) => (st, S) => { S.CharacterArea[1] = new CardInstance { InstanceId = "OTHER", CardId = cid, Owner = "south", Zone = "character", PlayedOnTurn = 3 }; };
            all &= Run("OP06-054 hand<=5 UNMET", "OP06-054", "Blocker", hand(8), false);
            all &= Run("OP06-054 hand<=5 MET",   "OP06-054", "Blocker", hand(3), true);
            all &= Run("OP15-119 DON>=6 UNMET",  "OP15-119", "Rush",    don(4),  false);
            all &= Run("OP15-119 DON>=6 MET",    "OP15-119", "Rush",    don(7),  true);
            all &= Run("OP05-086 trash>=10 UNMET", "OP05-086", "Blocker", trash(5),  false);
            all &= Run("OP05-086 trash>=10 MET",   "OP05-086", "Blocker", trash(12), true);
            all &= Run("OP12-107 Life<=2 UNMET", "OP12-107", "Rush", life(4), false);
            all &= Run("OP12-107 Life<=2 MET",   "OP12-107", "Rush", life(1), true);
            all &= Run("OP05-003 no-other-7000 UNMET", "OP05-003", "Rush", (st, S) => { }, false);
            all &= Run("OP05-003 other-7000 MET", "OP05-003", "Rush", secondChar("EB01-002"), true);   // EB01-002 = 7000
            all &= Run("OP13-009 self-only UNMET", "OP13-009", "DoubleAttack", (st, S) => { }, false);  // itself {Mountain Bandits}, no OTHER
            all &= Run("OP13-009 other-MB MET", "OP13-009", "DoubleAttack", secondChar("OP02-005"), true); // OP02-005 = another {Mountain Bandits}
            Console.WriteLine($"=== KWCONDTEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // eotcondtest — [End of Your Turn] "If <cond>, set this Character/Leader as active" must gate on the condition
        // (was fast-pathed UNCONDITIONALLY). Covers a rested-Characters count (OP09-031), an active-DON count
        // (OP04-028), a leader hand-size gate (OP05-022), and an unconditional control (OP04-027). Also asserts the
        // choice/cost variants (OP13-035, OP16-073) still self-recover (no stall/regression).
        if (args.Length > 0 && args[0] == "eotcondtest")
        {
            bool all = true;
            // Character self-recover: cardId in char slot; extraRestedChars decoys; activeDon controls DON conditions.
            bool RunChar(string label, string cardId, int extraRestedChars, int activeDon, bool expectActive)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "eot_" + label });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "SELF", CardId = cardId, Owner = "south", Zone = "character", Rested = true, PlayedOnTurn = 3 };
                S.CharacterArea[0].AttachedDonIds.Add("d0");   // satisfy any [DON!! x1] gate
                for (int i = 0; i < extraRestedChars; i++)
                    S.CharacterArea[i + 1] = new CardInstance { InstanceId = "R" + i, CardId = "ST01-006", Owner = "south", Zone = "character", Rested = true, PlayedOnTurn = 3 };
                S.CostArea.Clear();
                for (int i = 0; i < activeDon; i++) S.CostArea.Add(new DonInstance { InstanceId = "cd" + i, Rested = false });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "south" });
                var self = S.CharacterArea.FirstOrDefault(c => c != null && c.InstanceId == "SELF");
                bool active = self != null && !self.Rested;
                int pending = st.PendingEffects.Count(e => e.Seat == "south");
                bool ok = active == expectActive && pending == 0;
                Console.WriteLine($"  {label} ({cardId}): active={active} expect={expectActive} pending={pending} : {(ok ? "ok" : "FAIL")}");
                return ok;
            }
            all &= RunChar("OP09-031 rested<2 UNMET", "OP09-031", 0, 3, false);
            all &= RunChar("OP09-031 rested>=2 MET",  "OP09-031", 2, 3, true);
            all &= RunChar("OP04-028 activeDON<2 UNMET", "OP04-028", 0, 1, false);
            all &= RunChar("OP04-028 activeDON>=2 MET",  "OP04-028", 0, 4, true);
            all &= RunChar("OP04-027 unconditional", "OP04-027", 0, 3, true);
            all &= RunChar("OP13-035 choice self-recover", "OP13-035", 0, 3, true);
            // OP16-073 is now #222: its "DON!! −2:" cost is paid via the full resolver (see op16073test), no longer a
            // free fast-path self-recover. With activeDon=1 (+1 attached from RunChar = 2 field DON) the DON!! −2
            // auto-pays exactly, so it still ends active with no pending.
            all &= RunChar("OP16-073 pays DON!! −2 then recovers", "OP16-073", 0, 1, true);
            // Leader self-recover (OP05-022 "If you have 6 or less cards in your hand, set this Leader as active").
            bool RunLeader(string label, int handN, bool expectActive)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "eotL_" + label });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; S.TurnsStarted = 3;
                S.Leader = new CardInstance { InstanceId = "LDR", CardId = "OP05-022", Owner = "south", Zone = "leader", Rested = true };
                S.Hand.Clear();
                for (int i = 0; i < handN; i++) S.Hand.Add(new CardInstance { InstanceId = "h" + i, CardId = "ST01-006", Owner = "south", Zone = "hand" });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "south" });
                bool active = S.Leader != null && !S.Leader.Rested;
                bool ok = active == expectActive;
                Console.WriteLine($"  {label} (OP05-022 leader, hand={handN}): active={active} expect={expectActive} : {(ok ? "ok" : "FAIL")}");
                return ok;
            }
            all &= RunLeader("hand>6 UNMET", 8, false);
            all &= RunLeader("hand<=6 MET", 4, true);
            Console.WriteLine($"=== EOTCONDTEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // drawcond2test — #210 must gate EVERY trailing-"Draw N if <cond>" condition TYPE (else EvaluateCondition
        // fails to recognize it and the draw fires anyway). Covers OP01-095 (DON count), OP05-118 (opp Life),
        // OP05-009 (leader power) beyond drawcondtest's hand-size cases.
        if (args.Length > 0 && args[0] == "drawcond2test")
        {
            bool all = true;
            bool Run(string label, string clause, Action<GameState> setup, int drawN)
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "dc2_" + label });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                S.Hand.Clear();
                setup(st);
                int before = S.Hand.Count;
                st.PendingEffects.Add(new PendingEffect { EffectId = "D", Seat = "south", SourceInstanceId = S.Leader.InstanceId, Text = clause });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "D", Target = null });
                int drew = S.Hand.Count - before;
                bool ok = drew == drawN;
                Console.WriteLine($"  {label}: drew={drew} (expect {drawN}) : {(ok ? "ok" : "FAIL")}");
                return ok;
            }
            all &= Run("DON>=8 met",  "Draw 1 card if you have 8 or more DON!! cards on your field.",
                st => { var S = st.Players["south"]; S.CostArea.Clear(); for (int i = 0; i < 8; i++) S.CostArea.Add(new DonInstance { InstanceId = "d" + i }); }, 1);
            all &= Run("DON>=8 unmet", "Draw 1 card if you have 8 or more DON!! cards on your field.",
                st => { var S = st.Players["south"]; S.CostArea.Clear(); for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = "d" + i }); }, 0);
            all &= Run("oppLife<=3 met",  "Draw 1 card if your opponent has 3 or less Life cards.",
                st => { var N = st.Players["north"]; N.Life.Clear(); for (int i = 0; i < 2; i++) N.Life.Add(new CardInstance { InstanceId = "nl" + i, CardId = "ST01-006", Owner = "north", Zone = "life" }); }, 1);
            all &= Run("oppLife<=3 unmet", "Draw 1 card if your opponent has 3 or less Life cards.",
                st => { var N = st.Players["north"]; N.Life.Clear(); for (int i = 0; i < 5; i++) N.Life.Add(new CardInstance { InstanceId = "nl" + i, CardId = "ST01-006", Owner = "north", Zone = "life" }); }, 0);
            all &= Run("leaderPow<=0 unmet", "Draw 1 card if your Leader has 0 power or less.", st => { }, 0);
            Console.WriteLine($"=== DRAWCOND2TEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // drawcondtest — trailing "Draw N card(s) if <condition>" must be GATED (was drawn unconditionally, #210).
        // OP05-047 [On Block] "Draw 1 card if you have 3 or less cards in your hand. Then, +1000 during this battle."
        // and OP01-078 [When Attacking]/[On Block] "Draw 1 card if you have 5 or less cards in your hand." The draw
        // fires only when the hand-size condition holds; the ". Then," +1000 buff must fire in BOTH cases (OP05-047).
        if (args.Length > 0 && args[0] == "drawcondtest")
        {
            bool all = true;
            // (cardId, handSizeThatMeets, handSizeThatFails, expectBuffPower or -1 if no buff clause)
            var cases = new[] { ("OP05-047", 2, 6, 6000), ("OP01-078", 4, 6, -1) };
            foreach (var (cid, metHand, failHand, buffPow) in cases)
            {
                foreach (var (handN, shouldDraw) in new[] { (metHand, true), (failHand, false) })
                {
                    var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = $"dc_{cid}_{handN}" });
                    st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                    var S = st.Players["south"]; var N = st.Players["north"];
                    S.TurnsStarted = 3; N.TurnsStarted = 3;
                    for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                    N.CharacterArea[0] = new CardInstance { InstanceId = "ATK", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
                    S.CharacterArea[0] = new CardInstance { InstanceId = "BLK", CardId = cid, Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 3 };
                    for (int k = 0; k < 2; k++) S.CharacterArea[0].AttachedDonIds.Add("d" + k);   // satisfy any [DON!! xN] gate (OP01-078)
                    S.Hand.Clear();
                    for (int i = 0; i < handN; i++) S.Hand.Add(new CardInstance { InstanceId = "h" + i, CardId = "ST01-006", Owner = "south", Zone = "hand" });
                    int handBefore = S.Hand.Count;
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "ATK", Target = S.Leader.InstanceId });
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "blockAttack", Seat = "south", Blocker = "BLK" });
                    var react = st.PendingEffects.FirstOrDefault(e => e.Seat == "south" && e.Timing == "onBlock");
                    if (react != null) GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = react.EffectId, Target = null });
                    int drew = S.Hand.Count - handBefore;
                    bool drawOk = drew == (shouldDraw ? 1 : 0);
                    bool buffOk = buffPow < 0 || GameEngine.GetPower(st, S.CharacterArea[0]) == buffPow;
                    all &= drawOk && buffOk;
                    Console.WriteLine($"  {cid} hand={handN}: drew={drew}(want {(shouldDraw ? 1 : 0)}) buffOk={buffOk} : {(drawOk && buffOk ? "ok" : "FAIL")}");
                }
            }
            Console.WriteLine($"=== DRAWCONDTEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // onblock2probe — OP06-009 has a COMBINED "[When Attacking]/[On Block]" tag: "This Character's base power
        // becomes the same as your opponent's Leader until the start of your next turn." Verify the [On Block] path
        // recognizes the slash-combined tag and sets the blocker's power to the opponent Leader's.
        if (args.Length > 0 && args[0] == "onblock2probe")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "onblk2" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            N.CharacterArea[0] = new CardInstance { InstanceId = "ATK", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            S.CharacterArea[0] = new CardInstance { InstanceId = "BLK", CardId = "OP06-009", Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 3 };
            int leaderPow = GameEngine.GetPower(st, N.Leader);
            int before = GameEngine.GetPower(st, S.CharacterArea[0]);
            GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "ATK", Target = S.Leader.InstanceId });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "blockAttack", Seat = "south", Blocker = "BLK" });
            var react = st.PendingEffects.FirstOrDefault(e => e.Seat == "south" && e.Timing == "onBlock");
            if (react != null) GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = react.EffectId, Target = null });
            int after = GameEngine.GetPower(st, S.CharacterArea[0]);
            Console.WriteLine($"OP06-009: blkBefore={before} oppLeaderPow={leaderPow} blkAfter={after} reactQueued={react != null} (after should == oppLeaderPow)");
            return 0;
        }
        // onblocktest — [On Block] must FIRE + RESOLVE when a Blocker blocks. OP05-036: "[Blocker]\n[On Block] Rest
        // up to 1 of your opponent's Characters with a cost of 4 or less." After south blocks a north attack, south
        // should get to rest a north Character (cost ≤ 4).
        if (args.Length > 0 && args[0] == "onblocktest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "onblk" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            N.CharacterArea[0] = new CardInstance { InstanceId = "ATK", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            N.CharacterArea[1] = new CardInstance { InstanceId = "TARGET", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            S.CharacterArea[0] = new CardInstance { InstanceId = "BLK", CardId = "OP05-036", Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 3 };
            GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "ATK", Target = S.Leader.InstanceId });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "blockAttack", Seat = "south", Blocker = "BLK" });
            var react = st.PendingEffects.FirstOrDefault(e => e.Seat == "south" && e.Timing == "onBlock");
            bool reactQueued = react != null;
            if (react != null)
            {
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = react.EffectId, Target = null });
                var r2 = st.PendingEffects.FirstOrDefault(e => e.Seat == "south" && e.Timing == "onBlock");
                if (r2 != null) GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = r2.EffectId, Target = "TARGET" });
            }
            bool targetRested = N.CharacterArea[1] != null && N.CharacterArea[1].Rested;
            bool pass = reactQueued && targetRested;
            Console.WriteLine($"=== ONBLOCKTEST === reactQueued={reactQueued}(T) oppCharRested={targetRested}(T) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // oppattackrestest — [On Your Opponent's Attack] must not just QUEUE (the L812 probe checks that) but fully
        // RESOLVE. OP09-032: "[On Your Opponent's Attack] [Once Per Turn] Set this Character as active." A rested
        // OP09-032 on the defender's board should become active after the opponent declares an attack.
        if (args.Length > 0 && args[0] == "oppattackrestest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "oppatk" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            // North attacker: active, not summoning-sick.
            N.CharacterArea[0] = new CardInstance { InstanceId = "ATK", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            // South defender's OP09-032, rested.
            S.CharacterArea[0] = new CardInstance { InstanceId = "SELF", CardId = "OP09-032", Owner = "south", Zone = "character", Rested = true, PlayedOnTurn = 3 };
            GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "ATK", Target = S.Leader.InstanceId });
            var react = st.PendingEffects.FirstOrDefault(e => e.Seat == "south" && e.Timing == "onOpponentsAttack");
            bool reactQueued = react != null;
            if (react != null)
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = react.EffectId, Target = null });
            bool selfActive = S.CharacterArea[0] != null && !S.CharacterArea[0].Rested;
            bool pass = reactQueued && selfActive;
            Console.WriteLine($"=== OPPATTACKRESTEST === reactQueued={reactQueued}(T) selfBecameActive={selfActive}(T) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // auracondtest — conditional CONTINUOUS group auras must toggle with their live condition.
        // EB01-024 Hamlet ({SMILE}): "If you have 4 or less cards in your hand, all of your {SMILE} type Characters
        // gain +1000 power." OP13-004 Sabo Leader: "[DON!! x1] If you have a Character with a cost of 8 or more, your
        // Leader and all of your Characters gain +1000 power."
        if (args.Length > 0 && args[0] == "auracondtest")
        {
            bool all = true;
            // EB01-024: hand<=4 → +1000; hand>4 → +0.
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "aura1" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "HAM", CardId = "EB01-024", Owner = "south", Zone = "character" };
                S.Hand.Clear();
                for (int i = 0; i < 3; i++) S.Hand.Add(new CardInstance { InstanceId = "h" + i, CardId = "ST01-006", Owner = "south", Zone = "hand" });
                int pOn = GameEngine.GetPower(st, S.CharacterArea[0]);          // hand=3 → aura ON → 5000
                for (int i = 0; i < 4; i++) S.Hand.Add(new CardInstance { InstanceId = "x" + i, CardId = "ST01-006", Owner = "south", Zone = "hand" }); // hand=7
                int pOff = GameEngine.GetPower(st, S.CharacterArea[0]);         // hand=7 → aura OFF → 4000
                bool ok = pOn == 5000 && pOff == 4000;
                all &= ok; Console.WriteLine($"  EB01-024: handLE4={pOn}(5000) handGT4={pOff}(4000) ok={ok}");
            }
            // OP13-004: DON!!x1 on Leader + a cost-8+ Character → Leader +1000 and that Character +1000; remove either → +0.
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "aura2" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.Leader = new CardInstance { InstanceId = "SABO", CardId = "OP13-004", Owner = "south", Zone = "leader" };
                S.Leader.AttachedDonIds.Add("don1");   // [DON!! x1]
                S.CharacterArea[0] = new CardInstance { InstanceId = "BIG", CardId = "EB02-004", Owner = "south", Zone = "character" }; // cost 8+
                int bigBase = GameEngine.GetPower(st, S.CharacterArea[0]);
                int sabo0 = GameEngine.GetPower(st, S.Leader);
                // Now remove the cost-8+ character → condition fails → no bonus.
                var savedBig = S.CharacterArea[0]; S.CharacterArea[0] = null;
                int sabo1 = GameEngine.GetPower(st, S.Leader);
                bool ok = sabo0 == sabo1 + 1000;   // aura on with BIG present, off without
                all &= ok; Console.WriteLine($"  OP13-004: leaderWithCost8={sabo0} leaderWithout={sabo1} bigGotBonus={bigBase} ok={ok}");
            }
            // OP12-102: "[Opponent's Turn] If you have no other [Shirahoshi] with a base cost of 2, all of your
            // {Neptunian} type Characters gain +2000 power." Negative-existence "other [Name]" condition must flip
            // the aura off once a SECOND cost-2 Shirahoshi is present.
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "aura3" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;   // south's opponent's turn
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "OP12-102", Owner = "south", Zone = "character" }; // cost-2 Shirahoshi aura source
                S.CharacterArea[1] = new CardInstance { InstanceId = "NEP", CardId = "OP11-026", Owner = "south", Zone = "character" }; // Neptunian recipient (8000)
                int on = GameEngine.GetPower(st, S.CharacterArea[1]);      // no OTHER cost-2 Shirahoshi → +2000 → 10000
                S.CharacterArea[2] = new CardInstance { InstanceId = "SH2", CardId = "EB01-057", Owner = "south", Zone = "character" }; // 2nd cost-2 Shirahoshi
                int off = GameEngine.GetPower(st, S.CharacterArea[1]);     // now an OTHER cost-2 Shirahoshi exists → +0 → 8000
                bool ok = on == 10000 && off == 8000;
                all &= ok; Console.WriteLine($"  OP12-102: noOtherShira={on}(10000) withOtherShira={off}(8000) ok={ok}");
            }
            Console.WriteLine($"=== AURACONDTEST === {(all ? "PASS" : "FAIL")}");
            return all ? 0 : 1;
        }
        // op16024test — OP16-024 Inazuma: "When this Character is K.O.'d by your opponent's effect, rest up to 1 of
        // your opponent's Characters." Reactive payoff must FIRE on an effect-KO (not battle) and let the owner rest
        // an opponent Character. Verifies the on-KO dispatch (FireOnKoEffects) + the payoff body isn't a silent no-op.
        if (args.Length > 0 && args[0] == "op16024test")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op16024" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;   // opponent's (north's) turn — north KOs south's card
            var S = st.Players["south"]; var N = st.Players["north"];
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            S.CharacterArea[0] = new CardInstance { InstanceId = "VICT", CardId = "OP16-024", Owner = "south", Zone = "character", Rested = false };
            N.CharacterArea[0] = new CardInstance { InstanceId = "NC", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false };
            // North resolves an effect that K.O.s south's OP16-024 (an EFFECT K.O., not battle).
            st.PendingEffects.Add(new PendingEffect { EffectId = "KOE", Seat = "north", SourceInstanceId = "NC",
                Text = "K.O. up to 1 of your opponent's Characters." });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = "KOE", Target = "VICT" });
            bool victKoed = S.CharacterArea[0] == null || S.CharacterArea[0].InstanceId != "VICT";
            var react = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
            bool reactQueued = react != null;
            if (react != null)
            {
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = react.EffectId, Target = null });
