            st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "SRC",
                Text = "If your Leader's type includes \"Whitebeard Pirates\", reveal 1 card from the top of your deck. If that card is a Character card with a type including \"Whitebeard Pirates\" and a cost of 9 or less, you may play that card. If you do, that Character gains [Rush] during this turn." });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
            var playDecision = st.PendingEffects.FirstOrDefault(e => (e.Text ?? "").Contains("play the revealed card"));
