            if (playDecision != null) GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = playDecision.EffectId, Target = null });
            var played = S.CharacterArea.FirstOrDefault(c => c != null && c.InstanceId == "TOP");
            bool inPlay = played != null;
