        // buffed char). Buff applies (+6000), the SELECTED own char is frozen, it STAYS rested through the owner's
        // next Refresh, then refreshes normally the turn after.
        if (args.Length > 0 && args[0] == "eb02021test")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "eb02021" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"];
            for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
            var tgt = new CardInstance { InstanceId = "TGT", CardId = "ST01-006", Owner = "south", Zone = "character" }; // Straw Hat, base 1000
            S.CharacterArea[0] = tgt;
            st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "TGT",
                Text = "Up to 1 of your {Straw Hat Crew} type Characters gains +6000 power during this turn. Then, the selected Character will not become active in your next Refresh Phase." });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "TGT" });
            int pow = GameEngine.GetPower(st, tgt);
            bool notStalled = !st.PendingEffects.Any(e => (e.Text ?? "").Contains("will not become active"));
            // simulate: the char attacked (rests), then the owner's NEXT Refresh Phase
            tgt.Rested = true;
            var miStart = typeof(GameEngine).GetMethod("ApplyStartOfTurn", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static);
            st.ActiveSeat = "south";
            miStart.Invoke(null, new object[] { st }); // south's next refresh — freeze holds
            bool stayedRested = tgt.Rested;
            // the refresh AFTER — freeze expired, un-rests normally
            tgt.Rested = true;
            st.ActiveSeat = "south";
            miStart.Invoke(null, new object[] { st });
            bool refreshedLater = !tgt.Rested;
            bool pass = pow == 7000 && notStalled && stayedRested && refreshedLater;
            Console.WriteLine($"=== EB02021TEST === power={pow}(7000) notStalled={notStalled}(T) stayedRestedThisRefresh={stayedRested}(T) refreshedNextTime={refreshedLater}(T) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
