        {
            System.Func<int, int> run = (int lifeCount) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op01029_" + lifeCount });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6; // opponent's turn (Counter)
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var tgt = new CardInstance { InstanceId = "TGT", CardId = "ST01-006", Owner = "south", Zone = "character" }; // base 1000
                S.CharacterArea[0] = tgt;
                S.Life.Clear();
                for (int i = 0; i < lifeCount; i++) S.Life.Add(new CardInstance { InstanceId = "L" + i, CardId = "ST01-006", Owner = "south", Zone = "life" });
                st.Battle = new BattleState { Id = "b", AttackerId = st.Players["north"].Leader.InstanceId, TargetId = "TGT", Step = "counter", AttackerSeat = "north", TargetSeat = "south" };
                st.PendingEffects.Add(new PendingEffect { EffectId = "C", Seat = "south", SourceInstanceId = "TGT",
                    Text = "Up to 1 of your Leader or Character cards gains +2000 power during this battle. Then, if you have 2 or less Life cards, that card gains an additional +3000 power during this battle." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "C", Target = "TGT" });
                return GameEngine.GetPower(st, tgt);
            };
            int met = run(1);   // Life 1 (≤2): 1000 + 2000 + 3000 (additional) = 6000
            int notMet = run(4); // Life 4 (>2): 1000 + 2000 = 3000
            bool pass = met == 6000 && notMet == 3000;
            Console.WriteLine($"=== OP01029TEST === condMet(life1)={met}(6000, +2000+3000)   condNotMet(life4)={notMet}(3000, +2000 only) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
