        // restrict2test — the last two self-restriction no-ops: OP02-004 "cannot add Life cards to your hand using
        // your own effects" (blocks own Life-to-hand effect bodies) and EB04-016 "cannot set DON!! cards as active
        // using Character effects" (blocks CHARACTER-sourced DON-set-active). Both were no-ops.
        if (args.Length > 0 && args[0] == "restrict2test")
        {
