                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op02004" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "OP02-004", Owner = "south", Zone = "character" };
                int lifeBefore = S.Life.Count, handBefore = S.Hand.Count;
                // set the restriction
                st.PendingEffects.Add(new PendingEffect { EffectId = "R", Seat = "south", SourceInstanceId = "SRC",
                    Text = "You cannot add Life cards to your hand using your own effects during this turn." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "R", Target = null });
                bool flagSet = st.NoAddLifeToHandThisTurn.Contains("south");
