                    Text = "Add 1 card from the top of your Life cards to your hand." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "A", Target = null });
                bool lifeUnchanged = S.Life.Count == lifeBefore && S.Hand.Count == handBefore;
                lifePass = flagSet && lifeUnchanged;
            }
