                S.CostArea.Clear();
                for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = "sd" + i, Rested = true }); // 3 rested DON
                // set the restriction (source = a Character card)
                st.PendingEffects.Add(new PendingEffect { EffectId = "R", Seat = "south", SourceInstanceId = "C1", SourceCardId = "EB04-016",
                    Text = "You cannot set DON!! cards as active using Character effects during this turn." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "R", Target = null });
                bool flagSet = st.NoSetDonActiveViaCharThisTurn.Contains("south");
                // a CHARACTER effect tries to set a DON active → blocked (DON stays rested)
                st.PendingEffects.Add(new PendingEffect { EffectId = "D", Seat = "south", SourceInstanceId = "C2", SourceCardId = "EB04-016",
                    Text = "Set up to 1 of your DON!! cards as active." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "D", Target = null });
                bool donStillRestedFromChar = S.CostArea.All(d => d.Rested);
                // an EVENT effect setting DON active is NOT restricted (source type = event)
                st.PendingEffects.Add(new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "EV", SourceCardId = "EB01-009",
                    Text = "Set up to 1 of your DON!! cards as active." });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                bool eventSetActive = S.CostArea.Any(d => !d.Rested); // event was allowed to set 1 active
                donPass = flagSet && donStillRestedFromChar && eventSetActive;
