            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "R", Target = null });
            // try to play the big (cost 8) → blocked; small (cost 2) → allowed
            GameEngine.ApplyCommand(st, new GameCommand { Type = "playCard", Seat = "south", InstanceId = "BIG", SlotIndex = 1 });
            bool bigBlocked = S.Hand.Any(c => c.InstanceId == "BIG");
