            var miStart = typeof(GameEngine).GetMethod("ApplyStartOfTurn", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static);
            if (miStart != null) miStart.Invoke(null, new object[] { st });
