                "give this Character up to 2 rested DON!! cards",
                "at the end of this turn, return DON!! cards from your field to your DON!! deck until you have the same number of DON!! cards on your field as your opponent",
                "the selected Character will not become active in your next Refresh Phase",
                "this Character will not become active in your next Refresh Phase",
                "trash all cards from your hand",
                "trash the same number of cards from your hand",
                "trash this Character at the end of this turn",
                "trash this Stage",
                "set up to 1 of your Characters with a cost of 5 or less as active",
                "set up to 1 of your purple Stages as active",
                "set up to 1 of your {Fish-Man} type Characters as active",
                "give up to 4 rested DON!! cards to 1 of your Characters",
                "negate the effect of up to 1 of your opponent's Characters",
                "place 1 card from your hand at the bottom of your deck",
                "trash 1 of your {FILM} type Characters at the end of this turn",
                "this Leader cannot attack your opponent's Characters with a base cost of 7 or more",
            };
            Console.WriteLine("  -- batch 3 --");
            int stall3 = 0;
            foreach (var b in bodies3) { bool g = gated(b); if (!g) stall3++; Console.WriteLine($"  [{(g ? "gated" : "STALL")}] {b}"); }
            Console.WriteLine($"  batch3 stalls: {stall3}");
            return 0;
        }
        // setpowertest — "base power becomes N" overrides the base, then attached DON / buffs STACK on top; "Set
        // the power of up to 1 opponent Character to 0" sets it to 0; "becomes the same as opponent's Leader"
        // snapshots the opponent Leader's current power.
        if (args.Length > 0 && args[0] == "setpowertest")
        {
            // (1) base set 7000 + 2 attached DON (owner turn) → 9000
            int stacked;
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "setpow1" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var ch = new CardInstance { InstanceId = "CH", CardId = "ST01-006", Owner = "south", Zone = "character" }; // base 1000
                ch.AttachedDonIds.Add("d1"); ch.AttachedDonIds.Add("d2");
                S.CharacterArea[0] = ch;
                var eff = new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "CH", Text = "This Character's base power becomes 7000 during this turn." };
                st.PendingEffects.Add(eff);
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                stacked = GameEngine.GetPower(st, ch); // 7000 + 2000 DON
            }
            // (2) set opponent power to 0
            int oppZero;
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "setpow2" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) N.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-002", Owner = "south", Zone = "character" };
                var v = new CardInstance { InstanceId = "V", CardId = "OP11-017", Owner = "north", Zone = "character" }; // 7000
                N.CharacterArea[0] = v;
                var eff = new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "SRC", Text = "Set the power of up to 1 of your opponent's Characters to 0 during this turn." };
                st.PendingEffects.Add(eff);
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = "V" });
                oppZero = GameEngine.GetPower(st, v);
            }
            // (3) becomes same as opponent's Leader (5000)
            int mirror;
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "setpow3" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var ch = new CardInstance { InstanceId = "CH", CardId = "ST01-006", Owner = "south", Zone = "character" }; // base 1000
                S.CharacterArea[0] = ch;
                st.Battle = new BattleState { Id = "b", AttackerId = "CH", TargetId = st.Players["north"].Leader.InstanceId, Step = "counter", AttackerSeat = "south", TargetSeat = "north" };
                var eff = new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "CH", Text = "This Character's base power becomes the same as your opponent's Leader during this battle." };
                st.PendingEffects.Add(eff);
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "E", Target = null });
                mirror = GameEngine.GetPower(st, ch);
            }
            bool pass = stacked == 9000 && oppZero == 0 && mirror == 5000;
            Console.WriteLine($"=== SETPOWERTEST === base7000+2DON={stacked}(9000)   set-opp-to-0={oppZero}(0)   mirror-oppLeader={mirror}(5000) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // oppturnbufftest — EB04-007-style "Your Leader gains +2000 power until the end of your opponent's next
        // End Phase." The buff must PERSIST through the opponent's whole turn, then expire by the giver's next turn.
        if (args.Length > 0 && args[0] == "oppturnbufftest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "oppbuff" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
            S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-002", Owner = "south", Zone = "character" };
            int basePw = GameEngine.GetPower(st, S.Leader);
            var eff = new PendingEffect { EffectId = "B", Seat = "south", SourceInstanceId = "SRC",
                Text = "Your Leader gains +2000 power until the end of your opponent's next End Phase." };
            st.PendingEffects.Add(eff);
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "B", Target = null });
            int onGive = GameEngine.GetPower(st, S.Leader);              // south turn: base+2000
            GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "south" }); // → north's turn
            int onOppTurn = GameEngine.GetPower(st, S.Leader);          // north turn: STILL base+2000
            GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "north" }); // → south's next turn
            int afterOppTurn = GameEngine.GetPower(st, S.Leader);       // expired: base
            bool powerOk = onGive == basePw + 2000 && onOppTurn == basePw + 2000 && afterOppTurn == basePw;
            // Cost-grant variant (OP08-088 "gains +1 cost until the end of your opponent's next turn").
            var st2 = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "oppbuffcost" });
            st2.Status = "active"; st2.Phase = "main"; st2.ActiveSeat = "south"; st2.TurnNumber = 6;
            var S2 = st2.Players["south"]; S2.TurnsStarted = 3; st2.Players["north"].TurnsStarted = 3;
            for (int i = 0; i < 5; i++) S2.CharacterArea[i] = null;
            var ch = new CardInstance { InstanceId = "CH", CardId = "ST01-006", Owner = "south", Zone = "character" }; // base cost 1
            S2.CharacterArea[0] = ch;
            S2.CharacterArea[1] = new CardInstance { InstanceId = "SRC", CardId = "ST01-002", Owner = "south", Zone = "character" };
            int cBase = GameEngine.GetCost(st2, ch);
            var eff2 = new PendingEffect { EffectId = "C", Seat = "south", SourceInstanceId = "SRC", Text = "Up to 1 of your Characters gains +1 cost until the end of your opponent's next turn." };
            st2.PendingEffects.Add(eff2);
            GameEngine.ApplyCommand(st2, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "C", Target = "CH" });
            int cGive = GameEngine.GetCost(st2, ch);
            GameEngine.ApplyCommand(st2, new GameCommand { Type = "endTurn", Seat = "south" });
            int cOpp = GameEngine.GetCost(st2, ch); // persists into opp turn
            bool costOk = cGive == cBase + 1 && cOpp == cBase + 1;
            bool pass = powerOk && costOk;
            Console.WriteLine($"=== OPPTURNBUFFTEST === power: give={onGive}(+2000) opp={onOppTurn}(+2000) after={afterOppTurn}(exp)   cost: give={cGive}(+1) opp={cOpp}(+1) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // donpowertest — Rule 6-5-5-2: a Character gains +1000 power per attached DON!! ONLY during its
        // controller's turn (NOT on the opponent's turn — so a DON-boosted card blocks at BASE power).
        if (args.Length > 0 && args[0] == "donpowertest")
        {
            System.Func<string, int> pw = (string activeSeat) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "donpow" + activeSeat });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = activeSeat; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var ch = new CardInstance { InstanceId = "CH", CardId = "ST01-006", Owner = "south", Zone = "character" }; // base 1000
                ch.AttachedDonIds.Add("d1"); ch.AttachedDonIds.Add("d2"); // 2 attached DON
                S.CharacterArea[0] = ch;
                return GameEngine.GetPower(st, ch);
            };
            int ownTurn = pw("south");  // owner's turn → 1000 + 2000 = 3000
            int oppTurn = pw("north");  // opponent's turn → 1000 (no DON power)
            bool pass = ownTurn == 3000 && oppTurn == 1000;
            Console.WriteLine($"=== DONPOWERTEST === own-turn={ownTurn}(3000, +2 DON)   opp-turn={oppTurn}(1000, no DON power) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // blockerbantest — ST01-002 Usopp "[DON!! x2] [When Attacking] opponent cannot activate a [Blocker] with
        // 5000 or more power this battle." A 7000-power blocker is banned; a 2000-power blocker may still block.
        if (args.Length > 0 && args[0] == "blockerbantest")
        {
            System.Func<string, bool> canBlock = (string blockerCard) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "blockerban" + blockerCard });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                var usopp = new CardInstance { InstanceId = "USO", CardId = "ST01-002", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
                usopp.AttachedDonIds.Add("d1"); usopp.AttachedDonIds.Add("d2"); // [DON!! x2]
                N.CharacterArea[0] = usopp;
                var blk = new CardInstance { InstanceId = "BLK", CardId = blockerCard, Owner = "south", Zone = "character", Rested = false };
                S.CharacterArea[0] = blk;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "USO", Target = S.Leader.InstanceId });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "blockAttack", Seat = "south", Blocker = "BLK" });
                return st.Battle != null && st.Battle.TargetId == "BLK"; // block succeeded (redirected)?
            };
            bool bigBanned = !canBlock("EB02-044");  // 7000 → banned
            bool smallOk = canBlock("EB01-017");     // 2000 → allowed
            bool pass = bigBanned && smallOk;
            Console.WriteLine($"=== BLOCKERBANTEST === 7000-blocker banned={bigBanned}(T)   2000-blocker allowed={smallOk}(T) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // blockredirecttest — [Blocker] redirects the attack to itself; a weaker blocker is K.O.'d and the Leader
        // takes no Life. A RESTED Blocker cannot block. An unblockable/NoBlocker attack cannot be blocked.
        if (args.Length > 0 && args[0] == "blockredirecttest")
        {
            System.Func<bool, (bool, int, bool)> run = (bool blockerRested) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "blockredir" + blockerRested });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                var atk = new CardInstance { InstanceId = "ATK", CardId = "OP11-017", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 }; // 7000
                N.CharacterArea[0] = atk;
                var blk = new CardInstance { InstanceId = "BLK", CardId = "EB01-017", Owner = "south", Zone = "character", Rested = blockerRested }; // 2000 [Blocker]
                S.CharacterArea[0] = blk;
                int lifeBefore = S.Life.Count;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "ATK", Target = S.Leader.InstanceId });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "blockAttack", Seat = "south", Blocker = "BLK" });
                bool redirected = st.Battle != null && st.Battle.TargetId == "BLK";
                // finish the battle (defender passes counter, then the defender resolves the damage)
                if (st.Battle != null && st.Battle.Step == "counter") GameEngine.ApplyCommand(st, new GameCommand { Type = "passCounter", Seat = "south" });
                if (st.Battle != null && st.Battle.Step == "damage") GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveAttack", Seat = "south" });
                bool blkKoed = !S.CharacterArea.Any(c => c != null && c.InstanceId == "BLK");
                return (redirected, S.Life.Count - lifeBefore, blkKoed);
            };
            var active = run(false);   // active blocker → redirect, KO'd, leader safe
            var rested = run(true);    // rested blocker → cannot block
            bool pass = active.Item1 && active.Item2 == 0 && active.Item3    // redirected, leader life unchanged, blocker KO'd
                        && !rested.Item1;                                     // rested blocker did NOT redirect
            Console.WriteLine($"=== BLOCKREDIRECTTEST === active: redirect={active.Item1}(T) lifeΔ={active.Item2}(0) blockerKO={active.Item3}(T)   rested-blocker redirect={rested.Item1}(F) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // countereffecttest — a [Counter] event whose PRIMARY effect is NOT a defender power-buff (EB01-010
        // "[Counter] K.O. up to 1 opp Char 6000 base power or less") must fire that effect when played as a
        // counter. Was: only the "Then," SECONDARY was queued, so KO/−power counters did nothing.
        if (args.Length > 0 && args[0] == "countereffecttest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "counterfx" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6; // opponent's turn (north attacks)
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            var atk = new CardInstance { InstanceId = "ATK", CardId = "OP11-017", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 }; // 7000 attacker
            N.CharacterArea[0] = atk;
            var victim = new CardInstance { InstanceId = "VIC", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false }; // 1000 base ≤6000
            N.CharacterArea[1] = victim;
            S.Hand.Clear();
            S.Hand.Add(new CardInstance { InstanceId = "CTR", CardId = "EB01-010", Owner = "south", Zone = "hand" }); // Counter KO event (cost 3)
            S.CostArea.Clear();
            for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = "sd" + i, Rested = false }); // 3 active DON to pay
            GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "ATK", Target = S.Leader.InstanceId });
            if (st.Battle != null && st.Battle.Step == "block") GameEngine.ApplyCommand(st, new GameCommand { Type = "passBlock", Seat = "south" });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "counterWithCard", Seat = "south", InstanceId = "CTR" });
            // resolve the queued counter effect (KO), targeting the victim
            foreach (var pe in st.PendingEffects.Where(e => e.Seat == "south").ToList())
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "VIC" });
            bool victimKoed = !N.CharacterArea.Any(c => c != null && c.InstanceId == "VIC");
            Console.WriteLine($"=== COUNTEREFFECTTEST === EB01-010 counter-KO fired (victim K.O.'d)={victimKoed} (want True) : {(victimKoed ? "PASS" : "FAIL")}");
            return victimKoed ? 0 : 1;
        }
        // doublebanishtest — [Double Attack] deals 2 Life damage in one Leader hit (2 cards to hand via the
        // trigger step); [Banish] trashes the Life card (no Trigger, does NOT go to hand).
        if (args.Length > 0 && args[0] == "doublebanishtest")
        {
            System.Func<string, (int, int, int)> attackLeader = (string attackerCard) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "dbanish" + attackerCard });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                var atk = new CardInstance { InstanceId = "ATK", CardId = attackerCard, Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
                S.CharacterArea[0] = atk;
                N.Hand.Clear();
                N.Life.Clear();
                for (int i = 0; i < 5; i++) N.Life.Add(new CardInstance { InstanceId = "nl" + i, CardId = "ST01-006", Owner = "north", Zone = "life" }); // no-trigger vanilla
                int trashBefore = N.Trash.Count;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "south", Attacker = "ATK", Target = N.Leader.InstanceId });
                if (st.Battle != null && st.Battle.Step == "block") GameEngine.ApplyCommand(st, new GameCommand { Type = "passBlock", Seat = "north" });
                if (st.Battle != null && st.Battle.Step == "counter") GameEngine.ApplyCommand(st, new GameCommand { Type = "passCounter", Seat = "north" });
                if (st.Battle != null && st.Battle.Step == "damage") GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveAttack", Seat = "north" });
                // resolve any Life-trigger pending effects (add-to-hand) for north
                for (int g = 0; g < 6 && st.PendingEffects.Any(e => e.Seat == "north"); g++)
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = st.PendingEffects.First(e => e.Seat == "north").EffectId, Target = null });
                return (N.Life.Count, N.Hand.Count, N.Trash.Count - trashBefore);
            };
            var da = attackLeader("EB04-023");   // Double Attack (9000) → 2 Life to hand
            var ban = attackLeader("OP01-067");  // Banish (7000) → 1 Life trashed, not to hand
            bool daOk = da.Item1 == 3 && da.Item2 == 2 && da.Item3 == 0;   // Life 5→3, hand +2, trash +0
            bool banOk = ban.Item1 == 4 && ban.Item2 == 0 && ban.Item3 == 1; // Life 5→4, hand +0, trash +1
            bool pass = daOk && banOk;
            Console.WriteLine($"=== DOUBLEBANISHTEST === DA: life={da.Item1}(3) hand={da.Item2}(2) trash+{da.Item3}(0)   Banish: life={ban.Item1}(4) hand={ban.Item2}(0) trash+{ban.Item3}(1) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // conditionalrushtest — EB02-052 Enel "If your Leader has the {Sky Island} type, this Character gains
        // [Rush]." Rush must be granted only under a Sky-Island Leader, and Rush must clear summoning sickness
        // (the Character can attack the turn it's played).
        if (args.Length > 0 && args[0] == "conditionalrushtest")
        {
            System.Func<string, (bool, bool)> check = (string leaderId) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "condrush" + leaderId });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                S.Leader = new CardInstance { InstanceId = "LDR", CardId = leaderId, Owner = "south", Zone = "leader" };
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var enel = new CardInstance { InstanceId = "EN", CardId = "EB02-052", Owner = "south", Zone = "character", PlayedOnTurn = st.TurnNumber }; // played THIS turn
                S.CharacterArea[0] = enel;
                return (GameEngine.HasRush(st, enel), GameEngine.IsSummoningSick(st, enel));
            };
            var sky = check("OP05-098");   // Sky Island leader → Rush, not sick
            var nonSky = check("ST01-001"); // non-Sky-Island → no Rush, sick
            bool pass = sky.Item1 && !sky.Item2 && !nonSky.Item1 && nonSky.Item2;
            Console.WriteLine($"=== CONDITIONALRUSHTEST === Sky-leader: Rush={sky.Item1}(T) sick={sky.Item2}(F)   non-Sky: Rush={nonSky.Item1}(F) sick={nonSky.Item2}(T) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // cavendishtest — OP04-081 Cavendish "[DON!! x1] This Character can also attack active Characters." /
        // OP04-090 Luffy "This Character can also attack active Characters." The printed ability (WITHOUT "your
        // opponent's") must let the attacker target an ACTIVE opponent Character.
        if (args.Length > 0 && args[0] == "cavendishtest")
        {
            System.Func<string, int, bool> canHitActive = (string cardId, int don) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "cav" + cardId + don });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                var atk = new CardInstance { InstanceId = "ATK", CardId = cardId, Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
                for (int k = 0; k < don; k++) atk.AttachedDonIds.Add("d" + k);
                S.CharacterArea[0] = atk;
                var activeVictim = new CardInstance { InstanceId = "AV", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false }; // ACTIVE
                N.CharacterArea[0] = activeVictim;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "south", Attacker = "ATK", Target = "AV" });
                return st.Battle != null && st.Battle.TargetId == "AV"; // attack on the active char succeeded?
            };
            bool cav = canHitActive("OP04-081", 1);  // [DON!! x1] → with 1 DON, can hit active
            bool cavNoDon = canHitActive("OP04-081", 0); // 0 DON → gated, cannot
            bool luffy = canHitActive("OP04-090", 0); // no DON gate → can hit active
            bool pass = cav && !cavNoDon && luffy;
            Console.WriteLine($"=== CAVENDISHTEST === OP04-081 DON1 hits-active={cav}(T) DON0={cavNoDon}(F)   OP04-090 hits-active={luffy}(T) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // playrestedtest — "play … from your trash/hand rested" must enter the Character RESTED (not active).
        if (args.Length > 0 && args[0] == "playrestedtest")
        {
            System.Func<string, EffectTargetZone, bool> playAndCheck = (string effText, EffectTargetZone zone) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "playrested" + zone });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-002", Owner = "south", Zone = "character" };
                var card = new CardInstance { InstanceId = "P", CardId = "OP11-017", Owner = "south", Zone = zone == EffectTargetZone.Trash ? "trash" : "hand" }; // cost 6
                if (zone == EffectTargetZone.Trash) S.Trash.Add(card); else { S.Hand.Clear(); S.Hand.Add(card); }
                var eff = new PendingEffect { EffectId = "R", Seat = "south", SourceInstanceId = "SRC", TargetZone = zone, Text = effText };
                st.PendingEffects.Add(eff);
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "R", Target = "P" });
                var onBoard = S.CharacterArea.FirstOrDefault(c => c != null && c.InstanceId == "P");
                return onBoard != null && onBoard.Rested; // played AND rested?
            };
            bool trashRested = playAndCheck("Play up to 1 Character card with a cost of 8 or less from your trash rested.", EffectTargetZone.Trash);
            bool handRested = playAndCheck("Play up to 1 Character card with a cost of 8 or less from your hand rested.", EffectTargetZone.Hand);
            bool pass = trashRested && handRested;
            Console.WriteLine($"=== PLAYRESTEDTEST === from-trash-rested={trashRested}(T) from-hand-rested={handRested}(T) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // lifetrashtest — "Trash up to 1 card from the top of your opponent's Life cards" (aggressive Life removal).
        // OP03-120 gates on "opponent has 4+ Life"; trashing Life to 0 must NOT end the game (loss is by ATTACK at
        // 0 Life, not by Life reaching 0 via trash).
        if (args.Length > 0 && args[0] == "lifetrashtest")
        {
            System.Func<string, int, (int, string)> run = (string effText, int oppLife) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "lifetrash" + oppLife });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                while (N.Life.Count > oppLife) N.Life.RemoveAt(N.Life.Count - 1);
                while (N.Life.Count < oppLife) N.Life.Add(new CardInstance { InstanceId = "nl" + N.Life.Count, CardId = "ST01-006", Owner = "north", Zone = "life" });
                var eff = new PendingEffect { EffectId = "L", Seat = "south", SourceInstanceId = "SRC", Text = effText };
                st.PendingEffects.Add(eff);
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "L", Target = null });
                return (N.Life.Count, st.Status);
            };
            string cond = "If your opponent has 4 or more Life cards, trash up to 1 card from the top of your opponent's Life cards.";
            var hi = run(cond, 4);   // 4+ Life → trash 1 → 3
            var lo = run(cond, 3);   // <4 Life → condition fails → 3 (no trash)
            var toZero = run("Trash up to 1 card from the top of your opponent's Life cards.", 1); // 1→0, game stays active
            bool pass = hi.Item1 == 3 && lo.Item1 == 3 && toZero.Item1 == 0 && toZero.Item2 == "active";
            Console.WriteLine($"=== LIFETRASHTEST === cond 4Life->{hi.Item1}(3)   3Life(cond-fail)->{lo.Item1}(3)   toZero: life={toZero.Item1}(0) status={toZero.Item2}(active) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // op09073test — OP09-073 Brook "You may return 1 or more DON!! cards from your field to your DON!! deck:
        // Give up to 2 of your opponent's Characters −2000 power during this turn." Check the variable DON-return
        // cost pays (a DON returns to the DON!! deck) AND the body fires (−2000 power on the target).
        if (args.Length > 0 && args[0] == "op09073test")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op09073" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            S.CostArea.Clear();
            for (int i = 0; i < 3; i++) S.CostArea.Add(new DonInstance { InstanceId = "sd" + i, Rested = false });
            S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "OP09-073", Owner = "south", Zone = "character" };
            var v = new CardInstance { InstanceId = "V", CardId = "OP11-017", Owner = "north", Zone = "character" }; // 7000 power
            N.CharacterArea[0] = v;
            int pwBefore = GameEngine.GetPower(st, v); int donBefore = S.CostArea.Count;
            var eff = new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "SRC",
                Text = "You may return 1 or more DON!! cards from your field to your DON!! deck: Give up to 2 of your opponent's Characters −2000 power during this turn." };
            st.PendingEffects.Add(eff);
            // Resolve the cost, then target V TWICE. The distinct-target guard must apply −2000 only ONCE
            // (the repeat pick is rejected), leaving V at −2000, not −4000; a DON is returned for the cost.
            for (int g = 0; g < 4 && st.PendingEffects.Any(e => e.Seat == "south"); g++)
            {
                var pe = st.PendingEffects.First(e => e.Seat == "south");
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "V" });
            }
            int pwAfter = GameEngine.GetPower(st, v);
            bool donReturned = S.CostArea.Count == donBefore - 1;
            bool distinctEnforced = pwAfter == pwBefore - 2000; // not -4000
            bool pass = donReturned && distinctEnforced;
            Console.WriteLine($"=== OP09073TEST === V power {pwBefore}->{pwAfter} (want −2000, not −4000)   DON {donBefore}->{S.CostArea.Count} (want −1) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // oppdiscardtest — "Trash N cards from your opponent's hand" (the CONTROLLER picks). OP06-097 trash-1;
        // OP03-078 "[On Play] If your opponent has 6 or more cards in their hand, trash 2 …" (conditional).
        if (args.Length > 0 && args[0] == "oppdiscardtest")
        {
            System.Func<string, int, int> resolveTrash = (string effText, int oppHandSize) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "oppdisc" + oppHandSize });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                N.Hand.Clear();
                for (int i = 0; i < oppHandSize; i++) N.Hand.Add(new CardInstance { InstanceId = "nh" + i, CardId = "ST01-006", Owner = "north", Zone = "hand" });
                var eff = new PendingEffect { EffectId = "T", Seat = "south", SourceInstanceId = "SRC", TargetZone = EffectTargetZone.Hand, Text = effText };
                st.PendingEffects.Add(eff);
                for (int g = 0; g < 5 && st.PendingEffects.Any(e => e.Seat == "south"); g++)
                {
                    var pe = st.PendingEffects.First(e => e.Seat == "south");
                    var pick = N.Hand.FirstOrDefault();
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = pick?.InstanceId });
                    if (pick == null) break;
                }
                return N.Hand.Count;
            };
            int op6097 = resolveTrash("Trash 1 card from your opponent's hand.", 3);
            int op3078hi = resolveTrash("If your opponent has 6 or more cards in their hand, trash 2 cards from your opponent's hand.", 6);
            int op3078lo = resolveTrash("If your opponent has 6 or more cards in their hand, trash 2 cards from your opponent's hand.", 5);
            bool pass = op6097 == 2 && op3078hi == 4 && op3078lo == 5;
            Console.WriteLine($"=== OPPDISCARDTEST === OP06-097 trash1: 3->{op6097}(2)   OP03-078 6hand: 6->{op3078hi}(4)   5hand(cond-fail): 5->{op3078lo}(5) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
