        // blockbantest — OP12-051 Hina "Up to 1 of your opponent's Characters with a base cost of 4 or less cannot
        // activate [Blocker] during this turn." Must ban ONLY the chosen cost≤4 Character — not every opponent
        // Character (the handler parsed only "power or less", so a base-cost filter was ignored → banned all).
        if (args.Length > 0 && args[0] == "op12051test")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "blockban" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-002", Owner = "south", Zone = "character" };
            var lo = new CardInstance { InstanceId = "LO", CardId = "ST01-006", Owner = "north", Zone = "character" }; // base cost 1 ≤4
            var hi = new CardInstance { InstanceId = "HI", CardId = "EB01-002", Owner = "north", Zone = "character" }; // base cost 5 >4
            N.CharacterArea[0] = lo; N.CharacterArea[1] = hi;
            var eff = new PendingEffect { EffectId = "B", Seat = "south", SourceInstanceId = "SRC",
                Text = "Up to 1 of your opponent's Characters with a base cost of 4 or less cannot activate [Blocker] during this turn." };
            st.PendingEffects.Add(eff);
            // Resolve, picking the cost≤4 char (LO).
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "B", Target = "LO" });
            bool loBanned = GameEngine.HasModifier(st, lo, "cannotBlock");
            bool hiBanned = GameEngine.HasModifier(st, hi, "cannotBlock"); // the cost-5 char must NOT be banned
            // OP11-013-style "All of your opponent's Characters with 2000 power or less" — board-wide by power.
            var st2 = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "blockban2" });
            st2.Status = "active"; st2.Phase = "main"; st2.ActiveSeat = "south"; st2.TurnNumber = 6;
            var N2 = st2.Players["north"];
            for (int i = 0; i < 5; i++) { st2.Players["south"].CharacterArea[i] = null; N2.CharacterArea[i] = null; }
            st2.Players["south"].CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-002", Owner = "south", Zone = "character" };
            var weak = new CardInstance { InstanceId = "WEAK", CardId = "ST01-006", Owner = "north", Zone = "character" }; // 1000 power ≤2000
            var strong = new CardInstance { InstanceId = "STRONG", CardId = "OP11-017", Owner = "north", Zone = "character" }; // 7000 power >2000
            N2.CharacterArea[0] = weak; N2.CharacterArea[1] = strong;
            var eff2 = new PendingEffect { EffectId = "B2", Seat = "south", SourceInstanceId = "SRC",
                Text = "All of your opponent's Characters with 2000 power or less cannot activate [Blocker] during this turn." };
            st2.PendingEffects.Add(eff2);
            GameEngine.ApplyCommand(st2, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "B2", Target = null });
            bool weakBanned = GameEngine.HasModifier(st2, weak, "cannotBlock");
            bool strongBanned = GameEngine.HasModifier(st2, strong, "cannotBlock");
            bool pass = loBanned && !hiBanned && weakBanned && !strongBanned;
            Console.WriteLine($"=== OP12051TEST === upTo1: cost1={loBanned}(T) cost5={hiBanned}(F)   All-by-power: weak={weakBanned}(T) strong={strongBanned}(F) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
