        // cannotattacktest — OP05-042-style "Up to 1 of your opponent's Characters with a cost of 7 or less cannot
        // attack until the start of your next turn." The restriction must be enforced (the char can't declare an
        // attack) AND persist into the opponent's turn (untilNextTurn), then clear at the applier's next turn.
        if (args.Length > 0 && args[0] == "cannotattacktest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "cantatk" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-002", Owner = "south", Zone = "character" };
            var v = new CardInstance { InstanceId = "V", CardId = "OP11-017", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 }; // cost 6 ≤7
            N.CharacterArea[0] = v;
