                Text = "Up to 1 of your opponent's Characters with a cost of 7 or less cannot attack until the start of your next turn." };
            st.PendingEffects.Add(eff);
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "R", Target = "V" });
            bool restricted = GameEngine.HasModifier(st, v, "cannotAttack");
            // Move to the opponent's (north's) turn and try to attack with V — must be blocked (untilNextTurn).
            GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "south" }); // → north's turn
            for (int i = 0; i < 6; i++) N.CostArea.Add(new DonInstance { InstanceId = "nd" + i, Rested = false });
            bool stillRestricted = GameEngine.HasModifier(st, v, "cannotAttack");
            GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "V", Target = S.Leader.InstanceId });
            bool attackBlocked = st.Battle == null; // no battle created → attack rejected
            bool pass = restricted && stillRestricted && attackBlocked;
            Console.WriteLine($"=== CANNOTATTACKTEST === restricted={restricted}(T) persists-into-opp-turn={stillRestricted}(T) attack-blocked={attackBlocked}(T) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
