        // op16003test — OP16-003 Edward.Newgate "[Your Turn] Your Leader gains [Double Attack] and +2000 power."
        // A continuous keyword+power AURA on the LEADER — active during the controller's turn, off otherwise.
        if (args.Length > 0 && args[0] == "op16003test")
        {
