            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op16003" + activeSeat });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = activeSeat; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                S.CharacterArea[0] = new CardInstance { InstanceId = "WB", CardId = "OP16-003", Owner = "south", Zone = "character" };
                S.CharacterArea[1] = new CardInstance { InstanceId = "OTHER", CardId = "ST01-006", Owner = "south", Zone = "character" }; // must NOT get the aura
                return (GameEngine.HasDoubleAttack(st, S.Leader), GameEngine.GetPower(st, S.Leader));
            };
            var onTurn = leaderState("south");   // your turn → aura active
            var offTurn = leaderState("north");  // opponent's turn → aura off
            int baseP = offTurn.Item2;
            // no-leak: a plain Character must NOT gain the +2000 or [Double Attack].
            var stLeak = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op16003leak" });
            stLeak.Status = "active"; stLeak.Phase = "main"; stLeak.ActiveSeat = "south"; stLeak.TurnNumber = 6;
            var SL = stLeak.Players["south"];
            for (int i = 0; i < 5; i++) SL.CharacterArea[i] = null;
            SL.CharacterArea[0] = new CardInstance { InstanceId = "WB", CardId = "OP16-003", Owner = "south", Zone = "character" };
            var other = new CardInstance { InstanceId = "OTHER", CardId = "ST01-006", Owner = "south", Zone = "character" }; // 1000 power
            SL.CharacterArea[1] = other;
            bool leak = GameEngine.GetPower(stLeak, other) != 1000 || GameEngine.HasDoubleAttack(stLeak, other);
            bool pass = onTurn.Item1 && onTurn.Item2 == baseP + 2000 && !offTurn.Item1 && !leak;
            Console.WriteLine($"=== OP16003TEST === your-turn: DA={onTurn.Item1}(T) power={onTurn.Item2}(base+2000={baseP + 2000})   opp-turn: DA={offTurn.Item1}(F)   char-leak={leak}(F) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
