        // sakazukitest — OP05-041 Sakazuki "[Activate: Main] [Once Per Turn] … : Draw 1 / [When Attacking] Give
        // up to 1 opp Char −1 cost." The [Once Per Turn] is on the ACTIVATE line only — using the Activate:Main
        // must NOT block the (unlimited) When-Attacking, and vice versa (distinct once-per-turn keys).
        if (args.Length > 0 && args[0] == "sakazukitest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "sak" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            var sak = new CardInstance { InstanceId = "SAK", CardId = "OP05-041", Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            S.CharacterArea[0] = sak;
            var v = new CardInstance { InstanceId = "V", CardId = "EB01-002", Owner = "north", Zone = "character", Rested = false }; // cost 5
            N.CharacterArea[0] = v;
            int costBefore = GameEngine.GetCost(st, v);
            // Simulate the [Activate: Main] [Once Per Turn] having been used this turn (bare instanceId key).
            S.AbilityUsedThisTurn.Add("SAK");
            // Now attack — the When-Attacking (−1 cost) must still fire.
            GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "south", Attacker = "SAK", Target = N.Leader.InstanceId });
            bool waQueued = st.PendingEffects.Any(e => e.Seat == "south" && e.Timing == "whenAttacking");
            foreach (var pe in st.PendingEffects.Where(e => e.Seat == "south" && e.Timing == "whenAttacking").ToList())
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "V" });
            int costAfter = GameEngine.GetCost(st, v);
            bool pass = waQueued && costAfter == costBefore - 1;
            Console.WriteLine($"=== SAKAZUKITEST === When-Attacking queued after Activate:Main used={waQueued} (want True)   opp cost {costBefore}->{costAfter} (want −1) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
