        // onblocktest — OP01-039 Killer "[DON!! x1] [On Block] If you have 3 or more Characters, draw 1 card."
        // The [DON!! x1] gate must require Killer to have ≥1 DON attached — with 0 DON the On-Block must NOT fire.
        if (args.Length > 0 && args[0] == "onblocktest")
        {
            System.Func<int, int> handDeltaOnBlock = (int killerDon) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "onblock" + killerDon });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                S.TurnsStarted = 3; N.TurnsStarted = 3;
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                var killer = new CardInstance { InstanceId = "KILL", CardId = "OP01-039", Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
                for (int d = 0; d < killerDon; d++) killer.AttachedDonIds.Add("kd" + d);
                S.CharacterArea[0] = killer;
                S.CharacterArea[1] = new CardInstance { InstanceId = "C1", CardId = "ST01-006", Owner = "south", Zone = "character" };
                S.CharacterArea[2] = new CardInstance { InstanceId = "C2", CardId = "ST01-006", Owner = "south", Zone = "character" }; // 3 chars total
                var atk = new CardInstance { InstanceId = "ATK", CardId = "OP11-017", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
                N.CharacterArea[0] = atk;
                for (int i = 0; i < 4; i++) N.CostArea.Add(new DonInstance { InstanceId = "nd" + i, Rested = false });
                int handBefore = S.Hand.Count;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "ATK", Target = S.Leader.InstanceId });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "blockAttack", Seat = "south", Blocker = "KILL" });
