            bool pass = with1 == 1 && with0 == 0;
            Console.WriteLine($"=== ONBLOCKTEST === Killer DON x1 draws={with1} (want 1)   DON x0 draws={with0} (want 0) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
