        // endofturntest — [End of Your Turn] delayed effects. (a) OP04-027 "[DON!! x1] Set this Character as
        // active" un-rests at the END of the CONTROLLER's turn only. (b) OP04-034 "If you have 3+ active DON!!,
        // K.O. up to 1 opp rested Char cost ≤3" — conditional queued removal.
        if (args.Length > 0 && args[0] == "endofturntest")
        {
            // (a) self-untap fires on OWN EndTurn, not the opponent's.
            System.Func<string, bool> untapAfterEndTurn = (string enderSeat) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "eot_" + enderSeat });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = enderSeat; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var daddy = new CardInstance { InstanceId = "DAD", CardId = "OP04-027", Owner = "south", Zone = "character", Rested = true };
                daddy.AttachedDonIds.Add("d0"); // [DON!! x1] gate
                S.CharacterArea[0] = daddy;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = enderSeat });
                return !daddy.Rested; // set active?
            };
            bool ownTurn = untapAfterEndTurn("south");  // south ends → fires
            bool oppTurn = untapAfterEndTurn("north");  // north ends → south's card must NOT fire
            // (b) conditional KO.
            System.Func<int, bool> laoKo = (int activeDon) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "lao" + activeDon });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "LAO", CardId = "OP04-034", Owner = "south", Zone = "character" };
                S.CostArea.Clear();
                for (int i = 0; i < activeDon; i++) S.CostArea.Add(new DonInstance { InstanceId = "d" + i, Rested = false });
                var v = new CardInstance { InstanceId = "V", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = true }; // cost 1, rested
                N.CharacterArea[0] = v;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "endTurn", Seat = "south" });
                // OP04-034 resolves inline during End-of-Turn (before the opponent's refresh), so V is K.O.'d
                // immediately when the condition holds — no deferred pending pick.
                return !N.CharacterArea.Any(c => c != null && c.InstanceId == "V"); // KO'd?
            };
            bool koWith3 = laoKo(3);  // 3 active DON → condition met → KO
            bool koWith2 = laoKo(2);  // 2 active DON → condition NOT met → no KO
            bool pass = ownTurn && koWith3 && !koWith2;
            Console.WriteLine($"=== ENDOFTURNTEST === OP04-027 own-EndTurn-untap={ownTurn}(T)   OP04-034 KO@3DON={koWith3}(T) KO@2DON={koWith2}(F) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // onko3test — replacement effects "would be K.O.'d/removed BY YOUR OPPONENT'S EFFECT … instead" must NOT
        // save a Character that lost in BATTLE (only an EFFECT removal). Exception: an "or K.O.'d" / leading
        // "would be K.O.'d or" wording covers battle and still saves.
        if (args.Length > 0 && args[0] == "onko3test")
        {
            var mi = typeof(GameEngine).GetMethod("TryRemovalReplacement", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static);
            // OP10-074 Pica: "If this Character would be K.O.'d by your opponent's effect, rest 2 active DON!! instead."
            System.Func<bool, bool> pica = (bool battle) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "pica" + battle });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var p = new CardInstance { InstanceId = "P", CardId = "OP10-074", Owner = "south", Zone = "character" };
                S.CharacterArea[0] = p;
                S.CostArea.Clear();
                for (int i = 0; i < 2; i++) S.CostArea.Add(new DonInstance { InstanceId = "d" + i, Rested = false });
                return (bool)mi.Invoke(null, new object[] { st, "south", p, battle });
            };
            // OP13-046 Vista: "would be K.O.'d OR removed by opponent's effect: trash 1 Whitebeard card instead."
            System.Func<bool, bool> vista = (bool battle) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "vista" + battle });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"];
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var v = new CardInstance { InstanceId = "V", CardId = "OP13-046", Owner = "south", Zone = "character" };
                S.CharacterArea[0] = v;
                S.Hand.Clear(); S.Hand.Add(new CardInstance { InstanceId = "WB", CardId = "EB01-002", Owner = "south", Zone = "hand" });
                return (bool)mi.Invoke(null, new object[] { st, "south", v, battle });
            };
            bool picaEffect = pica(false), picaBattle = pica(true);
            bool vistaEffect = vista(false), vistaBattle = vista(true);
            bool pass = picaEffect && !picaBattle && vistaEffect && vistaBattle;
            Console.WriteLine($"=== ONKO3TEST === Pica effect-KO saved={picaEffect}(T) battle-KO saved={picaBattle}(F)   Vista effect={vistaEffect}(T) battle={vistaBattle}(T, or-K.O. exception) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // onko2test — OP16-024 Inazuma "When this Character is K.O.'d BY YOUR OPPONENT'S EFFECT, rest up to 1 of
        // your opponent's Characters." Must fire on an effect K.O. but NOT on a BATTLE K.O. (battle exclusion).
        if (args.Length > 0 && args[0] == "onko2test")
        {
            var mtrash = typeof(GameEngine).GetMethod("MoveToTrash", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static);
            System.Func<bool, bool> oppRested = (bool byBattle) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "onko2" + byBattle });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "INA", CardId = "OP16-024", Owner = "south", Zone = "character" };
                var oppc = new CardInstance { InstanceId = "OPPC", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false };
                N.CharacterArea[0] = oppc;
                mtrash.Invoke(null, new object[] { st, "south", "INA", false, true, byBattle }); // isKo=true, byBattleKo=byBattle
                foreach (var pe in st.PendingEffects.Where(e => e.Seat == "south").ToList())
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "OPPC" });
                return oppc.Rested;
            };
            bool effectKo = oppRested(false); // effect KO → should rest opponent
            bool battleKo = oppRested(true);  // battle KO → should NOT rest (battle exclusion)
            bool pass = effectKo && !battleKo;
            Console.WriteLine($"=== ONKO2TEST === effect-KO rests opp={effectKo} (want True)   battle-KO rests opp={battleKo} (want False) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // onkotest — OP01-007 "[On K.O.] K.O. up to 1 of your opponent's Characters with 4000 power or less."
        // When this Character is K.O.'d, its On-K.O. fires and KOs a weak opponent Character. Also checks the
        // negative: a NON-KO removal (isKo:false, e.g. a bounce/cost-trash) must NOT fire the On-K.O.
        if (args.Length > 0 && args[0] == "onkotest")
        {
            var mtrash = typeof(GameEngine).GetMethod("MoveToTrash", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static);
            System.Func<bool, bool> run = (bool asKo) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "onko" + asKo });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6; // opponent's turn
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                var self = new CardInstance { InstanceId = "SELF", CardId = "OP01-007", Owner = "south", Zone = "character" };
                S.CharacterArea[0] = self;
                var weak = new CardInstance { InstanceId = "WEAK", CardId = "ST01-006", Owner = "north", Zone = "character" }; // 1000 power
                N.CharacterArea[0] = weak;
                // silent=false, isKo=asKo, byBattleKo=false
                mtrash.Invoke(null, new object[] { st, "south", "SELF", false, asKo, false });
                foreach (var pe in st.PendingEffects.Where(e => e.Seat == "south").ToList())
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "WEAK" });
                return !N.CharacterArea.Any(c => c != null && c.InstanceId == "WEAK"); // weak KO'd by the On-K.O.?
            };
            bool koFires = run(true);    // genuine K.O. → On-K.O. fires → weak KO'd
            bool nonKoQuiet = !run(false); // non-K.O. removal → On-K.O. must NOT fire → weak survives
            bool pass = koFires && nonKoQuiet;
            Console.WriteLine($"=== ONKOTEST === on-KO fires (weak KO'd)={koFires} (want True)   non-KO stays quiet={nonKoQuiet} (want True) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // op09032test — OP09-032 Rosinante "[On Your Opponent's Attack] [Once Per Turn] Set this Character as
        // active." A RESTED Rosinante on the defender's board un-rests itself when the opponent declares an attack
        // (so it can keep [Blocker]-ing). Verifies the reactive dispatch fires + the once-per-turn gate.
        if (args.Length > 0 && args[0] == "op09032test")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "op09032" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            var rosi = new CardInstance { InstanceId = "ROSI", CardId = "OP09-032", Owner = "south", Zone = "character", Rested = true, PlayedOnTurn = 0 };
            S.CharacterArea[0] = rosi;
            var atk = new CardInstance { InstanceId = "ATK", CardId = "OP11-017", Owner = "north", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            N.CharacterArea[0] = atk;
            for (int i = 0; i < 4; i++) N.CostArea.Add(new DonInstance { InstanceId = "nd" + i, Rested = false });
            // North declares an attack on the south Leader.
            GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "north", Attacker = "ATK", Target = S.Leader.InstanceId });
            bool queued = st.PendingEffects.Any(e => e.Seat == "south" && e.SourceInstanceId == "ROSI");
            foreach (var pe in st.PendingEffects.Where(e => e.Seat == "south").ToList())
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "ROSI" });
            bool nowActive = !rosi.Rested;
            bool onceMarked = S.AbilityUsedThisTurn.Contains("ROSI:onOppAttack");
            bool pass = queued && nowActive && onceMarked;
            Console.WriteLine($"=== OP09032TEST === reaction-queued={queued} Rosinante-now-active={nowActive} once-per-turn-marked={onceMarked} : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // drawchaintest — draw/discard/return clauses followed by ". Then, <removal>": verify clause 2 fires.
        //   OP16-090: "Draw 2 and trash 2 from hand. Then, K.O. up to 1 opp Char cost ≤1."
        //   OP03-122: "Return up to 1 Char cost ≤6 to hand. Then, draw 2 and trash 2."
        if (args.Length > 0 && args[0] == "drawchaintest")
        {
            // OP16-090: does clause 2 (K.O. cost ≤1) fire after draw+discard? Victim = cost-1 char.
            bool drawKo;
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "drawko" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-002", Owner = "south", Zone = "character" };
                S.Hand.Clear();
                for (int i = 0; i < 4; i++) S.Hand.Add(new CardInstance { InstanceId = "h" + i, CardId = "ST01-006", Owner = "south", Zone = "hand" });
                var v = new CardInstance { InstanceId = "V", CardId = "ST01-006", Owner = "north", Zone = "character" }; // cost 1
                N.CharacterArea[0] = v;
                var eff = new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "SRC",
                    Text = "Draw 2 cards and trash 2 cards from your hand. Then, K.O. up to 1 of your opponent's Characters with a cost of 1 or less." };
                st.PendingEffects.Add(eff);
                // Drive: for a hand-discard clause target a hand card; for the K.O. target V.
                for (int g = 0; g < 8 && st.PendingEffects.Any(e => e.Seat == "south"); g++)
                {
                    var pe = st.PendingEffects.First(e => e.Seat == "south");
                    string tgt = (pe.TargetZone == EffectTargetZone.Hand || pe.Text.IndexOf("from your hand", StringComparison.OrdinalIgnoreCase) >= 0)
                        ? S.Hand.FirstOrDefault()?.InstanceId : "V";
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = tgt });
                }
                drawKo = !N.CharacterArea.Any(c => c != null && c.InstanceId == "V");
            }
            // OP03-122: "Return up to 1 Char cost ≤6 to hand. Then, draw 2 and trash 2." Verify clause 2 (draw 2)
            // fired — the source's deck drops by 2 (drew 2). Victim (cost 1) is returned by clause 1.
            bool returnDrew;
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "retdraw" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "SRC", CardId = "ST01-002", Owner = "south", Zone = "character" };
                S.Hand.Clear();
                for (int i = 0; i < 4; i++) S.Hand.Add(new CardInstance { InstanceId = "h" + i, CardId = "ST01-006", Owner = "south", Zone = "hand" });
                var v = new CardInstance { InstanceId = "V", CardId = "ST01-006", Owner = "north", Zone = "character" };
                N.CharacterArea[0] = v;
                int deckBefore = S.Deck.Count;
                var eff = new PendingEffect { EffectId = "E", Seat = "south", SourceInstanceId = "SRC",
                    Text = "Return up to 1 Character with a cost of 6 or less to the owner's hand. Then, draw 2 cards and trash 2 cards from your hand." };
                st.PendingEffects.Add(eff);
                for (int g = 0; g < 8 && st.PendingEffects.Any(e => e.Seat == "south"); g++)
                {
                    var pe = st.PendingEffects.First(e => e.Seat == "south");
                    string tgt = (pe.Text.IndexOf("from your hand", StringComparison.OrdinalIgnoreCase) >= 0 && pe.Text.IndexOf("Return", StringComparison.OrdinalIgnoreCase) < 0)
                        ? S.Hand.FirstOrDefault()?.InstanceId : "V";
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = tgt });
                }
                bool vReturned = !N.CharacterArea.Any(c => c != null && c.InstanceId == "V");
                returnDrew = vReturned && S.Deck.Count == deckBefore - 2;
            }
            bool pass = drawKo && returnDrew;
            Console.WriteLine($"=== DRAWCHAINTEST === OP16-090 draw→KO={drawKo}   OP03-122 return→draw2={returnDrew} (want True) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // decklooktest — "Look at 5; reveal up to 1 {Straw Hat Crew} type Character and add it to your hand. Then,
        // place the rest at the bottom" (EB02-017 pattern). Verifies: the reveal FILTER is enforced (a non-SHC card
        // is rejected), the matching card goes to HAND, and the rest go to the BOTTOM of the deck.
        if (args.Length > 0 && args[0] == "decklooktest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "decklook" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"];
            // Stack the top 5: [non-SHC, SHC, filler, filler, filler].
            var nonshc = new CardInstance { InstanceId = "NON", CardId = "EB01-002", Owner = "south", Zone = "deck" }; // Izo, not SHC
            var shc = new CardInstance { InstanceId = "SHC", CardId = "EB01-006", Owner = "south", Zone = "deck" };    // Chopper, SHC
            var f1 = new CardInstance { InstanceId = "F1", CardId = "EB01-002", Owner = "south", Zone = "deck" };
            var f2 = new CardInstance { InstanceId = "F2", CardId = "EB01-002", Owner = "south", Zone = "deck" };
            var f3 = new CardInstance { InstanceId = "F3", CardId = "EB01-002", Owner = "south", Zone = "deck" };
            S.Deck.Insert(0, f3); S.Deck.Insert(0, f2); S.Deck.Insert(0, f1); S.Deck.Insert(0, shc); S.Deck.Insert(0, nonshc);
            int deckBefore = S.Deck.Count;
            var eff = new PendingEffect { EffectId = "DL", Seat = "south", SourceInstanceId = "SRC",
                Text = "Look at 5 cards from the top of your deck; reveal up to 1 {Straw Hat Crew} type Character card and add it to your hand. Then, place the rest at the bottom of the deck in any order." };
            st.PendingEffects.Add(eff);
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "DL", Target = null });
            // Try the non-SHC card first — must be rejected (stays in the look).
            GameEngine.ApplyCommand(st, new GameCommand { Type = "deckLookSelect", Seat = "south", Target = "NON" });
            bool nonRejected = !S.Hand.Any(c => c.InstanceId == "NON");
            // Now the SHC card — accepted, added to hand.
            GameEngine.ApplyCommand(st, new GameCommand { Type = "deckLookSelect", Seat = "south", Target = "SHC" });
            // Confirm the rest go to the bottom (order as-is).
            if (st.DeckLook != null && st.DeckLook.Step == "rearrange")
            {
                var restIds = st.DeckLook.Cards.Select(c => c.InstanceId).ToList();
                GameEngine.ApplyCommand(st, new GameCommand { Type = "deckLookConfirmOrder", Seat = "south", OrderedInstanceIds = restIds });
            }
            bool shcInHand = S.Hand.Any(c => c.InstanceId == "SHC");
            bool nonAtBottom = S.Deck.Count > 0 && S.Deck.Skip(S.Deck.Count - 4).Any(c => c.InstanceId == "NON");
            bool deckDown1 = S.Deck.Count == deckBefore - 1;
            bool pass = nonRejected && shcInHand && nonAtBottom && deckDown1;
            Console.WriteLine($"=== DECKLOOKTEST === nonSHC-rejected={nonRejected} SHC-in-hand={shcInHand} rest-at-bottom={nonAtBottom} deck-1={deckDown1} : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // moriatrigtest — OP16-105 Gecko Moria [Trigger] "If you have 1 or less Life cards, play up to 1 [Absalom],
        // up to 1 [Dr. Hogback], and up to 1 [Perona], with a cost of 4 or less from your trash." Multi-named play
