            var per = new CardInstance { InstanceId = "PER", CardId = "EB03-045", Owner = "south", Zone = "trash" };
            S.Trash.Add(abs); S.Trash.Add(hog); S.Trash.Add(per);
            var eff = new PendingEffect { EffectId = "M", Seat = "south", SourceInstanceId = "SRC", TargetZone = EffectTargetZone.Trash,
                Text = "If you have 1 or less Life cards, play up to 1 [Absalom], up to 1 [Dr. Hogback], and up to 1 [Perona], with a cost of 4 or less from your trash." };
            st.PendingEffects.Add(eff);
