        // triggercaptest — ST29-013 Rob Lucci / EB01-059 Kingdom Come [Trigger] "K.O. up to 1 of your opponent's
        // Characters with a cost equal to or less than the TOTAL of your and your opponent's Life cards." Verifies
        // ComputeDynamicCap: with my Life 2 + opp Life 3 → cap 5, a cost-5 char is removable but a cost-6 is not.
        if (args.Length > 0 && args[0] == "triggercaptest")
        {
            System.Func<string, bool> canKo = (string victimId) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "trigcap" + victimId });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
