                while (S.Life.Count < 2) S.Life.Add(new CardInstance { InstanceId = "sl" + S.Life.Count, CardId = "ST01-006", Owner = "south", Zone = "life" });
                while (N.Life.Count > 3) N.Life.RemoveAt(N.Life.Count - 1);
                while (N.Life.Count < 3) N.Life.Add(new CardInstance { InstanceId = "nl" + N.Life.Count, CardId = "ST01-006", Owner = "north", Zone = "life" });
                for (int i = 0; i < 5; i++) N.CharacterArea[i] = null;
