                    Text = "K.O. up to 1 of your opponent's Characters with a cost equal to or less than the total of your and your opponent's Life cards." };
                st.PendingEffects.Add(eff);
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "T", Target = "V" });
                return !N.CharacterArea.Any(c => c != null && c.InstanceId == "V"); // true if KO'd
            };
            bool cost5 = canKo("EB01-002"); bool cost6 = canKo("EB01-008");
            bool pass = cost5 && !cost6;
            Console.WriteLine($"=== TRIGGERCAPTEST === (cap=Life 2+3=5) cost-5 KO'd={cost5} (want True)   cost-6 KO'd={cost6} (want False) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
