        // totalpowertest — OP05-007 Sabo "[On Play] K.O. up to 2 of your opponent's Characters with a TOTAL power
        // of 4000 or less." The SUM of the K.O.'d characters' power must stay ≤4000 (shared RemainingBudget), not
        // each. Two 3000-power chars → only ONE is removable; two 2000-power chars → BOTH.
        if (args.Length > 0 && args[0] == "totalpowertest")
        {
            System.Func<int, int> koCount = (int perPower) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "totpow" + perPower });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                var c1 = new CardInstance { InstanceId = "C1", CardId = "ST01-006", Owner = "north", Zone = "character" };
                var c2 = new CardInstance { InstanceId = "C2", CardId = "ST01-006", Owner = "north", Zone = "character" };
                N.CharacterArea[0] = c1; N.CharacterArea[1] = c2;
                st.TemporaryPowerBonus[c1.InstanceId] = perPower - 1000; // base 1000 → perPower
                st.TemporaryPowerBonus[c2.InstanceId] = perPower - 1000;
                var eff = new PendingEffect { EffectId = "SB", Seat = "south", SourceInstanceId = "SRC",
                    Text = "K.O. up to 2 of your opponent's Characters with a total power of 4000 or less." };
                st.PendingEffects.Add(eff);
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "SB", Target = "C1" });
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "SB", Target = "C2" });
                return N.CharacterArea.Count(c => c != null && (c.InstanceId == "C1" || c.InstanceId == "C2")); // survivors
            };
            System.Func<int, int> koed = p => 2 - koCount(p);
            int ko3000 = koed(3000); int ko2000 = koed(2000);
            bool pass = ko3000 == 1 && ko2000 == 2;
            Console.WriteLine($"=== TOTALPOWERTEST === two 3000s: KO'd={ko3000} (want 1, sum cap)   two 2000s: KO'd={ko2000} (want 2) : {(pass ? "PASS" : "FAIL")}");
            return pass ? 0 : 1;
        }
        // celestialtest — OP05-084 Saint Charlos "[Your Turn] If the only Characters on your field are {Celestial
        // Dragons} type, give all of your opponent's Characters −4 cost." Verifies the opponent-cost-debuff aura +
        // the "only … are {tag}" condition: reduction applies with an all-CD field, and drops when a non-CD char
        // joins your field.
        if (args.Length > 0 && args[0] == "celestialtest")
        {
            System.Func<bool, int> run = (bool allCD) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "celest" + allCD });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                S.CharacterArea[0] = new CardInstance { InstanceId = "CH", CardId = "OP05-084", Owner = "south", Zone = "character" }; // CD aura source
                S.CharacterArea[1] = new CardInstance { InstanceId = "CD2", CardId = "OP05-092", Owner = "south", Zone = "character" }; // CD
                if (!allCD) S.CharacterArea[2] = new CardInstance { InstanceId = "NONCD", CardId = "ST01-006", Owner = "south", Zone = "character" }; // breaks the "only CD" condition
                var opp = new CardInstance { InstanceId = "OPP", CardId = "OP02-004", Owner = "north", Zone = "character" }; // base cost 9
                N.CharacterArea[0] = opp;
                return GameEngine.GetCost(st, opp);
