            int withAllCD = run(true); int withNonCD = run(false);
            // Both OP05-084 (−4) and OP05-092 (−6) are CD cost-aura sources → stack to −10 → 9−10 clamped to 0.
            // With a non-CD char present, the "only CD" condition breaks for BOTH → no reduction → base 9.
            bool pass = withAllCD == 0 && withNonCD == 9;
            Console.WriteLine($"=== CELESTIALTEST === opp cost all-CD-field={withAllCD} (want 0, −4/−6 stacked+clamped)   non-CD-present={withNonCD} (want 9) : {(pass ? "PASS" : "FAIL")}");
