        // handcosttest — conditional "give this card in your hand −N cost" discounts (GetHandSelfCostBonus).
        // Fails CLOSED if EvaluateCondition can't parse the condition → discount silently never applies → the
        // card is unplayably expensive. Verifies each condition IS understood (cost drops when it's satisfied).
        if (args.Length > 0 && args[0] == "handcosttest")
        {
            int fails = 0;
            System.Action<string, System.Action<GameState, PlayerState, PlayerState, CardInstance>, int, int> chk =
              (cardId, setup, wantCost, reduce) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "handcost_" + cardId });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"]; var N = st.Players["north"];
                for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
                var card = new CardInstance { InstanceId = "HC", CardId = cardId, Owner = "south", Zone = "hand" };
                S.Hand.Clear(); S.Hand.Add(card);
                setup(st, S, N, card);
                int got = GameEngine.GetCost(st, card);
                bool ok = got == wantCost;
                if (!ok) fails++;
                Console.WriteLine($"  {cardId}: cost={got} want={wantCost} (−{reduce}) {(ok ? "ok" : "FAIL")}");
            };
            // Each satisfies its condition → discount applies.
            chk("EB04-061", (st, S, N, c) => { while (S.Life.Count > 1) S.Life.RemoveAt(S.Life.Count - 1); }, 9, 1);
            chk("OP15-013", (st, S, N, c) => { st.TemporaryPowerBonus[S.Leader.InstanceId] = -6000; }, 2, 2);
            chk("OP15-021", (st, S, N, c) => { for (int i = 0; i < 4; i++) S.Trash.Add(new CardInstance { InstanceId = "e" + i, CardId = "ST01-014", Owner = "south", Zone = "trash" }); }, 1, 3);
            chk("OP15-102", (st, S, N, c) => { S.CharacterArea[0] = new CardInstance { InstanceId = "SKY", CardId = "EB02-052", Owner = "south", Zone = "character" }; }, 1, 3);
            chk("OP16-005", (st, S, N, c) => { S.CharacterArea[0] = new CardInstance { InstanceId = "WB", CardId = "OP02-004", Owner = "south", Zone = "character" }; }, 5, 3);
            chk("OP16-015", (st, S, N, c) => { S.Leader = new CardInstance { InstanceId = "LDR", CardId = "OP03-001", Owner = "south", Zone = "leader" }; S.CostArea.Clear(); for (int i = 0; i < 6; i++) S.CostArea.Add(new DonInstance { InstanceId = "d" + i }); }, 2, 2);
            chk("PRB02-014", (st, S, N, c) => { for (int i = 0; i < 15; i++) S.Trash.Add(new CardInstance { InstanceId = "t" + i, CardId = "ST01-006", Owner = "south", Zone = "trash" }); }, 3, 3);
            chk("ST23-001", (st, S, N, c) => { var b = new CardInstance { InstanceId = "BIG", CardId = "ST01-006", Owner = "south", Zone = "character" }; S.CharacterArea[0] = b; st.TemporaryPowerBonus[b.InstanceId] = 10000; }, 2, 4);
            chk("ST23-002", (st, S, N, c) => { N.CharacterArea[0] = new CardInstance { InstanceId = "OPP8", CardId = "EB01-023", Owner = "north", Zone = "character" }; }, 6, 3);
            chk("ST26-001", (st, S, N, c) => { S.CharacterArea[0] = new CardInstance { InstanceId = "SG", CardId = "OP05-065", Owner = "south", Zone = "character" }; }, 2, 5);
            chk("OP07-064", (st, S, N, c) => { S.CostArea.Clear(); for (int i = 0; i < 2; i++) S.CostArea.Add(new DonInstance { InstanceId = "sd" + i }); N.CostArea.Clear(); for (int i = 0; i < 4; i++) N.CostArea.Add(new DonInstance { InstanceId = "nd" + i }); }, 3, 3);
            Console.WriteLine($"=== HANDCOSTTEST === {(fails == 0 ? "PASS" : fails + " FAIL")}");
            return fails == 0 ? 0 : 1;
