        //   EB04-048 Rob Lucci: "If Leader type includes CP, +1000 power and +2 cost for every 5 cards in trash"
        //   OP12-063 Reiju:     "If 4+ Events in trash, +2000 power and +5 cost"
        //   ST27-004 Sanjuan:   "If Leader Blackbeard, [Blocker] and +1 cost for every 4 cards in trash"
        if (args.Length > 0 && args[0] == "costscaletest")
        {
            // returns effective cost of a character given a Leader id and a trash composition
            System.Func<string, string, int, int, int> costOf = (charId, leaderId, trashEvents, trashOther) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "costscale" });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                S.Leader = new CardInstance { InstanceId = "LDR", CardId = leaderId, Owner = "south", Zone = "leader" };
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var ch = new CardInstance { InstanceId = "CH", CardId = charId, Owner = "south", Zone = "character" };
                S.CharacterArea[0] = ch;
                S.Trash.Clear();
                for (int i = 0; i < trashEvents; i++) S.Trash.Add(new CardInstance { InstanceId = "te" + i, CardId = "ST01-014", Owner = "south", Zone = "trash" }); // Event
                for (int i = 0; i < trashOther; i++) S.Trash.Add(new CardInstance { InstanceId = "to" + i, CardId = "ST01-002", Owner = "south", Zone = "trash" }); // Character
                return GameEngine.GetCost(st, ch);
            };
            // All three base cost 4. BB leader=OP09-081, CP leader=OP03-076 (CP9), plain leader=ST01-001.
            // EB04-048 Lucci: CP + 10 trash → +2*(10/5)=+4 → 8; non-CP → 4.
            int lucciCP = costOf("EB04-048", "OP03-076", 0, 10);
            int lucciNo = costOf("EB04-048", "ST01-001", 0, 10);
            // ST27-004 Sanjuan: BB + 8 trash → +1*(8/4)=+2 → 6; non-BB → 4.
            int wolfBB = costOf("ST27-004", "OP09-081", 0, 8);
            int wolfNo = costOf("ST27-004", "ST01-001", 0, 8);
            // OP12-063 Reiju: 5 Events → +5 → 9; 2 Events → 4.
            int reijuHi = costOf("OP12-063", "ST01-001", 5, 0);
            int reijuLo = costOf("OP12-063", "ST01-001", 2, 0);
            Console.WriteLine($"=== COSTSCALETEST ===");
            Console.WriteLine($"  Lucci: CP+10trash cost={lucciCP} (want 8)   non-CP cost={lucciNo} (want 4)");
            Console.WriteLine($"  Sanjuan Wolf: BB+8trash cost={wolfBB} (want 6)   non-BB cost={wolfNo} (want 4)");
            Console.WriteLine($"  Reiju: 5 events cost={reijuHi} (want 9)   2 events cost={reijuLo} (want 4)");
            // ST27-004 also grants [Blocker] conditionally on a Blackbeard Leader — verify that half too.
            System.Func<string, bool> wolfBlocker = (string leaderId) =>
            {
                var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "wolfblk" + leaderId });
                st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
                var S = st.Players["south"];
                S.Leader = new CardInstance { InstanceId = "LDR", CardId = leaderId, Owner = "south", Zone = "leader" };
                for (int i = 0; i < 5; i++) S.CharacterArea[i] = null;
                var ch = new CardInstance { InstanceId = "CH", CardId = "ST27-004", Owner = "south", Zone = "character" };
                S.CharacterArea[0] = ch;
                return GameEngine.HasBlocker(st, ch);
            };
            bool blkBB = wolfBlocker("OP09-081"); bool blkNo = wolfBlocker("ST01-001");
            Console.WriteLine($"  Sanjuan Blocker: BB-leader={blkBB} (want True)   non-BB={blkNo} (want False)");
            bool pass = lucciCP == 8 && lucciNo == 4 && wolfBB == 6 && wolfNo == 4 && reijuHi == 9 && reijuLo == 4 && blkBB && !blkNo;
            Console.WriteLine(pass ? "PASS" : "FAIL");
            return pass ? 0 : 1;
