            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = "FF2", Target = "A" });
            bool aAlive = N.CharacterArea.Any(c => c != null && c.InstanceId == "A");
            Console.WriteLine($"=== FIREFISTTEST ===\nB (5000 power) rejected & alive = {bAlive} (want True)\nA (0 power) K.O.'d = {!aAlive} (want True)");
            return 0;
        }
        // selfpowertest <attackerId> <donCount> — attach donCount DON to attackerId, attack, check its
        // "If this Character has 7000 power or more" When-Attacking fires (OP05-017 Lindbergh KO).
        if (args.Length > 0 && args[0] == "selfpowertest")
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "sp" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            var atk = new CardInstance { InstanceId = "ATK", CardId = args[1], Owner = "south", Zone = "character", Rested = false, PlayedOnTurn = 0 };
            int don = args.Length > 2 ? int.Parse(args[2]) : 0;
            for (int k = 0; k < don; k++) atk.AttachedDonIds.Add($"ad{k}");
            S.CharacterArea[0] = atk;
            N.CharacterArea[0] = new CardInstance { InstanceId = "OPP", CardId = "OP01-016", Owner = "north", Zone = "character" };  // 2000 power
            GameEngine.ApplyCommand(st, new GameCommand { Type = "declareAttack", Seat = "south", Attacker = "ATK", Target = N.Leader.InstanceId });
            var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
            if (pe != null) GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "OPP" });
            bool koed = !N.CharacterArea.Any(c => c != null && c.InstanceId == "OPP");
            Console.WriteLine($"=== SELFPOWERTEST {args[1]} DON={don} (power {GameEngine.GetPower(st, atk)}) ===\noppKOd={koed} (power≥7000 → KO fires)");
            return 0;
        }
        // audit <startIndex> <count> — anomaly pre-filter over the ordered card list, to prioritize
        // which cards need a deep manual trace. Flags: crash, manual-resolution, effect-skipped,
        // unresolved pending, unpayable cost. Not a correctness oracle — a triage list.
        if (args.Length > 0 && args[0] == "audit") { AuditRange(int.Parse(args[1]), args.Length > 2 ? int.Parse(args[2]) : 40); return 0; }
        int seedsPer = args.Length > 0 && int.TryParse(args[0], out var s) ? s : 3;
        var decks = CardData.StarterDecks.Keys.OrderBy(k => k).ToList();
        Console.WriteLine($"Starter decks ({decks.Count}): {string.Join(", ", decks)}");
        Console.WriteLine($"Seeds per pairing: {seedsPer}  →  {decks.Count * decks.Count * seedsPer} games\n");

        int games = 0, crashes = 0, stalls = 0, invariantFails = 0;
        var crashDetail = new List<string>();
        var stallDetail = new List<string>();
        var invDetail = new List<string>();
        long totalTurns = 0;
        int endDeckout = 0, endLife = 0, endOther = 0;
        var turnBuckets = new int[6]; // <=10, <=20, <=30, <=50, <=80, >80
        var deckGames = new Dictionary<string, int>();
        var deckDeckout = new Dictionary<string, int>();
        foreach (var d in decks) { deckGames[d] = 0; deckDeckout[d] = 0; }

        foreach (var sd in decks)
        foreach (var nd in decks)
        for (int seed = 0; seed < seedsPer; seed++)
        {
            games++;
            string tag = $"{sd} vs {nd} #{seed}";
            GameState state = null;
            try
            {
                var cfg = new MatchConfig { SouthDeck = sd, NorthDeck = nd, Seed = $"{sd}:{nd}:{seed}" };
                state = GameEngine.CreateMatch(cfg);
                IntermediateBot.PlayFullMatch(state, 20000);

                totalTurns += state.TurnNumber;
                int tn = state.TurnNumber;
                turnBuckets[tn <= 10 ? 0 : tn <= 20 ? 1 : tn <= 30 ? 2 : tn <= 50 ? 3 : tn <= 80 ? 4 : 5]++;
                string tail = LogTail(state).ToLowerInvariant();
                bool isDeckout = tail.Contains("no cards in deck") || tail.Contains("deck reached 0");
                if (isDeckout) endDeckout++;
                else if (tail.Contains("wins")) endLife++;
                else endOther++;
                deckGames[sd]++; deckGames[nd]++;
                if (isDeckout) { deckDeckout[sd]++; deckDeckout[nd]++; }

                if (state.Status != "finished")
                {
                    stalls++;
                    if (stallDetail.Count < 15) stallDetail.Add($"{tag}: status='{state.Status}' phase='{state.Phase}' turn={state.TurnNumber} active={state.ActiveSeat} {LogTail(state)}");
                    continue;
                }

                // ---- End-state invariants ----
                var problems = CheckInvariants(state);
                if (problems.Count > 0)
                {
                    invariantFails++;
                    if (invDetail.Count < 20) invDetail.Add($"{tag}: {string.Join("; ", problems)}");
                }
            }
            catch (Exception ex)
            {
                crashes++;
                string where = state == null ? "CreateMatch" : $"turn {state.TurnNumber}/{state.Phase}";
                if (crashDetail.Count < 25) crashDetail.Add($"{tag} @ {where}: {ex.GetType().Name}: {ex.Message}{LogTail(state)}");
            }
        }

        Console.WriteLine($"\n===== SUMMARY =====");
        Console.WriteLine($"games={games}  crashes={crashes}  stalls(non-finishing)={stalls}  invariantFails={invariantFails}");
        Console.WriteLine($"avg turns/finished game = {(games - crashes - stalls > 0 ? (double)totalTurns / (games - crashes - stalls) : 0):0.0}");
        Console.WriteLine($"end reason: lifeOut={endLife}  deckOut={endDeckout}  other={endOther}");
        Console.WriteLine($"turns: <=10:{turnBuckets[0]}  <=20:{turnBuckets[1]}  <=30:{turnBuckets[2]}  <=50:{turnBuckets[3]}  <=80:{turnBuckets[4]}  >80:{turnBuckets[5]}");

        Console.WriteLine("\n----- per-deck deck-out rate (deck : deckouts/games) sorted worst-first -----");
        foreach (var kv in deckDeckout.OrderByDescending(k => deckGames[k.Key] == 0 ? 0 : (double)k.Value / deckGames[k.Key]))
        {
            double rate = deckGames[kv.Key] == 0 ? 0 : 100.0 * kv.Value / deckGames[kv.Key];
            Console.WriteLine($"  {kv.Key,-10} {rate,5:0}%  ({kv.Value}/{deckGames[kv.Key]})");
        }

        Print("CRASHES", crashDetail);
        Print("STALLS (never reached 'finished' — deadlock/loop suspect)", stallDetail);
        Print("INVARIANT VIOLATIONS", invDetail);

        return (crashes + stalls + invariantFails) > 0 ? 1 : 0;
    }

    // LAYER 1 driver: replay every deck pairing one command at a time and assert the rules
    // invariants after EVERY command, reporting the first violation per game (with the command
    // that broke it). Catches transient rule breaks a bot-vs-bot end-state check would miss.
    static int InvariantSweep(int seedsPer)
    {
        var decks = CardData.StarterDecks.Keys.OrderBy(k => k).ToList();
        Console.WriteLine($"Invariant sweep: {decks.Count}x{decks.Count}x{seedsPer} = {decks.Count * decks.Count * seedsPer} games, checked per-command.\n");
        int games = 0, violGames = 0;
        var details = new List<string>();
        var byKind = new Dictionary<string, int>();
        foreach (var sd in decks)
        foreach (var nd in decks)
        for (int seed = 0; seed < seedsPer; seed++)
        {
            games++;
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = sd, NorthDeck = nd, Seed = $"{sd}:{nd}:{seed}" });
            string viol;
            try { viol = PlayWithInvariantChecks(st, 20000); }
            catch (Exception ex) { viol = $"CRASH {ex.GetType().Name}: {ex.Message}"; }
            if (viol != null)
            {
                violGames++;
                string kind = viol.Contains("::") ? viol.Substring(viol.IndexOf("::") + 2).Split(new[] { '=', '(', ':' }, 2)[0].Trim() : viol.Split(' ')[0];
                byKind[kind] = byKind.GetValueOrDefault(kind) + 1;
                if (details.Count < 40) details.Add($"{sd} vs {nd} #{seed}: {viol}");
            }
        }

        Console.WriteLine($"===== INVARIANTS =====");
        Console.WriteLine($"games={games}  gamesWithViolation={violGames}");
        foreach (var kv in byKind.OrderByDescending(k => k.Value)) Console.WriteLine($"  {kv.Value,5}x  {kv.Key}");
        Print("VIOLATIONS (first per game)", details);

        try
        {
            string dir = @"C:\Users\Nperr\One Piece TCG Simulator\Tools\Harness\findings";
            System.IO.Directory.CreateDirectory(dir);
            using var w = new System.IO.StreamWriter(System.IO.Path.Combine(dir, "invariant-violations.md"), false);
            w.WriteLine("# Invariant Violations (per-command)\n");
            w.WriteLine($"Generated {DateTime.Now:yyyy-MM-dd HH:mm}. `Tools/Harness invariants {seedsPer}` — NOT shipped.\n");
            w.WriteLine($"- games: {games}\n- games with a violation: {violGames}\n");
            foreach (var kv in byKind.OrderByDescending(k => k.Value)) w.WriteLine($"- {kv.Value}x `{kv.Key}`");
            w.WriteLine("\n## First violation per affected game\n");
            foreach (var d in details) w.WriteLine($"- {d}");
        }
        catch { }

        return violGames > 0 ? 1 : 0;
    }

    static string PlayWithInvariantChecks(GameState state, int maxTotal)
    {
        int total = 0;
        while (state.Status != "finished" && total < maxTotal)
        {
            var (aS, vS) = StepSeat(state, "south", maxTotal - total); total += aS; if (vS != null) return vS;
            var (aN, vN) = StepSeat(state, "north", maxTotal - total); total += aN; if (vN != null) return vN;
            if (aS == 0 && aN == 0) break;
        }
        return null;
    }

    // Mirrors IntermediateBot.TakeAllAvailableActions but checks invariants after every command.
    static (int applied, string violation) StepSeat(GameState state, string seat, int maxCommands)
    {
        int applied = 0;
        var blacklist = new HashSet<string>();
        for (int i = 0; i < maxCommands; i++)
        {
            var cmd = IntermediateBot.DecideOneCommand(state, seat, blacklist);
            if (cmd == null) break;
            object before = IntermediateBot.SnapshotFor(state, cmd);
            GameEngine.ApplyCommand(state, cmd);
            applied++;

            var problems = Invariants.Structural(state);
            problems.AddRange(Invariants.Conservation(state));
            if (problems.Count > 0)
                return (applied, $"turn {state.TurnNumber} after [{IntermediateBot.Signature(cmd)}] :: {string.Join("; ", problems.Take(3))}");

            if (!IntermediateBot.Succeeded(state, cmd, before))
                blacklist.Add(IntermediateBot.Signature(cmd));
        }
        return (applied, null);
    }

    // Stage a single card's [On Play] in a controlled board and step through its pending effects
    // one command at a time, printing the ORDERED sequence of prompts (buttons) the client would
    // show, plus zone counts before/after — so a dropped or mis-ordered clause is visible.
    static void AuditRange(int startIdx, int count)
    {
        var ids = System.IO.File.ReadAllLines("findings/audit-cardlist.txt").Where(l => l.Trim().Length > 0).ToList();
        int end = Math.Min(ids.Count, startIdx + count);
        Console.WriteLine($"=== AUDIT cards [{startIdx}..{end}) of {ids.Count} ===");
        var flagged = new List<string>();
        for (int idx = startIdx; idx < end; idx++)
        {
            string cid = ids[idx].Trim();
            var def = CardData.GetCard(cid);
            if (def == null) continue;
            string anomaly = AuditOne(cid, def);
            if (anomaly != null) { flagged.Add($"{idx}\t{cid}\t{def.Name}\t{anomaly}"); Console.WriteLine($"  ⚑ [{idx}] {cid} {def.Name}: {anomaly}"); }
        }
        Console.WriteLine($"\nFLAGGED {flagged.Count}/{end - startIdx} in this batch. Next index: {end}");
        System.IO.File.AppendAllText("findings/audit-flagged.tsv", string.Join("\n", flagged) + (flagged.Count > 0 ? "\n" : ""));
    }

    static string AuditOne(string cardId, CardDef def)
    {
        try
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "audit:" + cardId });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 5;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3; S.Hand.Clear();
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            S.CostArea.Clear();
            for (int i = 0; i < 10; i++) S.CostArea.Add(new DonInstance { InstanceId = $"a{i}", Rested = i < 2 });
            N.CharacterArea[0] = new CardInstance { InstanceId = "na", CardId = "ST01-006", Owner = "north", Zone = "character" };
            N.CharacterArea[1] = new CardInstance { InstanceId = "nb", CardId = "ST01-006", Owner = "north", Zone = "character" };
            S.CharacterArea[3] = new CardInstance { InstanceId = "sa", CardId = "ST01-006", Owner = "south", Zone = "character" };
            for (int i = 0; i < 4; i++) { S.Life.Add(new CardInstance { InstanceId = $"sl{i}", CardId = "ST01-006", Owner = "south", Zone = "life" }); N.Life.Add(new CardInstance { InstanceId = $"nl{i}", CardId = "ST01-006", Owner = "north", Zone = "life" }); }
            for (int i = 0; i < 5; i++) S.Hand.Add(new CardInstance { InstanceId = $"h{i}", CardId = "ST01-006", Owner = "south", Zone = "hand" });
            string eff = def.Effect ?? "";
            bool isActivate = eff.Contains("[Activate: Main]") && !eff.Contains("[On Play]");
            CardInstance src;
            if (isActivate)
            {
                bool isLeader = def.Type == "leader"; bool isStage = def.Type == "stage";
                src = new CardInstance { InstanceId = "SRC", CardId = cardId, Owner = "south", Zone = isLeader ? "leader" : isStage ? "stage" : "character", PlayedOnTurn = 0 };
                var dg = System.Text.RegularExpressions.Regex.Match(eff, @"\[DON!! x(\d+)\]");
                if (dg.Success) for (int k = 0; k < int.Parse(dg.Groups[1].Value); k++) src.AttachedDonIds.Add($"sd{k}");
                if (isLeader) S.Leader = src; else if (isStage) S.Stage = src; else S.CharacterArea[1] = src;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "activateMain", Seat = "south", Target = "SRC" });
            }
            else if (def.Type == "leader") { return null; }   // passive leaders — not exercised here
            else { src = new CardInstance { InstanceId = "SRC", CardId = cardId, Owner = "south", Zone = "hand" }; S.Hand.Add(src); GameEngine.ApplyCommand(st, new GameCommand { Type = "playCard", Seat = "south", InstanceId = "SRC", SlotIndex = 0 }); }
            // Resolve loop: step through choices / deck-looks / pending effects with generic picks.
            int guard = 0;
            while (guard++ < 30)
            {
                if (st.ActiveChoice != null && st.ActiveChoice.Seat == "south") { GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveChoice", Seat = "south", Target = "A" }); continue; }
                if (st.DeckLook != null && st.DeckLook.Seat == "south")
                {
                    var dl = st.DeckLook;
                    if (dl.Step == "select") GameEngine.ApplyCommand(st, new GameCommand { Type = "deckLookSelect", Seat = "south", Target = dl.Cards.FirstOrDefault()?.InstanceId ?? "" });
                    else if (dl.Step == "rearrange") GameEngine.ApplyCommand(st, new GameCommand { Type = "deckLookConfirmOrder", Seat = "south", OrderedInstanceIds = dl.Cards.Select(c => c.InstanceId).ToList() });
                    else GameEngine.ApplyCommand(st, new GameCommand { Type = "deckLookScryConfirm", Seat = "south", OrderedInstanceIds = new System.Collections.Generic.List<string>() });
                    if (st.DeckLook == dl) st.DeckLook = null;
                    continue;
                }
                var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south");
                if (pe == null) break;
                string t = pe.Text ?? "";
                string pick;
                if (pe.TargetZone == OnePieceTcg.Engine.EffectTargetZone.Hand || (t.IndexOf("from your hand", StringComparison.OrdinalIgnoreCase) >= 0 && t.IndexOf("opponent", StringComparison.OrdinalIgnoreCase) < 0))
                    pick = S.Hand.FirstOrDefault(c => c.InstanceId != "SRC")?.InstanceId;
                else if (t.IndexOf("rested DON!!", StringComparison.OrdinalIgnoreCase) >= 0 && t.IndexOf("Leader", StringComparison.OrdinalIgnoreCase) >= 0)
                    pick = S.CostArea.FirstOrDefault(dd => dd.Rested)?.InstanceId;
                else if (t.IndexOf("top or bottom of your Life", StringComparison.OrdinalIgnoreCase) >= 0)
                    pick = S.Life.LastOrDefault()?.InstanceId;
                else if (System.Text.RegularExpressions.Regex.IsMatch(t, @"of your.*Characters?", System.Text.RegularExpressions.RegexOptions.IgnoreCase) && t.IndexOf("opponent", StringComparison.OrdinalIgnoreCase) < 0)
                    pick = S.CharacterArea.FirstOrDefault(c => c != null && c.InstanceId != "SRC")?.InstanceId;
                else pick = N.CharacterArea.FirstOrDefault(c => c != null)?.InstanceId ?? S.Hand.FirstOrDefault(c => c.InstanceId != "SRC")?.InstanceId;
                long Sig() => st.Players.Values.Sum(pl => pl.Hand.Count + pl.Trash.Count + pl.Deck.Count + pl.CharacterArea.Count(c => c != null)) * 100 + pe.SelectionsRemaining;
                long before = Sig();
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = pick });
                if (st.PendingEffects.Contains(pe) && Sig() == before)
                    GameEngine.ApplyCommand(st, new GameCommand { Type = "passEffect", Seat = "south", EffectId = pe.EffectId });
            }
            var logs = st.EventLog.Select(l => l.Message ?? "").ToList();
            var reasons = new List<string>();
            if (logs.Any(m => m.IndexOf("manual resolution", StringComparison.OrdinalIgnoreCase) >= 0 || m.IndexOf("Unknown", StringComparison.OrdinalIgnoreCase) >= 0)) reasons.Add("MANUAL/UNKNOWN");
            if (logs.Any(m => m.IndexOf("cost cannot be paid", StringComparison.OrdinalIgnoreCase) >= 0)) reasons.Add("COST_UNPAYABLE");
            if (st.PendingEffects.Any(e => e.Seat == "south")) reasons.Add("PENDING_LEFT");
            if (guard >= 30) reasons.Add("LOOP_GUARD(possible spin)");
            // "effect skipped" for a NON-optional-cost card = suspicious dropped clause.
            if (logs.Any(m => m.IndexOf("effect skipped", StringComparison.OrdinalIgnoreCase) >= 0)
                && eff.IndexOf("You may", StringComparison.OrdinalIgnoreCase) < 0
                && eff.IndexOf("up to", StringComparison.OrdinalIgnoreCase) < 0
                && eff.IndexOf("If ", StringComparison.OrdinalIgnoreCase) < 0)
                reasons.Add("SKIPPED(non-optional)");
            return reasons.Count > 0 ? string.Join(",", reasons) : null;
        }
        catch (Exception ex) { return "CRASH: " + ex.GetType().Name + " " + (ex.Message ?? "").Replace("\n", " ").Substring(0, Math.Min(60, (ex.Message ?? "").Length)); }
    }

    static void DebuffTest()
    {
        var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "debuff" });
        st.Status = "active"; st.Phase = "main"; st.TurnNumber = 6;
        var S = st.Players["south"]; var N = st.Players["north"];
        for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
        // South leader = OP15-001 Krieg, with 1 DON attached (for [DON!! x1]).
        S.Leader = new CardInstance { InstanceId = "KL", CardId = "OP15-001", Owner = "south", Zone = "leader" };
        S.Leader.AttachedDonIds.Add("kd0");
        // South's ONLY character is East Blue (Gaimon) → the "only East Blue" condition is met.
        S.CharacterArea[0] = new CardInstance { InstanceId = "EB", CardId = "EB02-012", Owner = "south", Zone = "character" };
        // North's character we measure.
        N.CharacterArea[0] = new CardInstance { InstanceId = "NC", CardId = "ST01-006", Owner = "north", Zone = "character" };
        var nc = N.CharacterArea[0];
        int basePow = CardData.GetCard("ST01-006")?.Power ?? 0;
        st.ActiveSeat = "south";
        int onSouth = GameEngine.GetPower(st, nc);
        st.ActiveSeat = "north";
        int onNorth = GameEngine.GetPower(st, nc);
        Console.WriteLine($"north Character base power = {basePow}");
        Console.WriteLine($"power on SOUTH's turn (aura inactive): {onSouth}");
        Console.WriteLine($"power on NORTH's turn (opponent's turn — should be base-2000): {onNorth}");
    }

    static void KriegTest()
    {
        var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "krieg" });
        st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "south"; st.TurnNumber = 5;
        var S = st.Players["south"]; var N = st.Players["north"];
        S.TurnsStarted = 3; N.TurnsStarted = 3;
        for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
        // North (opponent): TWO characters + 3 RESTED DON in the cost area.
        N.CharacterArea[0] = new CardInstance { InstanceId = "NA", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false };
        N.CharacterArea[1] = new CardInstance { InstanceId = "NB", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false };
        for (int i = 0; i < 3; i++) N.CostArea.Add(new DonInstance { InstanceId = $"nr{i}", Rested = true });
        // South plays Krieg OP15-008 from hand (needs enough DON — cost 8).
        for (int i = 0; i < 10; i++) S.CostArea.Add(new DonInstance { InstanceId = $"sd{i}", Rested = false });
        var krieg = new CardInstance { InstanceId = "KRIEG", CardId = "OP15-008", Owner = "south", Zone = "hand" };
        S.Hand.Add(krieg);
        GameEngine.ApplyCommand(st, new GameCommand { Type = "playCard", Seat = "south", InstanceId = "KRIEG", SlotIndex = 0 });
        // The give-DON effect should be WAITING for a target (not auto-resolved). Choose NB (the 2nd char).
        var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "south" && (e.Text ?? "").Contains("opponent's rested DON"));
        Console.WriteLine($"give-DON effect pending & waiting for target: {(pe != null ? "YES" : "no")}");
        if (pe != null)
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "south", EffectId = pe.EffectId, Target = "NB" });
        int naDon = N.CharacterArea.FirstOrDefault(c => c != null && c.InstanceId == "NA")?.AttachedDonIds.Count ?? -1;
        int nbDon = N.CharacterArea.FirstOrDefault(c => c != null && c.InstanceId == "NB")?.AttachedDonIds.Count ?? -1;
        int restedLeft = N.CostArea.Count(d => d.Rested);
        Console.WriteLine($"NA (first char) attached DON: {naDon}");
        Console.WriteLine($"NB (chosen char) attached DON: {nbDon}");
        Console.WriteLine($"north rested DON left in cost area: {restedLeft}  (started 3)");
    }

    static void KoRepTest3(string guardId, string southLeaderId)
    {
        var gdef = CardData.GetCard(guardId);
        Console.WriteLine($"=== KOREPTEST3 guard={guardId} {gdef?.Name} southLeader={southLeaderId} {CardData.GetCard(southLeaderId)?.Name} ===\n{gdef?.Effect}\n");
        var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "korep3" });
        st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
        var S = st.Players["south"]; var N = st.Players["north"];
        S.TurnsStarted = 3; N.TurnsStarted = 3;
        S.Leader.CardId = southLeaderId;   // swap south's leader to exercise the condition gate
        for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
        S.CharacterArea[0] = new CardInstance { InstanceId = "GUARD", CardId = guardId, Owner = "south", Zone = "character", Rested = false };
        S.Hand.Add(new CardInstance { InstanceId = "sfuel", CardId = "ST01-006", Owner = "south", Zone = "hand" }); // fuel Koby's "trash 1 from hand"
        // North's uncapped KO: OP07-085 Stussy ("You may trash 1 of your Characters: K.O. up to 1 opp Character").
        N.CharacterArea[0] = new CardInstance { InstanceId = "nfodder", CardId = "ST01-006", Owner = "north", Zone = "character", Rested = false }; // cost of Stussy
        var stussy = new CardInstance { InstanceId = "STU", CardId = "OP07-085", Owner = "north", Zone = "hand" };
        N.Hand.Add(stussy);
        for (int i = 0; i < 10; i++) N.CostArea.Add(new DonInstance { InstanceId = $"nd{i}", Rested = false });
        GameEngine.ApplyCommand(st, new GameCommand { Type = "playCard", Seat = "north", InstanceId = "STU", SlotIndex = 1 });
        // Drive the pending chain: pay the trash cost (target nfodder), then KO the guard.
        for (int g = 0; g < 6; g++)
        {
            var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "north");
            if (pe == null) break;
            string tgt = (pe.Text ?? "").IndexOf("trash 1 of your", StringComparison.OrdinalIgnoreCase) >= 0 ? "nfodder" : "GUARD";
            GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = pe.EffectId, Target = tgt });
        }
        bool guardAlive = S.CharacterArea.Any(c => c != null && c.InstanceId == "GUARD");
        Console.WriteLine($"guardAlive={guardAlive}  (Navy leader → expect SAVED; non-Navy → expect K.O.'d)");
        foreach (var l in st.EventLog.Skip(Math.Max(0, st.EventLog.Count - 5))) Console.WriteLine("   " + l.Message);
    }

