        foreach (var l in st.EventLog.Skip(Math.Max(0, st.EventLog.Count - 6))) Console.WriteLine("   " + l.Message);
    }

    static void KoRepTest()
    {
        // Two cases on the OPPONENT's turn (ActiveSeat=north): victim rested (should be saved) vs
        // active (should die). North plays EB01-049 (K.O. up to 1 opponent Character cost ≤ 2).
        foreach (bool victimRested in new[] { true, false })
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "korep" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            S.CharacterArea[0] = new CardInstance { InstanceId = "ROSI", CardId = "OP05-030", Owner = "south", Zone = "character", Rested = false };
            S.CharacterArea[1] = new CardInstance { InstanceId = "VICT", CardId = "ST01-006", Owner = "south", Zone = "character", Rested = victimRested };
            var ko = new CardInstance { InstanceId = "KO", CardId = "EB01-049", Owner = "north", Zone = "hand" };
            N.Hand.Add(ko);
            for (int i = 0; i < 6; i++) N.CostArea.Add(new DonInstance { InstanceId = $"nd{i}", Rested = false });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "playCard", Seat = "north", InstanceId = "KO", SlotIndex = 0 });
            // Resolve the KO effect targeting the south victim.
            var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "north");
            if (pe != null) GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = pe.EffectId, Target = "VICT" });
            bool victAlive = S.CharacterArea.Any(c => c != null && c.InstanceId == "VICT");
            bool rosiAlive = S.CharacterArea.Any(c => c != null && c.InstanceId == "ROSI");
            string expect = victimRested ? "victim SAVED, Rosinante trashed" : "victim K.O.'d, Rosinante stays";
            Console.WriteLine($"victim {(victimRested ? "RESTED" : "ACTIVE")}: victimAlive={victAlive} rosinanteAlive={rosiAlive}  (expected: {expect})");
        }

        // Multi-K.O. "save all" (Kaido ruling): ONE board wipe K.O.s TWO rested cost-1 victims;
        // trashing Rosinante ONCE should save BOTH. North plays ST08-005 (trash 1: K.O. all cost ≤1).
        {
            var st = GameEngine.CreateMatch(new MatchConfig { SouthDeck = "st01", NorthDeck = "st01", Seed = "korepmulti" });
            st.Status = "active"; st.Phase = "main"; st.ActiveSeat = "north"; st.TurnNumber = 6;
            var S = st.Players["south"]; var N = st.Players["north"];
            S.TurnsStarted = 3; N.TurnsStarted = 3;
            for (int i = 0; i < 5; i++) { S.CharacterArea[i] = null; N.CharacterArea[i] = null; }
            S.CharacterArea[0] = new CardInstance { InstanceId = "ROSI", CardId = "OP05-030", Owner = "south", Zone = "character", Rested = false }; // cost 2 — not wiped
            S.CharacterArea[1] = new CardInstance { InstanceId = "V1", CardId = "ST01-006", Owner = "south", Zone = "character", Rested = true };   // cost 1, rested
            S.CharacterArea[2] = new CardInstance { InstanceId = "V2", CardId = "ST01-006", Owner = "south", Zone = "character", Rested = true };   // cost 1, rested
            var wipe = new CardInstance { InstanceId = "WIPE", CardId = "ST08-005", Owner = "north", Zone = "hand" };
            N.Hand.Add(wipe);
            N.Hand.Add(new CardInstance { InstanceId = "toss", CardId = "ST01-006", Owner = "north", Zone = "hand" }); // fuel the trash cost
            for (int i = 0; i < 10; i++) N.CostArea.Add(new DonInstance { InstanceId = $"nd{i}", Rested = false });
            GameEngine.ApplyCommand(st, new GameCommand { Type = "playCard", Seat = "north", InstanceId = "WIPE", SlotIndex = 0 });
            // Pay the "trash 1 from hand" cost, then the K.O.-all fires.
            for (int g = 0; g < 6; g++)
            {
                var pe = st.PendingEffects.FirstOrDefault(e => e.Seat == "north");
                if (pe == null) break;
                GameEngine.ApplyCommand(st, new GameCommand { Type = "resolveEffect", Seat = "north", EffectId = pe.EffectId, Target = "toss" });
            }
            bool v1 = S.CharacterArea.Any(c => c != null && c.InstanceId == "V1");
            bool v2 = S.CharacterArea.Any(c => c != null && c.InstanceId == "V2");
            bool rosi = S.CharacterArea.Any(c => c != null && c.InstanceId == "ROSI");
            Console.WriteLine($"MULTI-K.O.: v1Alive={v1} v2Alive={v2} rosinanteAlive={rosi}  (expected: BOTH saved, Rosinante trashed once)");
        }
    }

